import json

s = 'abstract contract Authorizable {\n    mapping (address => mapping (address => uint)) public record authorizations;\n\n    bool internal bypassAuthorizations = false;\n\n    \n    error AuthorizableUnauthorizedAccount(address account);\n\n    event AccountAuthorized(address indexed account);\n\n    event AuthorizationUsed(address indexed account, uint authorizationsRemaining);\n\n    function _authorize(address _target, address _account, uint _authorizations) internal {\n        authorizations[_target][_account] += _authorizations;\n    }\n\n    function isAuthorized(address _account) external returns (bool) {\n        if (bypassAuthorizations) {\n            return true;\n        } else {\n            uint numAuthorizations = authorizations[msg.sender][_account];\n            if (numAuthorizations > 0) {\n                authorizations[msg.sender][_account]--;\n                return true;\n            } else {\n                return false;\n            }\n        }\n    }\n}\n\n\n\ninterface IERC20 {\n    \n    event Transfer(address indexed from, address indexed to, uint256 value);\n\n    \n    event Approval(address indexed owner, address indexed spender, uint256 value);\n\n    \n    function totalSupply() external view returns (uint256);\n\n    \n    function balanceOf(address account) external view returns (uint256);\n\n    \n    function transfer(address to, uint256 value) external returns (bool);\n\n    \n    function allowance(address owner, address spender) external view returns (uint256);\n\n    \n    function approve(address spender, uint256 value) external returns (bool);\n\n    \n    function transferFrom(address from, address to, uint256 value) external returns (bool);\n}\n\n\n// SPDX-License-Identifier: MIT\n\n\n\n\ninterface IERC20Metadata is IERC20 {\n    \n    function name() external view returns (string memory);\n\n    \n    function symbol() external view returns (string memory);\n\n    \n    function decimals() external view returns (uint8);\n}\n\n\n// SPDX-License-Identifier: MIT\n\n\nabstract contract Context {\n\n   function _msgSender() internal view virtual returns (address) {\n        return msg.sender;\n    }\n\n    function _msgData() internal view virtual returns (variadic) {\n        return msg.data;\n    }\n\n    function _contextSuffixLength() internal view virtual returns (uint256) {\n        return 0;\n    }\n}\n\n\n// SPDX-License-Identifier: MIT\n\n\n\n\n\n\nabstract contract ERC20 is Context, IERC20, IERC20Metadata { \n    mapping(address => uint256) private record _balances;\n\n    mapping(address => mapping(address => uint256)) private record _allowances;\n\n    uint256 private _totalSupply;\n\n    string private _name;\n    string private _symbol;\n\n\n\n    bool private _erc20Initialized;\n    function __ERC20_init(string name_, string symbol_) internal {\n        require(!_erc20Initialized, "ERC20: already initialized");\n        _name = name_;\n        _symbol = symbol_;\n        _erc20Initialized = true;\n    }\n\n    \n    constructor(string name_, string symbol_) {\n        _name = name_;\n        _symbol = symbol_;\n    }\n\n    \n    function name() public view virtual override returns (string) {\n        return _name;\n    }\n\n    \n    function symbol() public view virtual override returns (string ) {\n        return _symbol;\n    }\n\n    \n    function decimals() public view virtual override returns (uint8) {\n        return 18;\n    }\n\n    \n    function totalSupply() public view virtual override returns (uint256) {\n        return _totalSupply;\n    }\n\n    \n    function balanceOf(address accountAddress) public view virtual override returns (uint256) {\n        return _balances[accountAddress];\n    }\n\n    \n    function transfer(address to, uint256 value) public virtual override returns (bool) {\n        address owner = _msgSender();\n        _transfer(owner, to, value);\n        return true;\n    }\n\n    \n    function allowance(address owner, address spender) public view virtual override returns (uint256) {\n        return _allowances[owner][spender];\n    }\n\n    \n    function approve(address spender, uint256 value) public virtual override returns (bool) {\n        address owner = _msgSender();\n        _approve(owner, spender, value);\n        return true;\n    }\n\n    \n    function transferFrom(address from, address to, uint256 value) public virtual override returns (bool) {\n        address spender = _msgSender();\n        _spendAllowance(from, spender, value);\n        _transfer(from, to, value);\n        return true;\n    }\n\n    \n    function _transfer(address from, address to, uint256 value) internal {\n        require(from != address(0), "ERC20: transfer from the zero address");\n        require(to != address(0), "ERC20: transfer to the zero address");\n        _update(from, to, value);\n    }\n\n    \n    function _update(address from, address to, uint256 value) internal virtual {\n        require(from != address(0) || to != address(0), "ERC20: transfer to/from the zero address");\n\n        if (from == address(0)) {\n\n            _totalSupply += value;\n        } else {\n            uint256 fromBalance = _balances[from];\n            require(fromBalance >= value, "ERC20: insufficient balance");\n\n            _balances[from] = fromBalance - value;\n        }\n\n        if (to == address(0)) {\n\n            _totalSupply -= value;\n        } else {\n\n            _balances[to] += value;\n        }\n\n        emit Transfer(from, to, value);\n    }\n\n    \n    function _mint(address accountAddress, uint256 value) internal {\n        require(accountAddress != address(0), "ERC20: mint to the zero address");\n        _update(address(0), accountAddress, value);\n    }\n\n    \n    function _burn(address accountAddress, uint256 value) internal { \n        require(accountAddress != address(0), "ERC20: burn from the zero address");\n        _update(accountAddress, address(0), value);\n    }\n\n    \n    function _approve(address owner, address spender, uint256 value) internal {\n        _approve(owner, spender, value, true);\n    }\n\n    \n    function _approve(address owner, address spender, uint256 value, bool emitEvent) internal virtual {\n        require(owner != address(0), "ERC20: approve from the zero address");\n        require(spender != address(0), "ERC20: approve to the zero address");\n        _allowances[owner][spender] = value;\n        if (emitEvent) {\n            emit Approval(owner, spender, value);\n        }\n    }\n\n    \n    function _spendAllowance(address owner, address spender, uint256 value) internal virtual {\n        uint256 currentAllowance = allowance(owner, spender);\n        if (currentAllowance != (2**256 - 1)) {  \n            require(currentAllowance >= value, "ERC20: insufficient allowance");\n            _approve(owner, spender, currentAllowance - value, false);\n        }\n    }\n\n}\n\n\n\n\n\n\ncontract record AdminRegistry is Ownable {\n    address[] public record admins;\n    mapping (address => uint) public record adminMap;\n\n    mapping (string => address[]) public record votes;\n    mapping (string => mapping (address => uint)) public record votesMap;\n    mapping (string => bool) public record currentIssues;\n\n    mapping (address => mapping (string => mapping (address => bool))) public record whitelist;\n\n    mapping (address => mapping (string => uint)) public record votingThresholds;\n\n    uint public defaultVotingThresholdBps = 6000; \n\n    event IssueCreated(address sender, address creator, string issueId, address target, string func, variadic args);\n    event IssueVoted(address sender, address voter, string issueId, address target, string func, variadic args);\n    event IssueExecuted(address sender, address executor, string issueId, address target, string func, variadic args);\n    event IssueBatchExecuted(address sender, address executor, string issueId, address target, string func, variadic args);\n    event IssueDismissed(address sender, string issueId);\n\n    bool public initialized = false;\n\n    address public batchTxController;\n\n    modifier onlyOnce() {\n        require(!initialized, "AdminRegistry is already initialized");\n        initialized = true;\n        _;\n    }\n\n    constructor() Ownable(this) { }\n\n    function initialize(address[] _initialAdmins) external onlyOnce {\n        defaultVotingThresholdBps = 6000; \n        require(admins.length == 0, "AdminRegistry is already initialized");\n        for (uint i = 0; i < _initialAdmins.length; i++) {\n            require(_initialAdmins[i] != address(0), "Invalid admin address");\n            admins.push(_initialAdmins[i]);\n            adminMap[_initialAdmins[i]] = admins.length;\n        }\n    }\n\n    function addAdmin(address _admin) external {\n        castVoteOnIssue(this, "_addAdmin", _admin);\n    }\n\n    function removeAdmin(address _admin) external {\n        castVoteOnIssue(this, "_removeAdmin", _admin);\n    }\n\n    function swapAdmin(address _adminToReplace, address _newAdmin) external {\n        castVoteOnIssue(this, "_swapAdmin", _adminToReplace, _newAdmin);\n    }\n\n    function isAdminAddress(address _admin) external returns (bool) {\n        return adminMap[_admin] > 0;\n    }\n\n    function dismissIssue(string _issueId) external {\n        require(currentIssues[_issueId], "Issue does not exist or is not active");\n        require(votes[_issueId].length == 1, "Only issues with a single vote can be dismissed");\n        require(votes[_issueId][0] == msg.sender, "Only the proposer can dismiss their issue");\n\n        for (uint i = 0; i < votes[_issueId].length; i++) {\n            votesMap[_issueId][votes[_issueId][i]] = 0;\n            votes[_issueId][i] = address(0);\n        }\n        votes[_issueId].length = 0;\n        delete currentIssues[_issueId];\n        emit IssueDismissed(msg.sender, _issueId);\n    }\n\n    function castVoteOnIssue(address _target, string _func, variadic _args) public returns (bool, variadic) {\n        if (batchTxController != address(0)) {\n            address sender = msg.sender;\n            if (_target == batchTxController) {\n                sender = _target;\n                _target = msg.sender;\n            }\n            require(sender == batchTxController, "Only batch tx controller can vote during batch tx");\n            string issueId = _getIssueId(_target, _func, _args);\n            variadic ret = _executeIssue(sender, issueId, _target, _func, _args);\n            return (true, ret);\n        }\n        if (adminMap[msg.sender] != 0 || adminMap[_target] != 0) {\n            address sender = msg.sender;\n            if (adminMap[msg.sender] == 0) {\n                if (_target != tx.origin) {\n                    bool authorizationGranted = false;\n                    try {\n                        authorizationGranted = Authorizable(_target).isAuthorized(msg.sender);\n                    } catch {\n\n                    }\n                    require(authorizationGranted, "Cannot forge a vote on behalf of an admin without their consent");\n                }\n                sender = _target;\n                _target = msg.sender;\n            }\n            string issueId = _getIssueId(_target, _func, _args);\n            bool hasVoted = votesMap[issueId][sender] != 0;\n\n            _createIssue(sender, issueId, _target, _func, _args);\n\n            if (!hasVoted) {\n                votes[issueId].push(sender);\n                votesMap[issueId][sender] = votes[issueId].length;\n                emit IssueVoted(msg.sender, sender, issueId, _target, _func, _args);\n            }\n\n            if (_shouldExecute(issueId, _target, _func, _args)) {\n                variadic ret = _executeIssue(sender, issueId, _target, _func, _args);\n                return (true, ret);\n            } else {\n                return (false, issueId);\n            }\n        } else {\n\n            address sender = msg.sender;\n            address target = _target;\n            require(whitelist[target][_func][sender] || whitelist[sender][_func][target], "Only an admin or a whitelisted account can call castVoteOnIssue");\n            if (!whitelist[target][_func][sender] && whitelist[sender][_func][target]) {\n                sender = _target;\n                target = msg.sender;\n            }\n            string issueId = _getIssueId(target, _func, _args);\n            variadic ret = _executeIssue(sender, issueId, target, _func, _args);\n            return (true, ret);\n        }\n\n        return (false, _args);\n    }\n\n    function _shouldExecute(string _issueId, address _target, string _func, variadic _args) internal returns (bool) {\n        uint issueVotes = votes[_issueId].length;\n\n        uint votingThresholdBps = votingThresholds[_target][_func];\n        if (votingThresholdBps == 0) votingThresholdBps = defaultVotingThresholdBps;\n\n        return 10000 * issueVotes >= votingThresholdBps * admins.length;\n    }\n\n    function _createIssue(address _sender, string _issueId, address _target, string _func, variadic _args) internal {\n        if(votes[_issueId].length == 0) {\n            currentIssues[_issueId] = true;\n            emit IssueCreated(msg.sender, _sender, _issueId, _target, _func, _args);\n        }\n    }\n\n    function getIssueId(address _target, string _func, variadic _args) external returns (string) {\n        return _getIssueId(_target, _func, _args);\n    }\n\n    function _getIssueId(address _target, string _func, variadic _args) internal returns (string) {\n        return keccak256(_target, _func, _args);\n    }\n\n    function _executeIssue(address _sender, string _issueId, address _target, string _func, variadic _args) internal returns (variadic) {\n        variadic ret = _target.call(_func, _args);\n        for (uint i = 0; i < votes[_issueId].length; i++) {\n            votesMap[_issueId][votes[_issueId][i]] = 0;\n            votes[_issueId][i] = address(0);\n        }\n        votes[_issueId].length = 0;\n        delete currentIssues[_issueId];\n        emit IssueExecuted(msg.sender, _sender, _issueId, _target, _func, _args);\n        return ret;\n    }\n\n    function _addAdmin(address _admin) external onlyOwner {\n        require(_admin != address(0), "Invalid admin address");\n        require(adminMap[_admin] == 0, "Account is already an admin");\n        admins.push(_admin);\n        adminMap[_admin] = admins.length;\n    }\n\n    function _removeAdmin(address _admin) external onlyOwner {\n        require(admins.length > 1, "Cannot remove the last admin");\n        uint index = adminMap[_admin];\n        require(index > 0, "Account is not an admin");\n        address swap = admins[admins.length - 1];\n        admins[index - 1] = swap;\n        adminMap[swap] = index;\n        adminMap[_admin] = 0;\n        admins[admins.length - 1] = address(0);\n        admins.length -= 1;\n    }\n\n    function _swapAdmin(address _adminToReplace, address _admin) external onlyOwner {\n        uint index = adminMap[_admin];\n        require(index == 0, "Account is already an admin");\n        index = adminMap[_adminToReplace];\n        require(index > 0, "Caller is not an admin");\n        address swap = admins[admins.length - 1];\n        admins[index - 1] = _admin;\n        adminMap[_admin] = index;\n        adminMap[_adminToReplace] = 0;\n    }\n\n    function addWhitelist(address _target, string _func, address _user) external onlyOwner {\n        if (_target == address(this)) {\n            require(\n                _func != "addWhitelist" &&\n                _func != "removeWhitelist" &&\n                _func != "_addAdmin" &&\n                _func != "_createIssue" &&\n                _func != "_executeIssue" &&\n                _func != "_removeAdmin" &&\n                _func != "_shouldExecute" &&\n                _func != "_swapAdmin" &&\n                _func != "setVotingThreshold" &&\n                _func != "setDefaultVotingThresholdBps" &&\n                _func != "createContract" &&\n                _func != "createSaltedContract",\n                "Cannot whitelist internal governance functions"\n            );\n        }\n        whitelist[_target][_func][_user] = true;\n    }\n\n    function removeWhitelist(address _target, string _func, address _user) external onlyOwner {\n        whitelist[_target][_func][_user] = false;\n    }\n\n    function setVotingThreshold(address _target, string _func, uint _votingThresholdBps) external onlyOwner {\n        require(_votingThresholdBps > 0, "Voting threshold must be greater than 0");\n        require(_votingThresholdBps <= 10000, "Voting threshold must be less than 100%");\n        votingThresholds[_target][_func] = _votingThresholdBps;\n    }\n\n    function setDefaultVotingThresholdBps(uint _defaultVotingThresholdBps) external onlyOwner {\n        require(_defaultVotingThresholdBps > 0, "Default voting threshold must be greater than 0");\n        require(_defaultVotingThresholdBps <= 10000, "Default voting threshold must be less than 100%");\n        defaultVotingThresholdBps = _defaultVotingThresholdBps;\n    }\n\n    function createContract(string _contractName, string _contractSrc, variadic _args) external onlyOwner returns (address) {\n        return create(_contractName, _contractSrc, _args);\n    }\n\n    function createSaltedContract(string _salt, string _contractName, string _contractSrc, variadic _args) external onlyOwner returns (address) {\n        return create2(_salt, _contractName, _contractSrc, _args);\n    }\n\n    function executeBatchTx(address controllerContract, string entrypoint, variadic _args) external onlyOwner\n    {\n        batchTxController = controllerContract;\n        controllerContract.call(entrypoint, _args);\n        delete batchTxController;\n    }\n}\n\n\n\n\n\n\nabstract contract Ownable is Context {\n    address private _owner;\n\n    \n    error OwnableUnauthorizedAccount(address account);\n\n    \n    error OwnableInvalidOwner(address owner);\n\n    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);\n\n    \n    constructor(address initialOwner) {\n        if (initialOwner == address(0)) {\n            revert OwnableInvalidOwner(address(0));\n        }\n        _transferOwnership(initialOwner);\n    }\n\n    \n    modifier onlyOwner() {\n        try {\n            _checkOwner();\n            _;\n        } catch {\n            address myOwner = owner();\n            AdminRegistry admin = AdminRegistry(myOwner);\n            address sender = _msgSender();\n            if (myOwner == this) {\n                sender = this;\n            }\n            (bool didExecute, variadic ret) = admin.castVoteOnIssue(sender, msg.sig, msg.data);\n            return ret;\n        }\n    }\n\n    \n    function owner() public view virtual returns (address) {\n        return _owner;\n    }\n\n    \n    function _checkOwner() internal view virtual {\n        if (owner() != _msgSender()) {\n            require(owner() == _msgSender(), string(owner()) + " does not match sender " + string(_msgSender()));\n            revert OwnableUnauthorizedAccount(_msgSender());\n        }\n    }\n\n    \n    function renounceOwnership() public virtual onlyOwner {\n        _transferOwnership(address(0));\n    }\n\n    \n    function transferOwnership(address newOwner) public virtual onlyOwner {\n        if (newOwner == address(0)) {\n            revert OwnableInvalidOwner(address(0));\n        }\n        _transferOwnership(newOwner);\n    }\n\n    \n    function _transferOwnership(address newOwner) internal virtual {\n        address oldOwner = _owner;\n        _owner = newOwner;\n        emit OwnershipTransferred(oldOwner, newOwner);\n    }\n}\n\n\n// SPDX-License-Identifier: MIT\n\n\n\n\n\n\n\nabstract contract Pausable is Context {\n    bool private _paused;\n\n    \n    event Paused(address account);\n\n    \n    event Unpaused(address account);\n\n    \n    error EnforcedPause();\n\n    \n    error ExpectedPause();\n\n    \n    modifier whenNotPaused() {\n        _requireNotPaused();\n        _;\n    }\n\n    \n    modifier whenPaused() {\n        _requirePaused();\n        _;\n    }\n\n    \n    function paused() public view virtual returns (bool) {\n        return _paused;\n    }\n\n    \n    function _requireNotPaused() internal view virtual {\n        if (paused()) {\n            revert EnforcedPause();\n        }\n    }\n\n    \n    function _requirePaused() internal view virtual {\n        if (!paused()) {\n            revert ExpectedPause();\n        }\n    }\n\n    \n    function _pause() internal virtual whenNotPaused {\n        _paused = true;\n        emit Paused(_msgSender());\n    }\n\n    \n    function _unpause() internal virtual whenPaused {\n        _paused = false;\n        emit Unpaused(_msgSender());\n    }\n}\n\ncontract TokenMetadata {\n    string description;\n    string[] record images;\n    string[] record files;\n    string[] record fileNames;\n\n    mapping(string => string) public record attributes;\n\n    constructor(\n        string _description,\n        string[] _images,\n        string[] _files,\n        string[] _fileNames\n    ){\n        description = _description;\n        images = _images;\n        files = _files;\n        fileNames = _fileNames;\n    }\n\n    function _setMetadata(\n        string _description,\n        string[] _images,\n        string[] _files,\n        string[] _fileNames\n    ) internal {\n        description = _description;\n        images = _images;\n        files = _files;\n        fileNames = _fileNames;\n    }\n\n    function _setAttribute(\n        string key,\n        string value\n    ) internal {\n        attributes[key] = value;\n    }\n}\n\n\n\n\n\ncontract record Proxy is Ownable {\n    address logicContract;\n\n    constructor(address _logicContract, address _initialOwner) Ownable(_initialOwner) {\n        logicContract = _logicContract;\n    }\n\n    function setLogicContract(address _logicContract) onlyOwner {\n        logicContract = _logicContract;\n    }\n\n    fallback(variadic args) external returns (variadic) {\n        return logicContract.delegatecall(msg.sig, args);\n    }\n}\n\n\n\n\n// SPDX-License-Identifier: MIT\n\n\n\n\n\ncontract record TokenFactory is Ownable {\n\n\n\n\n    event TokenCreated(address token, address creator, string name, string symbol);\n\n\n    event TokensMigrated(address oldFactory, address newFactory, uint256 tokenCount);\n\n\n    event TokensRegistered(uint256 tokenCount);\n\n\n\n\n    mapping(address => bool) public isFactoryToken;\n\n\n    address[] public record allTokens;\n\n\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) {\n    }\n\n\n\n\n\n\n\n\n\n\n\n\n\n    function createToken(\n        string _name,\n        string _description,\n        string[] _images,\n        string[] _files,\n        string[] _fileNames,\n        string _symbol,\n        uint256 _initialSupply,\n        uint8 _customDecimals\n    ) external onlyOwner returns (address) {\n        return createTokenWithInitialOwner(\n            _name,\n            _description,\n            _images,\n            _files,\n            _fileNames,\n            _symbol,\n            _initialSupply,\n            _customDecimals,\n            msg.sender\n        );\n    }\n\n    function createTokenWithInitialOwner(\n        string _name,\n        string _description,\n        string[] _images,\n        string[] _files,\n        string[] _fileNames,\n        string _symbol,\n        uint256 _initialSupply,\n        uint8 _customDecimals,\n        address _initialOwner\n    ) public onlyOwner returns (address) {\n\n        Token newToken = Token(address(new Proxy(address(new Token(_initialOwner)), address(this))));\n        newToken.initialize(\n            _name,\n            _description,\n            _images,\n            _files,\n            _fileNames,\n            _symbol,\n            _initialSupply,\n            _customDecimals,\n            _initialOwner\n        );\n        newToken.transferOwnership(_initialOwner);\n\n\n        address tokenAddress = address(newToken);\n        isFactoryToken[tokenAddress] = true;\n        allTokens.push(tokenAddress);\n\n        emit TokenCreated(tokenAddress, msg.sender, _name, _symbol);\n        return tokenAddress;\n    }\n\n\n\n\n    function isTokenActive(address token) external view returns (bool) {\n        return Token(token).status() == TokenStatus.ACTIVE && isFactoryToken[token];\n    }\n\n\n\n    function migrateTokensToFactory(address newFactory) external onlyOwner {\n        for (uint256 i = 0; i < allTokens.length; i++) {\n            address tokenAddr = allTokens[i];\n            Token(tokenAddr).setTokenFactory(newFactory);\n        }\n        emit TokensMigrated(address(this), newFactory, allTokens.length);\n    }\n\n\n\n    function registerMigratedTokens(address[] tokens) external onlyOwner {\n        for (uint256 i = 0; i < tokens.length; i++) {\n            isFactoryToken[tokens[i]] = true;\n            allTokens.push(tokens[i]);\n        }\n        emit TokensRegistered(tokens.length);\n    }\n}\n\n\n\n\n\n\n\n\n\n\nenum TokenStatus { NULL, PENDING, ACTIVE, LEGACY }\n\ncontract record Token is ERC20, Ownable, TokenMetadata, Pausable {\n    uint8 public customDecimals;\n    TokenStatus public status;\n    TokenFactory public tokenFactory;\n\n    event StatusChanged(TokenStatus newStatus);\n\n    modifier onlyTokenFactory() {\n        require(msg.sender == address(tokenFactory), "Token: caller is not token factory");\n        _;\n    }\n\n    modifier whenNotPausedOrOwner() {\n        if (paused()) {\n            try {\n                _checkOwner();\n            } catch {\n                AdminRegistry admin = AdminRegistry(Ownable(tokenFactory).owner());\n                require(admin.whitelist(address(this), msg.sig, _msgSender()), "not whitelisted");\n            }\n        }\n        _;\n    }\n\n    constructor(address initialOwner)\n        Ownable(initialOwner)\n        ERC20("", "")\n        TokenMetadata("", [], [], [])\n    {}\n\n\n    function initialize(\n        string name_,\n        string description_,\n        string[] images_,\n        string[] files_,\n        string[] fileNames_,\n        string symbol_,\n        uint256 initialSupply_,\n        uint8 customDecimals_,\n        address tokenCreator_\n    ) external onlyOwner {\n\n\n        __ERC20_init(name_, symbol_);\n\n\n        _setMetadata(description_, images_, files_, fileNames_);\n\n        customDecimals = customDecimals_;\n        status = TokenStatus.PENDING;\n        tokenFactory = TokenFactory(msg.sender);\n        _mint(tokenCreator_, initialSupply_);\n\n        emit StatusChanged(status);\n    }\n\n    function setStatus(uint newStatus) external onlyOwner {\n        require(newStatus != uint(status), "Token: New status is the same as the current status");\n        require(newStatus != uint(TokenStatus.NULL), "Token: New status is NULL");\n        TokenStatus _newStatus = TokenStatus(newStatus);\n        status = _newStatus;\n\n        emit StatusChanged(status);\n    }\n\n    function setTokenFactory(address _tokenFactory) external onlyTokenFactory {\n        tokenFactory = TokenFactory(_tokenFactory);\n    }\n\n    function mint(address to, uint256 amount) external onlyOwner {\n        _mint(to, amount);\n    }\n\n    function burn(address from, uint256 amount) external onlyOwner {\n        _burn(from, amount);\n    }\n\n    function pause() external onlyOwner {\n        _pause();\n    }\n\n    function unpause() external onlyOwner {\n        _unpause();\n    }\n\n    function setMetadata (\n        string _description,\n        string[] _images,\n        string[] _files,\n        string[] _fileNames\n    ) external onlyOwner {\n        _setMetadata(_description, _images, _files, _fileNames);\n    }\n\n    function setAttribute(string key, string value) external onlyOwner {\n        _setAttribute(key, value);\n    }\n\n    function decimals() external view virtual override returns (uint8) {\n        return customDecimals;\n    }\n\n    function transfer(address to, uint256 value) public override whenNotPausedOrOwner returns (bool) {\n        return super.transfer(to, value);\n    }\n\n    function transferFrom(address from, address to, uint256 value) public override whenNotPausedOrOwner returns (bool) {\n        return super.transferFrom(from, to, value);\n    }\n}\n\n\n\n\n\n\n\n\n\n\ncontract record PoolFactory is Ownable {\n\n\n\n\n    event NewPool(address tokenA, address tokenB, address pool);\n\n\n    event PoolsMigrated(address oldFactory, address newFactory, uint256 poolCount);\n\n\n    event AdminRegistryUpdated(address newRegistry);\n\n\n    event TokenFactoryUpdated(address newFactory);\n\n\n    event FeeCollectorsUpdated(address newFeeCollector);\n\n\n    event FeeParametersUpdated(uint256 newSwapFeeRate, uint256 newLpSharePercent);\n\n\n    event PoolFeeParametersUpdated(address poolAddress, uint256 newSwapFeeRate, uint256 newLpSharePercent);\n\n\n\n\n    mapping(address => mapping(address => address)) public record pools;\n\n\n    address[] public record allPools;\n\n\n    address public adminRegistry;\n\n\n    address public tokenFactory;\n\n\n    address public feeCollector;\n\n\n    uint256 public swapFeeRate;\n\n\n    uint256 public lpSharePercent;\n\n\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n\n\n\n\n    function initialize(address _tokenFactory, address _adminRegistry, address _feeCollector) external onlyOwner {\n        require(_adminRegistry != address(0), "Zero admin registry address");\n        require(_tokenFactory  != address(0), "Zero token factory address");\n        require(_feeCollector  != address(0), "Zero fee collector address");\n\n        adminRegistry = _adminRegistry;\n        tokenFactory = _tokenFactory;\n        feeCollector = _feeCollector;\n        swapFeeRate = 30;\n        lpSharePercent = 7000;\n\n        emit FeeParametersUpdated(swapFeeRate, lpSharePercent);\n        emit FeeCollectorsUpdated(feeCollector);\n        emit AdminRegistryUpdated(adminRegistry);\n        emit TokenFactoryUpdated(tokenFactory);\n    }\n\n\n\n\n\n\n    modifier tokensActive(address tokenA, address tokenB) {\n        require(TokenFactory(tokenFactory).isTokenActive(tokenA) && TokenFactory(tokenFactory).isTokenActive(tokenB), "Token not active");\n        _;\n    }\n\n\n\n\n    function setAdminRegistry(address _adminRegistry) external onlyOwner {\n        require(_adminRegistry != address(0), "Zero admin registry address");\n        address oldRegistry = address(adminRegistry);\n        adminRegistry = _adminRegistry;\n        emit AdminRegistryUpdated(_adminRegistry);\n    }\n\n\n    function setTokenFactory(address _tokenFactory) external onlyOwner {\n        require(_tokenFactory != address(0), "Zero token factory address");\n        address oldFactory = address(tokenFactory);\n        tokenFactory = _tokenFactory;\n        emit TokenFactoryUpdated(_tokenFactory);\n    }\n\n\n\n    function setFeeCollector(address newFeeCollector) external onlyOwner {\n        require(newFeeCollector != address(0), "Zero fee collector address");\n        address oldFeeCollector = feeCollector;\n        feeCollector = newFeeCollector;\n\n        emit FeeCollectorsUpdated(newFeeCollector);\n    }\n\n\n\n\n    function setFeeParameters(\n        uint256 newSwapFeeRate,\n        uint256 newLpSharePercent\n    ) external onlyOwner {\n        require(newSwapFeeRate > 0 && newSwapFeeRate <= 1000, "Invalid swap fee rate"); \n        require(newLpSharePercent > 0 && newLpSharePercent <= 10000, "Invalid LP share percent"); \n\n        swapFeeRate = newSwapFeeRate;\n        lpSharePercent = newLpSharePercent;\n\n        emit FeeParametersUpdated(newSwapFeeRate, newLpSharePercent);\n    }\n\n\n\n\n\n\n\n    function setPoolFeeParameters(\n        address poolAddress,\n        uint256 newSwapFeeRate,\n        uint256 newLpSharePercent\n    ) external onlyOwner {\n        require(poolAddress != address(0), "Zero pool address");\n        require(newSwapFeeRate > 0 && newSwapFeeRate <= 1000, "Invalid swap fee rate"); \n        require(newLpSharePercent > 0 && newLpSharePercent <= 10000, "Invalid LP share percent"); \n\n\n        require(address(Pool(poolAddress).poolFactory()) == address(this), "Pool does not belong to this factory");\n\n\n        Pool(poolAddress).setFeeParameters(newSwapFeeRate, newLpSharePercent);\n\n        emit PoolFeeParametersUpdated(poolAddress, newSwapFeeRate, newLpSharePercent);\n    }\n\n\n\n\n\n    function syncPools(address[] pools) external onlyOwner {\n        address[] memory targetPools = pools;\n        if (targetPools.length == 0) {\n            targetPools = allPools;\n        }\n        for (uint256 i = 0; i < targetPools.length; i++) {\n            Pool(targetPools[i]).sync();\n        }\n    }\n\n\n\n\n\n\n    function skimPools(address[] pools, address to) external onlyOwner {\n        address[] memory targetPools = pools;\n        if (targetPools.length == 0) {\n            targetPools = allPools;\n        }\n        for (uint256 i = 0; i < targetPools.length; i++) {\n            Pool(targetPools[i]).skim(to);\n        }\n    }\n\n\n\n\n\n    function createPool(address tokenA, address tokenB) external tokensActive(tokenA, tokenB) onlyOwner returns (address pool) {\n        require(tokenA != address(0) && tokenB != address(0), "Zero address");\n        require(tokenA != tokenB, "Identical addresses");\n        require(pools[tokenA][tokenB] == address(0) && pools[tokenB][tokenA] == address(0), "Pool exists");\n\n\n        string lpName = ERC20(tokenA).name() + "-" + ERC20(tokenB).name() + " LP Token";\n        string lpSymbol = ERC20(tokenA).symbol() + "-" + ERC20(tokenB).symbol() + "-LP";\n\n        address lpTokenAddress = TokenFactory(tokenFactory).createTokenWithInitialOwner(\n            lpName,\n            "Liquidity Provider Token",\n            [],\n            [],\n            [],\n            lpSymbol,\n            0,\n            18,\n            this\n        );\n\n\n        address thisOwner = owner();\n        pool = address(new Proxy(address(new Pool(address(thisOwner))), address(this)));\n        Pool(pool).initialize(tokenA, tokenB, lpTokenAddress);\n        Pool(pool).transferOwnership(thisOwner);\n        Ownable(lpTokenAddress).transferOwnership(thisOwner);\n\n\n        pools[tokenA][tokenB] = pool;\n        pools[tokenB][tokenA] = pool; \n        allPools.push(pool);\n\n        emit NewPool(tokenA, tokenB, pool);\n\n        return pool;\n    }\n\n\n\n    function transferPoolsToFactory(address newFactory) external onlyOwner {\n        for (uint256 i = 0; i < allPools.length; i++) {\n            address pool = allPools[i];\n            if (pool != address(0)) {\n\n                Pool(pool).transferPoolToFactory(newFactory);\n            }\n        }\n        emit PoolsMigrated(address(this), newFactory, allPools.length);\n    }\n\n\n\n    function registerPoolsFromFactory(address[] poolAddresses) external onlyOwner {\n        for (uint256 i = 0; i < poolAddresses.length; i++) {\n            address pool = poolAddresses[i];\n\n\n            require(address(Pool(pool).poolFactory()) == address(this), "Pool does not belong to this factory");\n\n\n            Pool poolContract = Pool(pool);\n            address tokenA = address(poolContract.tokenA());\n            address tokenB = address(poolContract.tokenB());\n\n\n            if (pools[tokenA][tokenB] == address(0) && pools[tokenB][tokenA] == address(0)) {\n                pools[tokenA][tokenB] = pool;\n                pools[tokenB][tokenA] = pool;\n                allPools.push(pool);\n            }\n        }\n        emit PoolsMigrated(address(0), address(this), poolAddresses.length);\n    }\n}\n\n\n// SPDX-License-Identifier: MIT\n\n\n\n\ncontract record FeeCollector is Ownable {\n\n    event Withdrawn(address indexed token, address indexed to, uint256 amount);\n\n    \n    constructor(address _owner) Ownable(_owner) {}\n\n    \n    function withdrawToken(address token, address to, uint256 amount) external onlyOwner {\n        require(token != address(0), "FeeCollector: zero token address");\n        require(to != address(0), "FeeCollector: zero recipient address");\n        require(amount > 0, "FeeCollector: zero amount");\n        require(ERC20(token).balanceOf(address(this)) >= amount, "FeeCollector: insufficient balance");\n        require(ERC20(token).transfer(to, amount), "FeeCollector: transfer failed");\n        emit Withdrawn(token, to, amount);\n    }\n}\n\n// SPDX-License-Identifier: MIT\n\n\n\n\n\n\n\ncontract record Pool is Ownable {\n\n\n\n\n\n\n\n\n\n    event Swap(address sender, address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOut);\n\n\n\n\n\n    event AddLiquidity(address provider, uint256 tokenBAmount, uint256 tokenAAmount);\n\n\n\n\n\n    event RemoveLiquidity(address provider, uint256 tokenBAmount, uint256 tokenAAmount);\n\n\n\n\n\n    event Skim(address to, uint256 tokenAAmount, uint256 tokenBAmount);\n\n\n\n\n    event Sync(uint256 tokenABalance, uint256 tokenBBalance);\n\n\n\n\n    PoolFactory public poolFactory;\n\n\n    Token public tokenA;\n\n\n    Token public tokenB;\n\n\n    Token public lpToken;\n\n\n    bool private locked;\n\n\n    decimal public aToBRatio;\n\n\n    decimal public bToARatio;\n\n\n    uint public tokenABalance;\n\n\n    uint public tokenBBalance;\n\n\n    uint256 public swapFeeRate;\n\n\n    uint256 public lpSharePercent;\n\n\n    bool public zapSwapFeesEnabled = true;\n\n\n\n\n\n    modifier nonReentrant() {\n        require(!locked, "REENTRANT");\n        locked = true;\n        _;\n        locked = false;\n    }\n\n\n    modifier onlyPoolFactory() {\n        require(\n            msg.sender == address(poolFactory)\n            || msg.sender == owner(), \n            "Caller is not PoolFactory");\n        _;\n    }\n\n\n\n\n\n    function _feeCollector() internal view returns (address) {\n        return PoolFactory(poolFactory).feeCollector();\n    }\n\n\n\n    function _tokenFactory() internal view returns (address) {\n        return PoolFactory(poolFactory).tokenFactory();\n    }\n\n\n\n    function _swapFeeRate() internal view returns (uint256) {\n        if (swapFeeRate == 0) {\n            return PoolFactory(poolFactory).swapFeeRate();\n        }\n        return swapFeeRate;\n    }\n\n\n\n    function _lpSharePercent() internal view returns (uint256) {\n        if (lpSharePercent == 0) {\n            return PoolFactory(poolFactory).lpSharePercent();\n        }\n        return lpSharePercent;\n    }\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) {}\n\n\n\n\n\n\n\n    function initialize(\n        address tokenAAddr,\n        address tokenBAddr,\n        address lpTokenAddr\n    ) external onlyOwner {\n        require(tokenAAddr != address(0), "Zero tokenA address");\n        require(tokenBAddr != address(0), "Zero tokenB address");\n        require(lpTokenAddr != address(0), "Zero lpToken address");\n\n\n\n        zapSwapFeesEnabled = true;\n\n        tokenA = Token(tokenAAddr);\n        tokenB = Token(tokenBAddr);\n        lpToken = Token(lpTokenAddr);\n\n        poolFactory = PoolFactory(msg.sender);\n    }\n\n\n\n\n    function sync() external onlyPoolFactory {\n        tokenABalance = tokenA.balanceOf(address(this));\n        tokenBBalance = tokenB.balanceOf(address(this));\n        _updateRatios();\n        emit Sync(tokenABalance, tokenBBalance);\n    }\n\n\n\n    function skim(address to) external onlyPoolFactory {\n        require(to != address(0), "Invalid recipient");\n        uint256 excessA = tokenA.balanceOf(address(this)) - tokenABalance;\n        uint256 excessB = tokenB.balanceOf(address(this)) - tokenBBalance;\n\n        if (excessA > 0) {\n            require(tokenA.transfer(to, excessA), "TokenA skim failed");\n        }\n        if (excessB > 0) {\n            require(tokenB.transfer(to, excessB), "TokenB skim failed");\n        }\n\n        emit Skim(to, excessA, excessB);\n    }\n\n\n    function _updateRatios() internal {\n        aToBRatio = _getCurrentTokenRatio(true);\n        bToARatio = _getCurrentTokenRatio(false);\n    }\n\n\n\n\n    function _updateStateVars(uint256 newTokenABalance, uint256 newTokenBBalance) internal {\n        tokenABalance = newTokenABalance;\n        tokenBBalance = newTokenBBalance;\n        _updateRatios();\n    }\n\n\n\n\n\n    function _getCurrentTokenRatio(bool isAToB) internal view returns (decimal) {\n        decimal tokenAReserve = decimal(tokenABalance);\n        decimal tokenBReserve = decimal(tokenBBalance);\n\n        if (tokenAReserve <= 0.000000000000000000 || tokenBReserve <= 0.000000000000000000) {\n            return 0.000000000000000000;\n        }\n\n        if (isAToB) {\n            return decimal((tokenBReserve * 1.000000000000000000) / tokenAReserve) / 1.000000000000000000;\n        } else {\n            return decimal((tokenAReserve * 1.000000000000000000) / tokenBReserve) / 1.000000000000000000;\n        }\n        return 0.000000000000000000;\n    }\n\n\n\n\n\n\n\n\n\n\n    function addLiquidity(\n        uint256 tokenBAmount,\n        uint256 maxTokenAAmount,\n        uint256 deadline\n    ) external returns (uint256) {\n        require(tokenBAmount > 0 && maxTokenAAmount > 0, "Invalid inputs");\n        require(block.timestamp <= deadline, "EXPIRED");\n\n        uint256 totalLiquidity = lpToken.totalSupply();\n        uint256 tokenAAmount;\n        uint256 mintAmount;\n\n        if (totalLiquidity > 0) {\n\n            tokenAAmount = (tokenBAmount * tokenABalance) / tokenBBalance;\n            require(maxTokenAAmount >= tokenAAmount, "Insufficient tokenA amount");\n\n            uint256 mintAmountA = (tokenAAmount * totalLiquidity) / tokenABalance;\n            uint256 mintAmountB = (tokenBAmount * totalLiquidity) / tokenBBalance;\n            mintAmount = mintAmountA < mintAmountB ? mintAmountA : mintAmountB;\n        } else {\n            tokenAAmount = maxTokenAAmount;\n            mintAmount = tokenBAmount;\n        }\n\n        lpToken.mint(msg.sender, mintAmount);\n        require(tokenB.transferFrom(msg.sender, address(this), tokenBAmount), "TokenB transfer failed");\n        require(tokenA.transferFrom(msg.sender, address(this), tokenAAmount), "TokenA transfer failed");\n\n        _updateStateVars(tokenABalance + tokenAAmount, tokenBBalance + tokenBAmount);\n        emit AddLiquidity(msg.sender, tokenBAmount, tokenAAmount);\n        return mintAmount;\n    }\n\n\n\n\n\n\n\n\n\n    function removeLiquidity(\n        uint256 lpTokenAmount,\n        uint256 minTokenBAmount,\n        uint256 minTokenAAmount,\n        uint256 deadline\n    ) external returns (uint256, uint256) {\n        require(lpTokenAmount > 0 && minTokenBAmount > 0 && minTokenAAmount > 0, "Invalid inputs");\n        require(block.timestamp <= deadline, "EXPIRED");\n        uint256 totalLiquidity = lpToken.totalSupply();\n        require(totalLiquidity > 0, "No liquidity");\n        uint256 tokenAReserve = tokenABalance;\n        uint256 tokenBReserve = tokenBBalance;\n        uint256 tokenBAmount = lpTokenAmount * tokenBReserve / totalLiquidity;\n        uint256 tokenAAmount = lpTokenAmount * tokenAReserve / totalLiquidity;\n\n        require(tokenBAmount >= minTokenBAmount && tokenAAmount >= minTokenAAmount, "Insufficient amounts");\n\n        require(tokenB.transfer(msg.sender, tokenBAmount), "TokenB transfer failed");\n        require(tokenA.transfer(msg.sender, tokenAAmount), "TokenA transfer failed");\n\n        lpToken.burn(msg.sender, lpTokenAmount);\n        _updateStateVars(tokenABalance - tokenAAmount, tokenBBalance - tokenBAmount);\n        emit RemoveLiquidity(msg.sender, tokenBAmount, tokenAAmount);\n\n        return (tokenBAmount, tokenAAmount);\n    }\n\n\n\n\n\n\n\n\n\n    function getInputPrice(\n        uint256 inputAmount,\n        uint256 inputReserve,\n        uint256 outputReserve\n    ) pure returns (uint256) {\n        require(inputReserve > 0 && outputReserve > 0, "Invalid reserves");\n        uint256 numerator = inputAmount * outputReserve;\n        uint256 denominator = inputReserve + inputAmount;\n        return numerator / denominator;\n    }\n\n\n\n\n\n\n\n\n\n    function swap(\n        bool isAToB,\n        uint256 amountIn,\n        uint256 minAmountOut,\n        uint256 deadline\n    ) external nonReentrant returns (uint256 amountOut) {\n        require(amountIn > 0 && minAmountOut > 0, "Invalid input");\n        require(block.timestamp <= deadline, "EXPIRED");\n\n        Token inputToken = isAToB ? tokenA : tokenB;\n        Token outputToken = isAToB ? tokenB : tokenA;\n\n        uint256 inputReserve = isAToB ? tokenABalance : tokenBBalance;\n        uint256 outputReserve = isAToB ? tokenBBalance : tokenABalance;\n\n        uint256 fee = (amountIn * _swapFeeRate()) / 10000;\n        uint256 lpFee = (fee * _lpSharePercent()) / 10000;\n        uint256 protocolFee = fee - lpFee;\n\n        uint256 netInput = amountIn - fee;\n\n\n        require(inputToken.transferFrom(msg.sender, address(this), amountIn), "Input transfer failed");\n\n\n        require(inputToken.transfer(_feeCollector(), protocolFee), "Protocol fee transfer failed");\n\n        amountOut = getInputPrice(netInput, inputReserve, outputReserve);\n        require(amountOut >= minAmountOut, "Slippage check failed");\n\n        require(outputToken.transfer(msg.sender, amountOut), "Output xfer failed");\n\n\n        if (isAToB) {\n            _updateStateVars(tokenABalance + amountIn - protocolFee, tokenBBalance - amountOut);\n        } else {\n            _updateStateVars(tokenABalance - amountOut, tokenBBalance + amountIn - protocolFee);\n        }\n\n        emit Swap(msg.sender, address(inputToken), address(outputToken), amountIn, amountOut);\n    }\n\n\n\n\n    function transferPoolToFactory(address newFactory) external onlyPoolFactory {\n        require(newFactory != address(0), "Invalid factory address");\n        poolFactory = PoolFactory(newFactory);\n    }\n\n\n\n\n\n\n\n\n\n    function setFeeParameters(\n        uint256 newSwapFeeRate,\n        uint256 newLpSharePercent\n    ) external onlyPoolFactory {\n        require(newSwapFeeRate > 0 && newSwapFeeRate <= 1000, "Invalid swap fee rate"); \n        require(newLpSharePercent > 0 && newLpSharePercent <= 10000, "Invalid LP share percent"); \n\n        swapFeeRate = newSwapFeeRate;\n        lpSharePercent = newLpSharePercent;\n    }\n\n\n\n\n\n    function setZapSwapFeesEnabled(bool enabled) external onlyOwner {\n        zapSwapFeesEnabled = enabled;\n    }\n\n\n\n\n\n\n    function _sqrt(uint256 y) internal pure returns (uint256 z) {\n        if (y > 3) {\n            z = y;\n            uint256 x = y / 2 + 1;\n            while (x < z) {\n                z = x;\n                x = (y / x + x) / 2;\n            }\n        } else if (y != 0) {\n            z = 1;\n        }\n    }\n\n\n\n    function _getOptimalSwapAmount(\n        uint256 reserveIn,\n        uint256 userIn,\n        uint256 feeBps\n    ) public internal returns (uint256) {\n        require(feeBps < 10000, "Fee too high");\n        uint256 a = 10000 - feeBps; \n        uint256 b = 10000;\n\n        uint256 term1 = userIn * 4 * a * b;\n        uint256 term2 = reserveIn * (a + b) * (a + b);\n        uint256 term = _sqrt(reserveIn * (term1 + term2));\n        uint256 numerator = term - reserveIn * (a + b);\n        return numerator / (2 * a);\n    }\n\n    function addLiquiditySingleToken(\n        bool isAToB,\n        uint256 amountIn,\n        uint256 deadline\n    ) external returns (uint256 liquidityMinted) {\n        require(amountIn > 0, "Invalid input");\n        require(block.timestamp <= deadline, "EXPIRED");\n        require(lpToken.totalSupply() > 0, "POOL_EMPTY");\n\n        Token depositToken = isAToB ? tokenA : tokenB;\n\n\n        uint256 reserveIn = isAToB ? tokenABalance : tokenBBalance;\n        uint256 reserveOut = isAToB ? tokenBBalance : tokenABalance;\n        uint256 feeBps = zapSwapFeesEnabled ? _swapFeeRate() : 0;\n        uint256 swapAmount = _getOptimalSwapAmount(reserveIn, amountIn, feeBps);\n        uint256 fee = zapSwapFeesEnabled ? (swapAmount * _swapFeeRate()) / 10000 : 0;\n        uint256 lpFee = zapSwapFeesEnabled ? (fee * _lpSharePercent()) / 10000 : 0;\n        uint256 protocolFee = fee - lpFee;\n        uint256 netInput = swapAmount - fee;\n        uint256 amountOut = getInputPrice(netInput, reserveIn, reserveOut);\n\n\n        uint256 postA = isAToB ? (tokenABalance + swapAmount - protocolFee) : (tokenABalance - amountOut);\n        uint256 postB = isAToB ? (tokenBBalance - amountOut) : (tokenBBalance + swapAmount - protocolFee);\n        uint256 requiredA = isAToB ? (amountOut * postA) / postB : amountOut;\n        uint256 requiredB = isAToB ? amountOut : (amountOut * postB) / postA;\n\n\n        uint256 totalNeeded = isAToB ? (swapAmount + requiredA) : (swapAmount + requiredB);\n        require(totalNeeded <= amountIn, "INSUFFICIENT_INPUT");\n        require(depositToken.transferFrom(msg.sender, address(this), totalNeeded), "Transfer failed");\n        if (zapSwapFeesEnabled && protocolFee > 0) {\n            require(depositToken.transfer(_feeCollector(), protocolFee), "Fee failed");\n        }\n\n\n        uint256 totalLiquidity = lpToken.totalSupply();\n        uint256 tokenAAmount = isAToB ? requiredA : amountOut;\n        uint256 tokenBAmount = isAToB ? amountOut : requiredB;\n        uint256 liquidityA = (tokenAAmount * totalLiquidity) / postA;\n        uint256 liquidityB = (tokenBAmount * totalLiquidity) / postB;\n        liquidityMinted = liquidityA < liquidityB ? liquidityA : liquidityB;\n        require(liquidityMinted > 0, "Insufficient liquidity");\n        lpToken.mint(msg.sender, liquidityMinted);\n\n\n        if (isAToB) {\n            _updateStateVars(tokenABalance + totalNeeded - protocolFee, tokenBBalance);\n        } else {\n            _updateStateVars(tokenABalance, tokenBBalance + totalNeeded - protocolFee);\n        }\n\n        emit AddLiquidity(msg.sender, tokenBAmount, tokenAAmount);\n        return liquidityMinted;\n    }\n\n}\n\n// SPDX-License-Identifier: MIT\npragma solidity ^0.8.0;\n\n\n\n\n\n\n\n\nstruct UserInfo {\n    uint256 amount;      \n    uint256 rewardDebt;  \n}\n\nstruct BonusPeriod {\n    uint256 startTimestamp;   \n    uint256 bonusMultiplier;  \n}\n\nstruct PoolInfo {\n    address lpToken;             \n    uint256 allocPoint;          \n\n    uint256 lastRewardTimestamp; \n    uint256 accPerToken;         \n    BonusPeriod[] bonusPeriods;  \n}\n\n\ncontract record RewardsChef is Ownable {\n\n\n\n\n\n    event PoolAdded(uint256 indexed pid, address indexed lpToken, uint256 allocPoint, uint256 initialBonusMultiplier);\n    event AllocationPointsUpdated(uint256 indexed pid, uint256 oldAllocPoint, uint256 newAllocPoint);\n    event BonusPeriodAdded(uint256 indexed pid, uint256 startTimestamp, uint256 bonusMultiplier);\n    event MinFutureTimeUpdated(uint256 oldMinFutureTime, uint256 newMinFutureTime);\n    event CataPerSecondUpdated(uint256 oldCataPerSecond, uint256 newCataPerSecond);\n    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);\n    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);\n    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);\n    event Claim(address indexed user, uint256 indexed pid, uint256 amount);\n    event CurrentUserAmount(address indexed user, uint256 indexed pid, uint256 currentAmount);\n\n\n\n\n\n\n    uint256 private MAX_INT = 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff;\n\n\n\n\n\n\n    uint256 public PRECISION_MULTIPLIER = 1e18;\n\n\n\n\n\n\n    Token public rewardToken;\n\n\n    uint256 public cataPerSecond;\n\n\n\n    uint256 public totalAllocPoint = 0;\n\n\n    uint256 public minFutureTime;\n\n\n    PoolInfo[] public record pools;\n\n    function getPoolBonusPeriod(uint poolIndex, uint bonusPeriodIndex) public returns (uint, uint) {\n        BonusPeriod bp = pools[poolIndex].bonusPeriods[bonusPeriodIndex];\n        return (bp.startTimestamp, bp.bonusMultiplier);\n    }\n\n\n    mapping(address => bool) private lpTokenInUse;\n\n\n    mapping(uint256 => mapping(address => UserInfo)) public record userInfo;\n\n\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _rewardToken, uint256 _cataPerSecond) external onlyOwner {\n\n\n        MAX_INT = 0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff;\n        PRECISION_MULTIPLIER = 1e18;\n\n        require(_rewardToken != address(0), "Invalid reward token address");\n        rewardToken = Token(_rewardToken);\n        cataPerSecond = _cataPerSecond;\n        pools = [];\n        minFutureTime = 3600; \n    }\n\n\n\n\n\n    function addPool(\n        uint256 _allocPoint,\n        address _lpToken,\n        uint256 _bonusMultiplier\n    ) public onlyOwner {\n        require(!lpTokenInUse[_lpToken], "LP token already exists");\n        require(_lpToken != address(rewardToken), "LP token cannot be the same as reward token");\n        require(_bonusMultiplier >= 1, "Bonus multiplier must be at least 1");\n\n        massUpdatePools();\n\n        totalAllocPoint += _allocPoint;\n        require(totalAllocPoint > 0, "Total allocation points must be greater than zero");\n\n        require(cataPerSecond >= totalAllocPoint, "cataPerSecond must be >= totalAllocPoint to prevent precision loss");\n\n\n        PoolInfo memory poolInfo;\n        poolInfo.lpToken = _lpToken;\n        poolInfo.allocPoint = _allocPoint;\n        poolInfo.lastRewardTimestamp = block.timestamp;\n        poolInfo.accPerToken = 0;\n        poolInfo.bonusPeriods = [];\n        poolInfo.bonusPeriods.push(BonusPeriod(block.timestamp, _bonusMultiplier));\n\n        pools.push(poolInfo);\n        lpTokenInUse[_lpToken] = true;\n\n        emit PoolAdded(pools.length - 1, _lpToken, _allocPoint, _bonusMultiplier);\n    }\n\n    function updateAllocationPoints(\n        uint256 _pid,\n        uint256 _allocPoint\n    ) public onlyOwner {\n        require(_pid < pools.length, "Pool does not exist");\n\n        massUpdatePools();\n\n        uint256 oldAllocPoint = pools[_pid].allocPoint;\n        totalAllocPoint = totalAllocPoint - oldAllocPoint + _allocPoint;\n        require(totalAllocPoint > 0, "Total allocation points must be greater than zero");\n\n        require(cataPerSecond >= totalAllocPoint, "cataPerSecond must be >= totalAllocPoint to prevent precision loss");\n        pools[_pid].allocPoint = _allocPoint;\n\n        emit AllocationPointsUpdated(_pid, oldAllocPoint, _allocPoint);\n    }\n\n    function updateCataPerSecond(uint256 _cataPerSecond) public onlyOwner {\n\n        require(_cataPerSecond >= totalAllocPoint, "cataPerSecond must be >= totalAllocPoint to prevent precision loss");\n\n\n\n        massUpdatePools();\n\n        uint256 oldCataPerSecond = cataPerSecond;\n        cataPerSecond = _cataPerSecond;\n\n        emit CataPerSecondUpdated(oldCataPerSecond, _cataPerSecond);\n    }\n\n    function addBonusPeriod(\n        uint256 _pid,\n        uint256 _startTimestamp,\n        uint256 _bonusMultiplier\n    ) public onlyOwner {\n        require(_pid < pools.length, "Pool does not exist");\n        require(_bonusMultiplier >= 1, "Bonus multiplier must be at least 1");\n        require(_startTimestamp >= block.timestamp + minFutureTime, "Start timestamp must be far enough in the future");\n\n\n        uint256 periodsLength = pools[_pid].bonusPeriods.length;\n        require(_startTimestamp > pools[_pid].bonusPeriods[periodsLength - 1].startTimestamp,\n                "New period must start after the last period");\n\n        pools[_pid].bonusPeriods.push(BonusPeriod(_startTimestamp, _bonusMultiplier));\n\n        emit BonusPeriodAdded(_pid, _startTimestamp, _bonusMultiplier);\n    }\n\n    function updateMinFutureTime(uint256 _minFutureTime) public onlyOwner {\n        require(_minFutureTime >= 60, "Minimum future time must be at least 60 seconds");\n        uint256 oldMinFutureTime = minFutureTime;\n        minFutureTime = _minFutureTime;\n        emit MinFutureTimeUpdated(oldMinFutureTime, _minFutureTime);\n    }\n\n    function getMultiplier(uint256 _pid, uint256 _from, uint256 _to) public view returns (uint256) {\n        require(_pid < pools.length, "Pool does not exist");\n        require(_from <= _to, "From timestamp must be less than or equal to to timestamp");\n\n        if (_from == _to) {\n            return 0;\n        }\n\n        BonusPeriod[] storage periods = pools[_pid].bonusPeriods;\n        uint256 totalMultipliedTime = 0;\n        uint256 currentTime = _from;\n\n        for (uint256 i = 0; i < periods.length && currentTime < _to; i++) {\n            uint256 periodStart = periods[i].startTimestamp;\n            uint256 periodEnd = (i + 1 < periods.length) ? periods[i + 1].startTimestamp : MAX_INT;\n\n            if (currentTime < periodStart) {\n                currentTime = periodStart;\n            }\n\n            if (currentTime < _to && currentTime < periodEnd) {\n                uint256 segmentEnd = (_to < periodEnd) ? _to : periodEnd;\n                uint256 segmentDuration = segmentEnd - currentTime;\n                totalMultipliedTime += segmentDuration * (periods[i].bonusMultiplier);\n                currentTime = segmentEnd;\n            }\n        }\n\n        return totalMultipliedTime;\n    }\n\n    function updatePool(uint256 _pid) public {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        if (block.timestamp <= pool.lastRewardTimestamp) {\n            return;\n        }\n\n        uint256 lpSupply = ERC20(pool.lpToken).balanceOf(address(this));\n        if (lpSupply == 0) {\n            pool.lastRewardTimestamp = block.timestamp;\n            return;\n        }\n\n        uint256 multiplier = getMultiplier(_pid, pool.lastRewardTimestamp, block.timestamp);\n\n        uint256 cataReward = (multiplier * cataPerSecond * pool.allocPoint) / totalAllocPoint;\n\n        rewardToken.mint(address(this), cataReward);\n\n        pool.accPerToken += (cataReward * PRECISION_MULTIPLIER) / lpSupply;\n        pool.lastRewardTimestamp = block.timestamp;\n    }\n\n    function massUpdatePools() public {\n        uint256 poolCount = pools.length;\n        for (uint256 pid = 0; pid < poolCount; pid++) {\n            updatePool(pid);\n        }\n    }\n\n\n\n\n\n    function deposit(uint256 _pid, uint256 _amount) public {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        UserInfo storage user = userInfo[_pid][msg.sender];\n\n        updatePool(_pid);\n\n        if (user.amount > 0) {\n            uint256 pending = ((user.amount * pool.accPerToken) / PRECISION_MULTIPLIER) - user.rewardDebt;\n            if (pending > 0) {\n                rewardToken.transfer(msg.sender, pending);\n            }\n        }\n\n        if (_amount > 0) {\n            ERC20(pool.lpToken).transferFrom(msg.sender, address(this), _amount);\n            user.amount += _amount;\n        }\n\n\n\n\n\n\n        uint256 rewardDebt = (user.amount * pool.accPerToken) / PRECISION_MULTIPLIER;\n        user.rewardDebt = rewardDebt;\n\n        emit CurrentUserAmount(msg.sender, _pid, user.amount);\n        emit Deposit(msg.sender, _pid, _amount);\n    }\n\n    function withdraw(uint256 _pid, uint256 _amount) public {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        UserInfo storage user = userInfo[_pid][msg.sender];\n\n        require(user.amount >= _amount, "withdraw: not good");\n\n        updatePool(_pid);\n\n        uint256 pending = ((user.amount * pool.accPerToken) / PRECISION_MULTIPLIER) - user.rewardDebt;\n        if (pending > 0) {\n            ERC20(rewardToken).transfer(msg.sender, pending);\n        }\n\n        if (_amount > 0) {\n            user.amount -= _amount;\n            ERC20(pool.lpToken).transfer(msg.sender, _amount);\n        }\n\n\n\n\n\n\n        uint256 rewardDebt = (user.amount * pool.accPerToken) / PRECISION_MULTIPLIER;\n        user.rewardDebt = rewardDebt;\n\n        emit CurrentUserAmount(msg.sender, _pid, user.amount);\n        emit Withdraw(msg.sender, _pid, _amount);\n    }\n\n    function emergencyWithdraw(uint256 _pid) public {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        UserInfo storage user = userInfo[_pid][msg.sender];\n\n        uint256 amount = user.amount;\n        user.amount = 0;\n        user.rewardDebt = 0;\n\n        if (amount > 0) {\n            ERC20(pool.lpToken).transfer(msg.sender, amount);\n        }\n\n        emit EmergencyWithdraw(msg.sender, _pid, amount);\n    }\n\n    function claim(uint256 _pid) public {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        UserInfo storage user = userInfo[_pid][msg.sender];\n\n        updatePool(_pid);\n\n        uint256 pending = ((user.amount * pool.accPerToken) / PRECISION_MULTIPLIER) - user.rewardDebt;\n        if (pending > 0) {\n            rewardToken.transfer(msg.sender, pending);\n        }\n\n\n\n\n\n\n        uint256 rewardDebt = (user.amount * pool.accPerToken) / PRECISION_MULTIPLIER;\n        user.rewardDebt = rewardDebt;\n\n        emit Claim(msg.sender, _pid, pending);\n    }\n\n    function claimAll() public {\n        for (uint256 pid = 0; pid < pools.length; pid++) {\n            UserInfo storage user = userInfo[pid][msg.sender];\n            if (user.amount > 0) {\n                claim(pid);\n            }\n        }\n    }\n\n    function pendingCata(uint256 _pid, address _user) external view returns (uint256) {\n        require(_pid < pools.length, "Pool does not exist");\n\n        PoolInfo storage pool = pools[_pid];\n        UserInfo storage user = userInfo[_pid][_user];\n\n        uint256 accPerToken = pool.accPerToken;\n        uint256 lpSupply = ERC20(pool.lpToken).balanceOf(address(this));\n\n        if (block.timestamp > pool.lastRewardTimestamp && lpSupply != 0) {\n            uint256 multiplier = getMultiplier(_pid, pool.lastRewardTimestamp, block.timestamp);\n            uint256 cataReward = (multiplier * cataPerSecond * pool.allocPoint) / totalAllocPoint;\n            accPerToken += (cataReward * PRECISION_MULTIPLIER) / lpSupply;\n        }\n\n        return ((user.amount * accPerToken) / PRECISION_MULTIPLIER) - user.rewardDebt;\n    }\n\n    function pendingCataAll(address _user) external view returns (uint256) {\n        uint256 totalPending = 0;\n\n        for (uint256 pid = 0; pid < pools.length; pid++) {\n            PoolInfo storage pool = pools[pid];\n            UserInfo storage user = userInfo[pid][_user];\n\n            uint256 accPerToken = pool.accPerToken;\n            uint256 lpSupply = ERC20(pool.lpToken).balanceOf(address(this));\n\n            if (block.timestamp > pool.lastRewardTimestamp && lpSupply != 0) {\n                uint256 multiplier = getMultiplier(pid, pool.lastRewardTimestamp, block.timestamp);\n                uint256 cataReward = (multiplier * cataPerSecond * pool.allocPoint) / totalAllocPoint;\n                accPerToken += (cataReward * PRECISION_MULTIPLIER) / lpSupply;\n            }\n\n            uint256 pending = ((user.amount * accPerToken) / PRECISION_MULTIPLIER) - user.rewardDebt;\n            totalPending += pending;\n        }\n\n        return totalPending;\n    }\n\n    function getBalance(uint256 _pid, address _user) external view returns (uint256) {\n        require(_pid < pools.length, "Pool does not exist");\n        return userInfo[_pid][_user].amount;\n    }\n}\n\n\n\n\n\n\n\n\n\nenum ActivityType {\n    Position,  \n    OneTime    \n}\n\nenum ActionType {\n    Deposit,   \n    Withdraw,  \n    Occurred   \n}\n\nstruct Action {\n    address sourceContract; \n    string eventName;       \n    address user;           \n    uint256 amount;         \n    uint256 blockNumber;    \n    uint256 eventIndex;     \n}\n\nstruct ActionableEvent {\n    string eventName;    \n    ActionType actionType; \n}\n\nstruct RewardsUserInfo {\n    uint256 stake;       \n    uint256 userIndex;   \n}\n\n\nstruct Activity {\n    string name;                 \n    ActivityType activityType;   \n    uint256 emissionRate;        \n    address sourceContract;      \n    ActionableEvent[] actionableEvents; \n    uint256 minAmount;           \n    uint256 weightMultiplier;    \n}\n\n\nstruct ActivityState {\n    uint256 accRewardPerStake;   \n    uint256 lastUpdateTime;      \n    uint256 totalStake;          \n}\n\n\ncontract record Rewards is Ownable {\n\n\n\n\n\n    event ActivityIndexUpdated(uint256 indexed activityId, uint256 accRewardPerStake, uint256 totalStake);\n    event UserStakeUpdated(uint256 indexed activityId, address indexed user, uint256 oldStake, uint256 newStake, uint256 pendingRewards);\n    event ActivityAdded(uint256 indexed activityId, string name, uint256 emissionRate, address sourceContract);\n    event EmissionRateUpdated(uint256 indexed activityId, uint256 oldRate, uint256 newRate);\n    event SourceContractUpdated(uint256 indexed activityId, address oldSourceContract, address newSourceContract);\n    event RewardsClaimed(address indexed user, uint256 amount);\n    event MaxBatchSizeUpdated(uint256 oldMaxBatchSize, uint256 newMaxBatchSize);\n    event ActivityMinAmountUpdated(uint256 indexed activityId, uint256 oldMinAmount, uint256 newMinAmount);\n    event ActivityWeightUpdated(uint256 indexed activityId, uint256 oldWeight, uint256 newWeight);\n    event SeasonAnnouncement(uint256 indexed seasonId, string seasonName, uint256 timestamp);\n    event ActionProcessed(\n        uint256 indexed activityId,\n        address indexed user,\n        address indexed sourceContract,\n        string eventName,\n        ActionType actionType,\n        uint256 amount,\n        uint256 blockNumber,\n        uint256 eventIndex\n    );\n    event ActionFailed(\n        address indexed sourceContract,\n        address indexed user,\n        string eventName,\n        uint256 blockNumber,\n        uint256 eventIndex,\n        string reason\n    );\n    event ActivityNameUpdated(uint256 indexed activityId, string newName);\n\n\n\n\n\n\n    uint256 public PRECISION_MULTIPLIER = 1e18;\n\n\n\n\n\n\n    Token public rewardToken;\n\n\n    mapping(uint256 => Activity) public record activities;\n\n\n    mapping(uint256 => ActivityState) public record activityStates;\n\n\n    uint256[] public activityIds;\n\n\n    uint256 public nextActivityId = 1;\n\n\n    uint256 public totalRewardsEmission;\n\n\n    mapping(address => mapping(uint256 => RewardsUserInfo)) public record userInfo;\n\n\n    mapping(address => uint256) public record unclaimedRewards;\n\n\n\n\n\n\n    struct EventInfo {\n        uint256 activityId;  \n        ActionType actionType;\n    }\n\n\n\n    mapping(address => mapping(string => EventInfo)) public record sourceEventInfo;\n\n\n\n\n\n\n\n\n    mapping(string => bool) public record processedEvents;\n\n\n    uint256 public highestBlockSeen;\n\n\n\n\n\n\n    uint256 public maxBatchSize = 100;\n\n\n    uint256 public currentSeason = 1;\n\n\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _rewardToken) external onlyOwner {\n        require(_rewardToken != address(0), "Invalid reward token address");\n        rewardToken = Token(_rewardToken);\n        PRECISION_MULTIPLIER = 1e18;\n    }\n\n\n\n\n\n    \n    function massUpdateActivitiesIndices() public {\n        for (uint256 i = 0; i < activityIds.length; i++) {\n            _updateActivityIndex(activityIds[i]);\n        }\n    }\n\n    \n    function addPositionActivity(\n        string  name,\n        uint256 emissionRate,\n        address sourceContract,\n        ActionableEvent[]  actionableEvents\n    ) external onlyOwner returns (uint256) {\n        require(actionableEvents.length > 0, "At least one actionable event required");\n        return _addActivity(name, ActivityType.Position, emissionRate, sourceContract, actionableEvents);\n    }\n\n    \n    function addOneTimeActivity(\n        string  name,\n        uint256 emissionRate,\n        address sourceContract,\n        string  eventName\n    ) external onlyOwner returns (uint256) {\n        ActionableEvent[]  actionableEvents = new ActionableEvent[](1);\n        actionableEvents[0] = ActionableEvent(eventName, ActionType.Occurred);\n        return _addActivity(name, ActivityType.OneTime, emissionRate, sourceContract, actionableEvents);\n    }\n\n    \n    function addPositionActivitySimple(\n        string  name,\n        uint256 emissionRate,\n        address sourceContract,\n        string  depositEventName,\n        string  withdrawEventName\n    ) external onlyOwner returns (uint256) {\n        ActionableEvent[]  actionableEvents = new ActionableEvent[](2);\n        actionableEvents[0] = ActionableEvent(depositEventName, ActionType.Deposit);\n        actionableEvents[1] = ActionableEvent(withdrawEventName, ActionType.Withdraw);\n        return _addActivity(name, ActivityType.Position, emissionRate, sourceContract, actionableEvents);\n    }\n\n    \n    function setEmissionRate(uint256 activityId, uint256 newEmissionRate) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n\n\n        _updateActivityIndex(activityId);\n\n        uint256 oldRate = activity.emissionRate;\n        activity.emissionRate = newEmissionRate;\n\n\n        totalRewardsEmission = totalRewardsEmission - oldRate + newEmissionRate;\n\n        emit EmissionRateUpdated(activityId, oldRate, newEmissionRate);\n    }\n\n    \n    function setActivityName(uint256 activityId, string newName) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        activity.name = newName;\n        emit ActivityNameUpdated(activityId, newName);\n    }\n\n    \n    function setSourceContract(uint256 activityId, address newSourceContract) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        require(newSourceContract != address(0), "Invalid source contract address");\n\n        address oldSourceContract = activity.sourceContract;\n\n\n        for (uint256 removeIdx = 0; removeIdx < activity.actionableEvents.length; removeIdx++) {\n            string  evt = activity.actionableEvents[removeIdx].eventName;\n            delete sourceEventInfo[oldSourceContract][evt].activityId;\n            delete sourceEventInfo[oldSourceContract][evt].actionType;\n        }\n\n\n        for (uint256 checkIdx = 0; checkIdx < activity.actionableEvents.length; checkIdx++) {\n            string  evt = activity.actionableEvents[checkIdx].eventName;\n            EventInfo storage existing = sourceEventInfo[newSourceContract][evt];\n            require(\n                existing.activityId == 0 || existing.activityId == activityId,\n                "Event already used by another activity for this sourceContract"\n            );\n        }\n\n\n        activity.sourceContract = newSourceContract;\n\n\n        for (uint256 j = 0; j < activity.actionableEvents.length; j++) {\n            ActionableEvent  ae = activity.actionableEvents[j];\n            sourceEventInfo[newSourceContract][ae.eventName] = EventInfo(activityId, ae.actionType);\n        }\n\n        emit SourceContractUpdated(activityId, oldSourceContract, newSourceContract);\n    }\n\n    \n    function setMaxBatchSize(uint256 newMaxBatchSize) external onlyOwner {\n        require(newMaxBatchSize > 0, "Batch size must be greater than 0");\n\n        uint256 oldMaxBatchSize = maxBatchSize;\n        maxBatchSize = newMaxBatchSize;\n\n        emit MaxBatchSizeUpdated(oldMaxBatchSize, newMaxBatchSize);\n    }\n\n    \n    function setActivityMinAmount(uint256 activityId, uint256 newMinAmount) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n\n        uint256 oldMinAmount = activity.minAmount;\n        activity.minAmount = newMinAmount;\n\n        emit ActivityMinAmountUpdated(activityId, oldMinAmount, newMinAmount);\n    }\n\n    \n    function setActivityWeight(uint256 activityId, uint256 newWeight) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        require(activity.activityType == ActivityType.OneTime, "Only for OneTime activities");\n        require(newWeight > 0, "Weight must be > 0");\n\n        uint256 oldWeight = activity.weightMultiplier;\n        activity.weightMultiplier = newWeight;\n\n        emit ActivityWeightUpdated(activityId, oldWeight, newWeight);\n    }\n\n    \n    function announceNewSeason(string  seasonName) external onlyOwner {\n\n\n\n        massUpdateActivitiesIndices();\n\n\n        currentSeason++;\n\n        emit SeasonAnnouncement(currentSeason, seasonName, block.timestamp);\n    }\n\n    \n    function setPositionActivityEvents(\n        uint256 activityId,\n        ActionableEvent[]  newActionableEvents\n    ) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        require(activity.activityType == ActivityType.Position, "Only for Position activities");\n\n        ActivityState storage state = activityStates[activityId];\n        require(state.totalStake == 0, "Cannot change events while activity has stakes");\n        require(newActionableEvents.length > 0, "At least one actionable event required");\n\n        address sourceContract = activity.sourceContract;\n\n\n        for (uint256 evtIdx = 0; evtIdx < newActionableEvents.length; evtIdx++) {\n            EventInfo storage existingInfo = sourceEventInfo[sourceContract][newActionableEvents[evtIdx].eventName];\n            require(\n                existingInfo.activityId == 0 || existingInfo.activityId == activityId,\n                "Event name already exists for this source contract"\n            );\n        }\n\n\n        for (uint256 typeIdx = 0; typeIdx < newActionableEvents.length; typeIdx++) {\n            require(\n                newActionableEvents[typeIdx].actionType == ActionType.Deposit ||\n                newActionableEvents[typeIdx].actionType == ActionType.Withdraw,\n                "Position activity cannot use Occurred action type"\n            );\n        }\n\n\n        for (uint256 oldIdx = 0; oldIdx < activity.actionableEvents.length; oldIdx++) {\n            delete sourceEventInfo[sourceContract][activity.actionableEvents[oldIdx].eventName].activityId;\n            delete sourceEventInfo[sourceContract][activity.actionableEvents[oldIdx].eventName].actionType;\n        }\n\n\n\n        activity.actionableEvents = newActionableEvents;\n\n\n        for (uint256 j = 0; j < newActionableEvents.length; j++) {\n            sourceEventInfo[sourceContract][newActionableEvents[j].eventName] = EventInfo(activityId, newActionableEvents[j].actionType);\n        }\n    }\n\n    \n    function setPositionActivityEventsSimple(\n        uint256 activityId,\n        string depositEventName,\n        string withdrawEventName\n    ) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        require(activity.activityType == ActivityType.Position, "Only for Position activities");\n\n        ActivityState storage state = activityStates[activityId];\n        require(state.totalStake == 0, "Cannot change events while activity has stakes");\n\n        address sourceContract = activity.sourceContract;\n\n\n        EventInfo storage depositInfo = sourceEventInfo[sourceContract][depositEventName];\n        require(\n            depositInfo.activityId == 0 || depositInfo.activityId == activityId,\n            "Deposit event name already exists for this source contract"\n        );\n        EventInfo storage withdrawInfo = sourceEventInfo[sourceContract][withdrawEventName];\n        require(\n            withdrawInfo.activityId == 0 || withdrawInfo.activityId == activityId,\n            "Withdraw event name already exists for this source contract"\n        );\n\n\n        for (uint256 oldIdx = 0; oldIdx < activity.actionableEvents.length; oldIdx++) {\n            delete sourceEventInfo[sourceContract][activity.actionableEvents[oldIdx].eventName].activityId;\n            delete sourceEventInfo[sourceContract][activity.actionableEvents[oldIdx].eventName].actionType;\n        }\n\n\n        ActionableEvent[] newActionableEvents = new ActionableEvent[](2);\n        newActionableEvents[0] = ActionableEvent(depositEventName, ActionType.Deposit);\n        newActionableEvents[1] = ActionableEvent(withdrawEventName, ActionType.Withdraw);\n\n\n        activity.actionableEvents = newActionableEvents;\n\n\n        sourceEventInfo[sourceContract][depositEventName] = EventInfo(activityId, ActionType.Deposit);\n        sourceEventInfo[sourceContract][withdrawEventName] = EventInfo(activityId, ActionType.Withdraw);\n    }\n\n    \n    function setOneTimeActivityEvent(\n        uint256 activityId,\n        string  newEventName\n    ) external onlyOwner {\n        Activity storage activity = activities[activityId];\n        require(activity.sourceContract != address(0), "Activity does not exist");\n        require(activity.activityType == ActivityType.OneTime, "Only for OneTime activities");\n\n        ActivityState storage state = activityStates[activityId];\n        require(state.totalStake == 0, "Cannot change events while activity has stakes");\n        require(bytes(newEventName).length > 0, "Event name cannot be empty");\n\n        address sourceContract = activity.sourceContract;\n\n\n        EventInfo storage existingInfo = sourceEventInfo[sourceContract][newEventName];\n        require(\n            existingInfo.activityId == 0 || existingInfo.activityId == activityId,\n            "Event name already exists for this source contract"\n        );\n\n\n        string  oldEventName = activity.actionableEvents[0].eventName;\n        delete sourceEventInfo[sourceContract][oldEventName].activityId;\n        delete sourceEventInfo[sourceContract][oldEventName].actionType;\n\n\n        activity.actionableEvents[0].eventName = newEventName;\n\n\n        sourceEventInfo[sourceContract][newEventName] = EventInfo(activityId, ActionType.Occurred);\n    }\n\n    \n    function claimRewards(uint256[] calldata activityIdsToSettle) external {\n        address user = msg.sender;\n\n\n        for (uint256 i = 0; i < activityIdsToSettle.length; i++) {\n            _settlePendingRewards(activityIdsToSettle[i], user);\n        }\n\n\n        uint256 totalRewards = unclaimedRewards[user];\n        require(totalRewards > 0, "No rewards to claim");\n\n\n        require(rewardToken.balanceOf(address(this)) >= totalRewards, "Insufficient reward tokens");\n\n\n        unclaimedRewards[user] = 0;\n        rewardToken.transfer(user, totalRewards);\n\n        emit RewardsClaimed(user, totalRewards);\n    }\n\n    \n    function claimAllRewards() external {\n        address user = msg.sender;\n\n\n        for (uint256 i = 0; i < activityIds.length; i++) {\n            _settlePendingRewards(activityIds[i], user);\n        }\n\n\n        uint256 totalRewards = unclaimedRewards[user];\n        require(totalRewards > 0, "No rewards to claim");\n\n\n        require(rewardToken.balanceOf(address(this)) >= totalRewards, "Insufficient reward tokens");\n\n\n        unclaimedRewards[user] = 0;\n        rewardToken.transfer(user, totalRewards);\n\n        emit RewardsClaimed(user, totalRewards);\n    }\n\n    \n    function handleAction(\n        address sourceContract,\n        string calldata eventName,\n        address user,\n        uint256 amount,\n        uint256 blockNumber,\n        uint256 eventIndex\n    ) external onlyOwner {\n        Action  action = Action({\n            sourceContract: sourceContract,\n            eventName: eventName,\n            user: user,\n            amount: amount,\n            blockNumber: blockNumber,\n            eventIndex: eventIndex\n        });\n        _handleAction(action);\n    }\n\n    \n    function batchHandleAction(\n        address[] calldata sourceContracts,\n        string[] calldata eventNames,\n        address[] calldata users,\n        uint256[] calldata amounts,\n        uint256[] calldata blockNumbers,\n        uint256[] calldata eventIndexes\n    ) external onlyOwner {\n\n        if (maxBatchSize == 0) {\n            maxBatchSize = 100;\n        }\n        require(sourceContracts.length <= maxBatchSize, "Batch too large");\n        require(\n            sourceContracts.length == eventNames.length &&\n            eventNames.length == users.length &&\n            users.length == amounts.length &&\n            amounts.length == blockNumbers.length &&\n            blockNumbers.length == eventIndexes.length,\n            "Array length mismatch"\n        );\n\n        for (uint256 i = 0; i < sourceContracts.length; i++) {\n            try {\n                Action action = Action({\n                    sourceContract: sourceContracts[i],\n                    eventName: eventNames[i],\n                    user: users[i],\n                    amount: amounts[i],\n                    blockNumber: blockNumbers[i],\n                    eventIndex: eventIndexes[i]\n                });\n                _handleAction(action);\n            } catch {\n                emit ActionFailed(sourceContracts[i], users[i], eventNames[i], blockNumbers[i], eventIndexes[i], "Action failed");\n            }\n        }\n    }\n\n\n\n\n\n    \n    function _addActivity(\n        string  name,\n        ActivityType activityType,\n        uint256 emissionRate,\n        address sourceContract,\n        ActionableEvent[]  actionableEvents\n    ) internal returns (uint256) {\n        require(sourceContract != address(0), "Invalid source contract address");\n        require(bytes(name).length > 0, "Name cannot be empty");\n\n\n        for (uint256 evtIdx = 0; evtIdx < actionableEvents.length; evtIdx++) {\n            require(\n                sourceEventInfo[sourceContract][actionableEvents[evtIdx].eventName].activityId == 0,\n                "Event name already exists for this source contract"\n            );\n        }\n\n\n        if (activityType == ActivityType.Position) {\n            for (uint256 posIdx = 0; posIdx < actionableEvents.length; posIdx++) {\n                require(\n                    actionableEvents[posIdx].actionType == ActionType.Deposit ||\n                    actionableEvents[posIdx].actionType == ActionType.Withdraw,\n                    "Position activity cannot use Occurred action type"\n                );\n            }\n        }\n\n        if (activityType == ActivityType.OneTime) {\n            for (uint256 oneIdx = 0; oneIdx < actionableEvents.length; oneIdx++) {\n                require(\n                    actionableEvents[oneIdx].actionType == ActionType.Occurred,\n                    "OneTime activity must use Occurred action type"\n                );\n            }\n        }\n\n\n\n        if (nextActivityId == 0) {\n            nextActivityId = 1;\n        }\n        uint256 activityId = nextActivityId;\n        nextActivityId++;\n\n\n        Activity storage activity = activities[activityId];\n        activity.name = name;\n        activity.activityType = activityType;\n        activity.emissionRate = emissionRate;\n        activity.sourceContract = sourceContract;\n        activity.minAmount = 0; \n        activity.weightMultiplier = 1e18; \n\n\n        ActivityState storage state = activityStates[activityId];\n        state.accRewardPerStake = 0;\n        state.lastUpdateTime = block.timestamp;\n        state.totalStake = 0;\n\n\n        for (uint256 regIdx = 0; regIdx < actionableEvents.length; regIdx++) {\n            activity.actionableEvents.push(actionableEvents[regIdx]);\n            sourceEventInfo[sourceContract][actionableEvents[regIdx].eventName] = EventInfo(activityId, actionableEvents[regIdx].actionType);\n        }\n\n        activityIds.push(activityId);\n\n\n        totalRewardsEmission += emissionRate;\n\n        emit ActivityAdded(activityId, name, emissionRate, sourceContract);\n\n        return activityId;\n    }\n\n    \n    function _handleAction(Action calldata action) internal {\n\n\n\n\n\n\n\n        string eventHash = keccak256(action.blockNumber, action.eventIndex);\n\n\n        if (processedEvents[eventHash]) {\n\n            return;\n        }\n\n\n        processedEvents[eventHash] = true;\n\n\n        if (action.blockNumber > highestBlockSeen) {\n            highestBlockSeen = action.blockNumber;\n        }\n\n\n\n\n\n\n\n        EventInfo storage eventInfo = sourceEventInfo[action.sourceContract][action.eventName];\n        require(eventInfo.activityId != 0, "Activity not found for source/event");\n\n        uint256 activityId = eventInfo.activityId;\n        ActionType actionType = eventInfo.actionType;\n\n        Activity storage activity = activities[activityId];      \n        ActivityState storage state = activityStates[activityId]; \n\n\n        require(action.user != address(0), "Invalid user");\n\n\n        if (activity.activityType == ActivityType.OneTime) {\n            require(actionType == ActionType.Occurred, "Invalid action for OneTime activity");\n        }\n\n\n        if (action.amount == 0) {\n\n\n            return;\n        }\n\n\n        if (activity.minAmount > 0 && action.amount < activity.minAmount) {\n\n            return;\n        }\n\n\n\n\n\n\n        if (actionType == ActionType.Deposit || actionType == ActionType.Withdraw) {\n            require(activity.activityType == ActivityType.Position, "Only for Position activities");\n        } else {\n            require(activity.activityType == ActivityType.OneTime, "Only for OneTime activities");\n        }\n\n\n        emit ActionProcessed(\n            activityId,\n            action.user,\n            action.sourceContract,\n            action.eventName,\n            actionType,\n            action.amount,\n            action.blockNumber,\n            action.eventIndex\n        );\n\n\n        bool isIncrease = (actionType != ActionType.Withdraw);\n\n\n        _updateActivityIndex(activityId);\n\n\n        RewardsUserInfo storage userState = userInfo[action.user][activityId];\n        uint256 oldStake = userState.stake;\n        uint256 pendingRewards = 0;\n\n        if (oldStake > 0) {\n\n            uint256 indexDelta = state.accRewardPerStake - userState.userIndex;\n            pendingRewards = (oldStake * indexDelta) / PRECISION_MULTIPLIER;\n\n            if (pendingRewards > 0) {\n                unclaimedRewards[action.user] += pendingRewards;\n            }\n        }\n\n\n        uint256 newStake;\n\n        if (activity.activityType == ActivityType.OneTime) {\n\n\n\n\n            uint256 weighted = (action.amount * activity.weightMultiplier) / PRECISION_MULTIPLIER;\n            newStake = oldStake + weighted;\n        } else {\n\n            if (isIncrease) {\n                newStake = oldStake + action.amount;\n            } else {\n\n\n                if (oldStake >= action.amount) {\n                    newStake = oldStake - action.amount;\n                } else {\n\n\n                    newStake = 0;\n                }\n            }\n        }\n\n\n        userState.stake = newStake;\n        userState.userIndex = state.accRewardPerStake;\n\n\n        state.totalStake = state.totalStake + newStake - oldStake;\n\n        emit UserStakeUpdated(activityId, action.user, oldStake, newStake, pendingRewards);\n    }\n\n    \n    function _settlePendingRewards(uint256 activityId, address user) internal {\n\n        _updateActivityIndex(activityId);\n\n        ActivityState storage state = activityStates[activityId];\n        RewardsUserInfo storage userState = userInfo[user][activityId];\n        uint256 userStake = userState.stake;\n\n        if (userStake > 0) {\n\n            uint256 indexDelta = state.accRewardPerStake - userState.userIndex;\n            uint256 pending = (userStake * indexDelta) / PRECISION_MULTIPLIER;\n\n            if (pending > 0) {\n                unclaimedRewards[user] += pending;\n            }\n\n\n            userState.userIndex = state.accRewardPerStake;\n        }\n    }\n\n    \n    function _updateActivityIndex(uint256 activityId) internal {\n        Activity storage activity = activities[activityId];      \n        ActivityState storage state = activityStates[activityId]; \n\n\n        if (block.timestamp <= state.lastUpdateTime) {\n            return;\n        }\n\n\n        if (state.totalStake == 0) {\n            state.lastUpdateTime = block.timestamp;\n            return;\n        }\n\n\n        uint256 dt = block.timestamp - state.lastUpdateTime;\n\n\n        uint256 reward = activity.emissionRate * dt;\n\n\n        state.accRewardPerStake += (reward * PRECISION_MULTIPLIER) / state.totalStake;\n        state.lastUpdateTime = block.timestamp;\n\n        emit ActivityIndexUpdated(activityId, state.accRewardPerStake, state.totalStake);\n    }\n\n}\n\n\n\n\n\n\n\n\n\ncontract record LiquidityPool is Ownable  {\n    event Deposited(address indexed user, uint amount, uint mTokenMinted);\n    event DepositedOnBehalfOf(address indexed depositor, address indexed recipient, uint amount, uint mTokenMinted);\n    event Withdrawn(address indexed user, uint amount, uint mTokenBurned);\n    event Borrowed(address indexed user, uint amount);\n    event Repaid(address indexed user, uint amount);\n\n    LendingRegistry public registry;\n    Token public mToken;\n\n\n    modifier onlyLendingPool() {\n        require(msg.sender == address(registry.lendingPool()), "Caller is not LendingPool");\n        _;\n    }\n\n    constructor(address _owner) Ownable(_owner) { }\n\n    function initialize(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry");\n        registry = LendingRegistry(_registry);\n    }\n\n    \n    function _getAsset() internal view returns (address) {\n        return LendingPool(registry.lendingPool()).borrowableAsset();\n    }\n\n    \n    function getUnderlyingBalance() external view returns (uint) {\n        address asset = _getAsset();\n        return IERC20(asset).balanceOf(address(this));\n    }\n\n    \n    function deposit(uint amount, uint mintAmount, address user) external onlyLendingPool {\n        require(amount > 0 && mintAmount > 0 && user != address(0), "Invalid deposit");\n        require(address(mToken) != address(0), "mToken not set");\n\n        address asset = _getAsset();\n\n\n        require(IERC20(asset).transferFrom(user, address(this), amount), "Transfer failed");\n\n\n        mToken.mint(user, mintAmount);\n\n        emit Deposited(user, amount, mintAmount);\n    }\n\n    function depositOnBehalfOf(address recipient, uint amount, uint mintAmount, address depositor) external onlyLendingPool {\n        require(recipient != address(0) && amount > 0 && mintAmount > 0 && depositor != address(0), "Invalid deposit");\n        require(address(mToken) != address(0), "mToken not set");\n\n        address asset = _getAsset();\n\n\n        require(IERC20(asset).transferFrom(depositor, address(this), amount), "Transfer failed");\n\n\n        mToken.mint(recipient, mintAmount);\n\n        emit DepositedOnBehalfOf(depositor, recipient, amount, mintAmount);\n        emit Deposited(recipient, amount, mintAmount); \n    }\n\n    \n    function withdraw(uint mTokenAmount, address user, uint underlyingAmount) external onlyLendingPool {\n        require(mTokenAmount > 0 && user != address(0), "Invalid withdrawal");\n        require(underlyingAmount > 0, "Invalid underlying amount");\n        require(address(mToken) != address(0), "mToken not set");\n\n        address asset = _getAsset();\n        uint currentBalance = IERC20(asset).balanceOf(address(this));\n\n        uint reserves = LendingPool(registry.lendingPool()).reservesAccrued();\n        uint cashForLPs = currentBalance > reserves ? currentBalance - reserves : 0;\n        require(underlyingAmount <= cashForLPs, "Insufficient liquidity (excl reserves)");\n\n\n        mToken.burn(user, mTokenAmount);\n\n\n        require(IERC20(asset).transfer(user, underlyingAmount), "Withdraw failed");\n\n        emit Withdrawn(user, underlyingAmount, mTokenAmount);\n    }\n\n    \n    function borrow(uint amount, address borrower) external onlyLendingPool {\n        require(amount > 0 && borrower != address(0), "Invalid borrow");\n\n        address asset = _getAsset();\n        uint currentBalance = IERC20(asset).balanceOf(address(this));\n        require(currentBalance >= amount, "Insufficient liquidity");\n\n\n        require(IERC20(asset).transfer(borrower, amount), "Borrow transfer failed");\n\n        emit Borrowed(borrower, amount);\n    }\n\n    \n    function repay(uint amount, address borrower) external onlyLendingPool {\n        require(amount > 0 && borrower != address(0), "Invalid repayment");\n\n        address asset = _getAsset();\n\n\n        require(IERC20(asset).transferFrom(borrower, address(this), amount), "Repay failed");\n\n        emit Repaid(borrower, amount);\n    }\n\n    \n    function transferReserve(uint reserveAmount, address feeCollector) external onlyLendingPool {\n        require(reserveAmount > 0 && feeCollector != address(0), "Invalid reserve transfer");\n\n        address asset = _getAsset();\n        uint currentBalance = IERC20(asset).balanceOf(address(this));\n        require(currentBalance >= reserveAmount, "Insufficient liquidity to transfer to reserve");\n\n\n        require(IERC20(asset).transfer(feeCollector, reserveAmount), "Reserve transfer failed");\n    }\n\n    \n    function setMToken(address _mToken) external onlyLendingPool {\n        require(_mToken != address(0), "Invalid mToken");\n        mToken = Token(_mToken);\n    }\n\n    \n    function setRegistry(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry address");\n        registry = LendingRegistry(_registry);\n    }\n}\n\n\n\n\n\n contract record PriceOracle is Ownable {\n\n    mapping(address => uint256) public record prices;\n    mapping(address => uint256) public record lastUpdated;\n\n\n    event PriceUpdated(address indexed asset, uint256 price, uint256 timestamp);\n    event BatchPricesUpdated(address[] assets, uint256[] priceValues, uint256 timestamp);\n\n    constructor(address _owner) Ownable(_owner) {}\n\n    \n    function _setAssetPrice(address asset, uint256 price) internal {\n        require(asset != address(0), "Invalid asset address");\n        require(price > 0, "Price must be greater than 0");\n\n        prices[asset] = price;\n        lastUpdated[asset] = block.timestamp;\n    }\n\n    \n    function setAssetPrice(address asset, uint256 price) external onlyOwner {\n        _setAssetPrice(asset, price);\n        emit PriceUpdated(asset, price, block.timestamp);\n    }\n\n    \n    function setAssetPrices(address[] calldata assets, uint256[] calldata priceValues) external onlyOwner {\n        require(assets.length == priceValues.length, "Arrays length mismatch");\n        require(assets.length > 0, "Empty arrays");\n\n        for (uint256 i = 0; i < assets.length; i++) {\n            _setAssetPrice(assets[i], priceValues[i]);\n        }\n\n        emit BatchPricesUpdated(assets, priceValues, block.timestamp);\n    }\n\n    \n    function getAssetPrice(address asset) external view returns (uint256) {\n        require(asset != address(0), "Invalid asset address");\n        uint256 price = prices[asset];\n        require(price > 0, "Price not available");\n        return price;\n    }\n\n    \n    function getAssetPriceWithTimestamp(address asset) external view returns (uint256 price, uint256 timestamp) {\n        require(asset != address(0), "Invalid asset address");\n        price = prices[asset];\n        require(price > 0, "Price not available");\n        timestamp = lastUpdated[asset];\n        return (price, timestamp);\n    }\n\n    \n    function isPriceFresh(address asset, uint256 maxAge) external view returns (bool) {\n        if (prices[asset] == 0) return false;\n        return (block.timestamp - lastUpdated[asset]) <= maxAge;\n    }\n}\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record SafetyModule is Ownable {\n\n    event Staked(address indexed user, uint assetsIn, uint sharesOut);\n    event UnstakeCooldown(address indexed user, uint start, uint end);\n    event Redeemed(address indexed user, uint sharesIn, uint assetsOut);\n    event RewardNotified(address indexed sender, uint amount);\n    event ShortfallCovered(uint amount);\n    event ParamsUpdated(uint cooldown, uint window, uint maxSlashBps);\n    event TokensUpdated(address _asset, address _sToken);\n    event TokenFactoryUpdated(address _tokenFactory);\n    event EndpointsSynced(address _lendingPool, address _liquidityPool, address newAsset);\n    event RegistryUpdated(address _lendingRegistry);\n\n\n    LendingRegistry public lendingRegistry;\n    LendingPool public  lendingPool;\n    LiquidityPool public liquidityPool;\n    TokenFactory public tokenFactory;\n    address public  asset;   \n    address public  sToken;  \n\n\n    uint public COOLDOWN_SECONDS = 259200;\n    uint public UNSTAKE_WINDOW  = 172800;\n    mapping(address => uint) public record cooldownStart; \n\n\n    uint public MAX_SLASH_BPS = 3000; \n\n\n    uint256 private _managedAssets;\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _lendingRegistry, address _tokenFactory) external onlyOwner {\n\n        COOLDOWN_SECONDS = 259200;\n        UNSTAKE_WINDOW = 172800;\n        MAX_SLASH_BPS = 3000;\n\n        require(_lendingRegistry != address(0)  && _tokenFactory != address(0), "SM:zero addr");\n        lendingRegistry = LendingRegistry(_lendingRegistry);\n        tokenFactory = TokenFactory(_tokenFactory);\n    }\n\n    modifier onlyActiveToken(address token) {\n        require(token != address(0) && tokenFactory.isTokenActive(token), "Invalid or inactive token");\n        _;\n    }\n\n\n\n\n    function setRegistry(address r) external onlyOwner {\n        require(r != address(0), "SM:reg=0");\n        lendingRegistry = LendingRegistry(r);\n        emit RegistryUpdated(r);\n    }\n\n    function setTokenFactory(address _tokenFactory) external onlyOwner {\n        require(_tokenFactory != address(0), "SM:reg=0");\n        tokenFactory = TokenFactory(_tokenFactory);\n        emit TokenFactoryUpdated(_tokenFactory);\n    }\n\n\n\n    function syncFromRegistry() external onlyOwner {\n        _syncFromRegistry();\n    }\n\n\n\n    function _syncFromRegistry() internal {\n        address _lendingPool = lendingRegistry.getLendingPool();\n        address _liquidityPool = lendingRegistry.getLiquidityPool();\n        require(_lendingPool != address(0) && _liquidityPool != address(0), "SM:bad registry addrs");\n\n\n        address newAsset = LendingPool(_lendingPool).borrowableAsset();\n        require(newAsset != address(0), "SM:asset=0");\n\n\n        if (address(asset) != address(0)) {\n            require(newAsset == address(asset), "SM:asset mismatch");\n        } else {\n            asset = newAsset;\n        }\n\n        lendingPool   = LendingPool(_lendingPool);\n        liquidityPool = LiquidityPool(_liquidityPool);\n\n        emit EndpointsSynced(_lendingPool, _liquidityPool, newAsset);\n    }\n\n\n\n\n\n    function totalAssets() public view returns (uint)\n    {\n        require(asset != address(0), "SM:asset not set");\n        return _managedAssets;\n    }\n\n\n    function totalShares() public view returns (uint)\n    {\n        require(sToken != address(0), "SM:sToken not set");\n        return IERC20(sToken).totalSupply();\n    }\n\n\n\n\n\n\n\n    function exchangeRate() public view returns (uint) {\n        uint s = totalShares();\n        if (s == 0) return 1e18;\n        return (totalAssets() * 1e18) / s;\n    }\n\n\n\n\n\n\n\n\n\n    function previewStake(uint assetsIn) external view returns (uint) {\n        require(assetsIn > 0, "SM:zero");\n        uint s = totalShares();\n        uint a = totalAssets();\n        if (s == 0) return assetsIn;           \n        require(a > 0, "SM:price=0");          \n        return (assetsIn * s) / a;             \n    }\n\n\n\n\n\n\n\n\n    function previewRedeem(uint sharesIn) external view returns (uint) {\n        require(sharesIn > 0, "SM:zero");\n        uint s = totalShares();\n        require(s > 0, "SM:no shares");\n        return (sharesIn * totalAssets()) / s;\n    }\n\n\n\n\n\n\n\n\n\n    function stake(uint assetsIn, uint minSharesOut) external onlyActiveToken(asset) onlyActiveToken(sToken) returns (uint sharesOut) {\n        require(assetsIn > 0, "SM:zero");\n        uint s = totalShares();\n        uint beforeBal = totalAssets();\n\n        if (s == 0) {\n            require(beforeBal == 0, "SM:init stray funds"); \n        } else {\n            require(beforeBal > 0, "SM:price=0");  \n        }\n\n        uint256 bal = IERC20(asset).balanceOf(address(this));\n        require(IERC20(asset).transferFrom(msg.sender, address(this), assetsIn), "SM: stake transfer failed");\n        uint256 delta = IERC20(asset).balanceOf(address(this)) - bal;\n        require(delta > 0, "SM:no delta");\n        _managedAssets += delta;\n\n        sharesOut = (s == 0) ? delta : (delta * s) / beforeBal;\n        require(sharesOut > 0, "SM:dust");\n        require(sharesOut >= minSharesOut, "SM:slippage");\n\n        Token(sToken).mint(msg.sender, sharesOut);\n\n\n        cooldownStart[msg.sender] = 0;\n\n        emit Staked(msg.sender, delta, sharesOut);\n    }\n\n\n\n    function startCooldown() external {\n        uint start = block.timestamp;\n        cooldownStart[msg.sender] = start;\n        emit UnstakeCooldown(msg.sender, start, start + COOLDOWN_SECONDS);\n    }\n\n\n\n    function redeem(uint sharesIn, uint minAssetsOut) external returns (uint assetsOut) {\n        require(sharesIn > 0, "SM:zero");\n        require(IERC20(sToken).balanceOf(msg.sender) >= sharesIn, "SM:not holder");\n\n        uint start = cooldownStart[msg.sender];\n        require(start > 0, "SM:no cooldown");\n        require(block.timestamp >= start + COOLDOWN_SECONDS, "SM:cooling");\n        require(block.timestamp <= start + COOLDOWN_SECONDS + UNSTAKE_WINDOW, "SM:window over");\n\n        uint a = totalAssets();\n        uint s = totalShares();\n        assetsOut = (sharesIn * a) / s;\n        require(assetsOut > 0, "SM:dust");\n        require(assetsOut >= minAssetsOut, "SM:slippage");\n\n\n        Token(sToken).burn(msg.sender, sharesIn);\n\n        uint256 bal = IERC20(asset).balanceOf(address(this));\n        require(IERC20(asset).transfer(msg.sender, assetsOut), "SM: redeem transfer failed");\n        uint256 delta = bal - IERC20(asset).balanceOf(address(this));\n        require(delta > 0, "SM:no delta");\n        _managedAssets -= delta;\n\n        if (IERC20(sToken).balanceOf(msg.sender) == 0) cooldownStart[msg.sender] = 0;\n\n        emit Redeemed(msg.sender, sharesIn, delta);\n    }\n\n\n\n\n\n    function notifyReward(uint amount) external onlyOwner {\n        require(amount > 0, "SM:zero");\n\n        uint256 bal = IERC20(asset).balanceOf(address(this));\n        require(IERC20(asset).transferFrom(msg.sender, address(this), amount), "SM: notifyReward transfer failed");\n        uint256 delta = IERC20(asset).balanceOf(address(this)) - bal;\n        require(delta > 0, "SM:no delta");\n        _managedAssets += delta;\n\n        emit RewardNotified(msg.sender, delta);\n    }\n\n\n\n\n\n    function recordTransfer(uint256 expectedAmount, uint256 balanceBefore) external {\n        require(msg.sender == address(lendingPool), "SM: only LendingPool");\n        require(expectedAmount > 0, "SM: zero amount");\n\n        uint256 balanceAfter = IERC20(asset).balanceOf(address(this));\n        uint256 actualReceived = balanceAfter - balanceBefore;\n\n\n        require(actualReceived == expectedAmount, "SM: unexpected balance change");\n\n        _managedAssets += actualReceived;\n\n        emit RewardNotified(msg.sender, actualReceived);\n    }\n\n\n\n\n\n    function coverShortfall(uint256 amount) external onlyOwner returns (uint256 covered) {\n        require(amount > 0, "SM:zero");\n\n\n        uint256 ta        = totalAssets();                         \n        uint256 bd        = lendingPool.badDebt();                 \n        require(bd > 0, "SM:no bad debt");\n\n        uint256 maxSlash  = (ta * MAX_SLASH_BPS) / 10000;\n\n\n        uint256 covered = amount;\n        if (covered > ta)        covered = ta;        \n        if (covered > maxSlash)  covered = maxSlash;  \n        if (covered > bd)        covered = bd;        \n\n        require(covered > 0, "SM:nothing to cover");\n\n\n        uint256 bal = IERC20(asset).balanceOf(address(this));\n        require(IERC20(asset).transfer(address(liquidityPool), covered), "SM: coverShortfall transfer failed");\n        uint256 delta = bal - IERC20(asset).balanceOf(address(this));\n        require(delta > 0, "SM:no delta");\n        _managedAssets -= delta;\n\n        lendingPool.coverShortfall(delta);\n\n        emit ShortfallCovered(delta);\n    }\n\n\n\n\n\n    function setParams(uint cooldown, uint window, uint maxSlashBps) external onlyOwner {\n        require(cooldown > 0 && window > 0, "SM:bad params");\n        require(maxSlashBps <= 10000, "SM:bad slash");\n        COOLDOWN_SECONDS = cooldown;\n        UNSTAKE_WINDOW = window;\n        MAX_SLASH_BPS = maxSlashBps;\n        emit ParamsUpdated(cooldown, window, maxSlashBps);\n    }\n\n\n\n    function setTokens(address _sToken, address _asset) external onlyOwner {\n        require(_sToken != address(0), "Invalid sToken address");\n        require(_asset != address(0), "Invalid underlyingAsset address");\n\n        require(LendingPool(address(lendingPool)).borrowableAsset() == _asset, "SM:asset mismatch");\n\n        require(_sToken != _asset, "SM:equal tokens");\n\n        sToken = _sToken;\n        asset = _asset;\n        emit TokensUpdated(_asset, _sToken);\n    }\n\n\n\n\n    function recoverStrayAssets(address to) external onlyOwner {\n        require(to != address(0), "SM:bad recipient");\n        uint256 stray = IERC20(asset).balanceOf(address(this)) - totalAssets();\n        require(stray > 0, "SM:no stray");\n        require(IERC20(asset).transfer(to, stray), "SM:transfer failed");\n    }\n\n\n    function rescueToken(address token, address to, uint amount) external onlyOwner {\n        require(token != address(asset), "SM:no USDST rescue");\n        require(IERC20(token).transfer(to, amount), "SM: rescue transfer failed");\n    }\n}\n\n\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record LendingPool is Ownable, Pausable {\n\n\n\n\n\n    event Deposited(address indexed user, address indexed asset, uint amount);\n    event DepositedOnBehalfOf(address indexed depositor, address indexed recipient, address indexed borrowableAsset, uint amount);\n    event Withdrawn(address indexed user, address indexed asset, uint amount);\n    event Borrowed(address indexed user, address indexed asset, uint amount);\n    event Repaid(address indexed user, address indexed asset, uint amount);\n    event Liquidated(address indexed borrower, address indexed asset, uint repaidAmount, address indexed collateralAsset, uint collateralSeized);\n    event SuppliedCollateral(address indexed user, address indexed asset, uint amount);\n    event WithdrawnCollateral(address indexed user, address indexed asset, uint amount);\n    event ExchangeRateUpdated(address indexed asset, uint newRate);\n    event AssetConfigured(address indexed asset, uint ltv, uint liquidationThreshold, uint liquidationBonus, uint interestRate, uint reserveFactor, uint perSecondFactorRAY);\n    event DebtCeilingsUpdated(uint assetUnits, uint usdValue);\n    event IndexAccrued(uint oldIndex, uint newIndex, uint dt, uint rateBps, uint interestDelta, uint reservesAccruedAfter);\n    event ReservesSweptTreasury(uint amount, address to);\n    event ReservesSweptSafety(uint amount, address to);\n    event BadDebtRecognized(uint amount);     \n    event BadDebtCovered(uint cover, uint remainingBadDebt);\n    event BadDebtWrittenOffFromReserves(uint writeOff, uint badDebt, uint reservesAccrued);\n    event DepositorHaircutApplied(uint writeOff, uint badDebt, string calldata reason);\n\n\n\n\n\n    struct LoanInfo {\n        uint scaledDebt;     \n        uint lastUpdated;    \n    }\n\n    struct AssetConfig {\n        uint ltv;                    \n        uint liquidationThreshold;   \n        uint liquidationBonus;       \n        uint interestRate;          \n        uint reserveFactor;         \n        uint perSecondFactorRAY;    \n    }\n\n\n\n\n\n\n    uint public RAY = 1e27;\n    uint public SECONDS_PER_YEAR = 31536000;\n\n    uint public borrowIndex;    \n    uint public lastAccrual;    \n    uint public totalScaledDebt; \n    uint public reservesAccrued; \n\n\n    uint public badDebt;                      \n\n\n    uint public debtCeilingAsset; \n    uint public debtCeilingUSD;   \n\n    uint  public safetyShareBps;      \n\n\n    mapping(address => LoanInfo) public record userLoan; \n\n\n    mapping(address => AssetConfig) public record assetConfigs;\n\n\n    address[] public record configuredAssets;\n\n\n    address public borrowableAsset; \n    address public mToken; \n\n\n    LendingRegistry public registry;\n    TokenFactory public tokenFactory;\n    address public poolConfigurator;\n    FeeCollector public feeCollector;\n    SafetyModule public safetyModule;\n\n\n\n\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _registry, address _poolConfigurator, address _tokenFactory, address _feeCollector, address _safetyModule) external onlyOwner {\n\n        RAY = 1e27;\n        SECONDS_PER_YEAR = 31536000;\n\n        require(_registry != address(0), "Invalid registry address");\n        registry = LendingRegistry(_registry);\n        require(_poolConfigurator != address(0), "Invalid pool configurator address");\n        poolConfigurator = _poolConfigurator;\n        tokenFactory = TokenFactory(_tokenFactory);\n        feeCollector = FeeCollector(_feeCollector);\n        safetyModule = SafetyModule(_safetyModule);\n        borrowIndex = RAY;\n        lastAccrual = uint(block.timestamp);\n    }\n\n    modifier onlyPoolConfigurator() {\n        require(msg.sender == address(poolConfigurator), "Caller is not PoolConfigurator");\n        _;\n    }\n\n    modifier onlyTokenFactory(address token) {\n        require(token != address(0) && tokenFactory.isTokenActive(token), "Invalid or inactive token");\n        _;\n    }\n\n    \n    function _requireNotPaused() internal view override {\n        require(!paused(), "This functionality has been paused and is currently not available");\n    }\n\n\n\n\n\n    function _liquidityPool() internal view returns (LiquidityPool) {\n        return registry.liquidityPool();\n    }\n\n    function _collateralVault() internal view returns (CollateralVault) {\n        return registry.collateralVault();\n    }\n\n    function _priceOracle() internal view returns (PriceOracle) {\n        return registry.priceOracle();\n    }\n\n\n\n\n\n\n    function rpow(uint x, uint n, uint b) internal pure returns (uint z) {\n        z = b;\n        if (n == 0) return z;\n        uint y = x;\n        while (n > 0) {\n            if (n % 2 == 1) {\n\n                z = (z * y) / b;\n            }\n            n /= 2;\n            if (n > 0) {\n\n                y = (y * y) / b;\n            }\n        }\n        return z;\n    }\n\n\n\n\n\n    function pause() external onlyOwner {\n        _pause();\n    }\n\n    function unpause() external onlyOwner {\n        _unpause();\n    }\n\n\n\n\n\n    \n    function depositLiquidity(uint amount) external onlyTokenFactory(borrowableAsset) {\n        require(amount > 0, "Invalid amount");\n        require(mToken != address(0), "mToken not set");\n\n\n        _accrue();\n\n\n        uint exchangeRate = getExchangeRate();\n        require(exchangeRate > 0, "Invalid rate");\n        uint mTokenAmount = (amount * 1e18) / exchangeRate;\n        require(mTokenAmount > 0, "Mint calc");\n\n\n        LiquidityPool(_liquidityPool()).deposit(amount, mTokenAmount, msg.sender);\n\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Deposited(msg.sender, borrowableAsset, amount);\n    }\n\n    \n    function depositLiquidityOnBehalfOf(address user, uint amount) external onlyTokenFactory(borrowableAsset) {\n        require(mToken != address(0), "mToken not set");\n        require(amount > 0, "Invalid amount");\n        require(user != address(0), "Invalid user address");\n        require(user != msg.sender, "Please call depositLiquidity instead");\n\n\n        _accrue();\n\n\n        uint exchangeRate = getExchangeRate();\n        require(exchangeRate > 0, "Invalid rate");\n        uint mTokenAmount = (amount * 1e18) / exchangeRate;\n        require(mTokenAmount > 0, "Mint calc");\n\n\n        LiquidityPool(_liquidityPool()).depositOnBehalfOf(user, amount, mTokenAmount, msg.sender);\n\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit DepositedOnBehalfOf(msg.sender, user, borrowableAsset, amount);\n        emit Deposited(user, borrowableAsset, amount); \n    }\n\n    \n    function withdrawLiquidity(uint amount) external whenNotPaused onlyTokenFactory(borrowableAsset) {\n        require(amount > 0, "Invalid amount");\n        require(mToken != address(0), "mToken not set");\n\n        _accrue(); \n\n\n        uint exchangeRate = getExchangeRate();\n\n        uint mTokensToBurn = (amount * 1e18 + exchangeRate - 1) / exchangeRate;\n\n        require(IERC20(mToken).balanceOf(msg.sender) >= mTokensToBurn, "Insufficient mToken balance");\n\n\n        LiquidityPool(_liquidityPool()).withdraw(mTokensToBurn, msg.sender, amount);\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Withdrawn(msg.sender, borrowableAsset, amount);\n    }\n\n\n\n\n\n    \n    function supplyCollateral(address asset, uint amount) external onlyTokenFactory(asset) {\n        require(amount > 0, "Invalid amount");\n\n\n        AssetConfig memory config = assetConfigs[asset];\n        require(config.ltv > 0, "Asset not configured as collateral");\n        require(config.liquidationThreshold > 0, "Asset missing liquidation threshold");\n        require(config.liquidationBonus >= 10000, "Asset missing liquidation bonus");\n\n\n\n        CollateralVault(_collateralVault()).addCollateral(msg.sender, asset, amount);\n\n        emit SuppliedCollateral(msg.sender, asset, amount);\n    }\n\n    \n    function withdrawCollateral(address asset, uint amount) external whenNotPaused onlyTokenFactory(asset) {\n        require(amount > 0, "Invalid amount");\n\n        uint totalCollateral = CollateralVault(_collateralVault()).userCollaterals(msg.sender, asset);\n        require(totalCollateral >= amount, "Insufficient collateral");\n\n        _accrue(); \n\n\n        uint currentBorrow = getUserDebt(msg.sender); \n        uint newMaxBorrow = calculateMaxBorrowingPower(msg.sender, asset, amount); \n        require(currentBorrow <= newMaxBorrow, "Withdrawal would exceed existing loan");\n\n        CollateralVault(_collateralVault()).removeCollateral(msg.sender, asset, amount);\n\n        emit WithdrawnCollateral(msg.sender, asset, amount);\n    }\n\n\n\n\n\n    \n    function borrow(uint amount) external whenNotPaused onlyTokenFactory(borrowableAsset) {\n        require(amount > 0, "Invalid amount");\n\n\n        _accrue();\n        _checkDebtLimits(amount);\n\n\n        uint maxBorrowAmount = calculateMaxBorrowingPower(msg.sender, address(0), 0);\n        uint currentOwed = getUserDebt(msg.sender); \n        require(currentOwed + amount <= maxBorrowAmount, "Insufficient collateral for borrow");\n\n\n        LoanInfo storage loan = userLoan[msg.sender];\n        uint scaledAdd = (amount * RAY + borrowIndex - 1) / borrowIndex;\n        require(scaledAdd > 0, "Insufficient loan amount");\n        loan.scaledDebt += scaledAdd;\n        loan.lastUpdated = block.timestamp;\n        totalScaledDebt += scaledAdd;\n\n\n        LiquidityPool(_liquidityPool()).borrow(amount, msg.sender);\n\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Borrowed(msg.sender, borrowableAsset, amount);\n    }\n\n\n\n\n\n    \n    function repay(uint amount) external onlyTokenFactory(borrowableAsset) {\n        LoanInfo storage loan = userLoan[msg.sender];\n        require(loan.scaledDebt > 0, "No active loan");\n        require(amount > 0, "Invalid repayment");\n\n\n        _accrue();\n\n\n        uint owed = (loan.scaledDebt * borrowIndex) / RAY;\n        require(owed > 0, "Nothing to repay");\n\n\n        uint repayAmount = amount > owed ? owed : amount;\n\n\n        uint scaledDelta = (repayAmount * RAY) / borrowIndex;\n\n\n        if (repayAmount < owed) {\n            require(scaledDelta > 0, "Insufficient repayment amount");\n        }\n\n\n        LiquidityPool(_liquidityPool()).repay(repayAmount, msg.sender);\n\n\n        if (scaledDelta > loan.scaledDebt) scaledDelta = loan.scaledDebt; \n\n        loan.scaledDebt -= scaledDelta;\n        totalScaledDebt -= scaledDelta;\n\n\n        uint owedAfter = (loan.scaledDebt * borrowIndex) / RAY;\n        if (owedAfter <= 1) {\n            if (loan.scaledDebt > 0) {\n                totalScaledDebt -= loan.scaledDebt;\n                loan.scaledDebt = 0;\n            }\n            delete userLoan[msg.sender].scaledDebt;\n            delete userLoan[msg.sender].lastUpdated;\n        } else {\n            loan.lastUpdated = block.timestamp;\n        }\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Repaid(msg.sender, borrowableAsset, repayAmount);\n    }\n\n    \n    function borrowMax() external whenNotPaused onlyTokenFactory(borrowableAsset) returns (uint amountBorrowed) {\n\n        _accrue();\n\n        uint maxBorrowAmount = calculateMaxBorrowingPower(msg.sender, address(0), 0);\n        uint currentOwed = getUserDebt(msg.sender);\n        require(maxBorrowAmount > currentOwed, "No borrowing power");\n\n        uint available = maxBorrowAmount - currentOwed;\n\n        amountBorrowed = available > 1 ? (available - 1) : 0;\n        require(amountBorrowed > 0, "No borrowing power");\n\n        _checkDebtLimits(amountBorrowed);\n\n\n        LoanInfo storage loan = userLoan[msg.sender];\n        uint scaledAdd = (amountBorrowed * RAY + borrowIndex - 1) / borrowIndex;\n        require(scaledAdd > 0, "Insufficient loan amount");\n        loan.scaledDebt += scaledAdd;\n        loan.lastUpdated = block.timestamp;\n        totalScaledDebt += scaledAdd;\n\n\n        LiquidityPool(_liquidityPool()).borrow(amountBorrowed, msg.sender);\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Borrowed(msg.sender, borrowableAsset, amountBorrowed);\n        return amountBorrowed;\n    }\n\n    \n    function repayAll() external onlyTokenFactory(borrowableAsset) returns (uint amountRepaid) {\n        LoanInfo storage loan = userLoan[msg.sender];\n        require(loan.scaledDebt > 0, "No active loan");\n\n        _accrue();\n\n        uint owed = (loan.scaledDebt * borrowIndex) / RAY;\n        require(owed > 0, "Nothing to repay");\n\n\n        LiquidityPool(_liquidityPool()).repay(owed, msg.sender);\n        amountRepaid = owed;\n\n\n        uint scaledDelta = (amountRepaid * RAY) / borrowIndex;\n        if (scaledDelta > loan.scaledDebt) {\n            scaledDelta = loan.scaledDebt;\n        } else if (scaledDelta < loan.scaledDebt) {\n\n            uint remaining = loan.scaledDebt - scaledDelta;\n            scaledDelta += remaining;\n        }\n        loan.scaledDebt -= scaledDelta; \n        totalScaledDebt -= scaledDelta;\n\n        if (loan.scaledDebt == 0) {\n            delete userLoan[msg.sender].scaledDebt;\n            delete userLoan[msg.sender].lastUpdated;\n        } else {\n            loan.lastUpdated = block.timestamp;\n        }\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Repaid(msg.sender, borrowableAsset, amountRepaid);\n        return amountRepaid;\n    }\n\n    \n    function withdrawLiquidityAll() external whenNotPaused onlyTokenFactory(borrowableAsset) {\n        _accrue();\n        require(mToken != address(0), "mToken not set");\n        uint userShares = IERC20(mToken).balanceOf(msg.sender);\n        require(userShares > 0, "No mTokens to withdraw");\n\n\n        uint exchangeRate = getExchangeRate();\n        uint underlyingAmount = (userShares * exchangeRate) / 1e18;\n\n\n        address asset = borrowableAsset;\n        uint poolCash = IERC20(asset).balanceOf(address(_liquidityPool()));\n        require(poolCash >= underlyingAmount, "Insufficient liquidity");\n\n        LiquidityPool(_liquidityPool()).withdraw(userShares, msg.sender, underlyingAmount);\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n    }\n\n    \n    function withdrawCollateralMax(address asset) external whenNotPaused onlyTokenFactory(asset) returns (uint amountWithdrawn) {\n\n         uint totalCollateral = CollateralVault(_collateralVault()).userCollaterals(msg.sender, asset);\n         require(totalCollateral > 0, "No collateral");\n\n         _accrue();\n\n\n         uint maxBorrowAmount = calculateMaxBorrowingPower(msg.sender, address(0), 0);\n         uint currentOwed = getUserDebt(msg.sender);\n\n\n         if (currentOwed == 0) {\n             CollateralVault(_collateralVault()).removeCollateral(msg.sender, asset, totalCollateral);\n             emit WithdrawnCollateral(msg.sender, asset, totalCollateral);\n             return totalCollateral;\n         }\n         require(maxBorrowAmount > currentOwed, "No room");\n\n\n         (uint priceAsset, uint timestampAsset) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(asset); \n         (uint priceBorrow, uint timestampBorrow) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset); \n         uint ltv = assetConfigs[asset].ltv; \n         require(priceAsset > 0 && priceBorrow > 0 && ltv > 0, "Config");\n\n\n         uint roomBorrow = maxBorrowAmount - currentOwed;\n\n\n\n\n         uint numerator = roomBorrow * priceBorrow * 10000;\n         uint denom = priceAsset * ltv;\n         if (denom == 0) {\n             return 0;\n         }\n         uint maxByHealth = numerator / denom;\n\n\n         amountWithdrawn = maxByHealth < totalCollateral ? maxByHealth : totalCollateral;\n\n         if (amountWithdrawn > 1) {\n             amountWithdrawn = amountWithdrawn - 1;\n         }\n         require(amountWithdrawn > 0, "No withdrawable amount");\n\n\n         uint newMaxBorrow = calculateMaxBorrowingPower(msg.sender, asset, amountWithdrawn);\n         require(currentOwed <= newMaxBorrow, "Withdrawal would exceed existing loan");\n\n         CollateralVault(_collateralVault()).removeCollateral(msg.sender, asset, amountWithdrawn);\n         emit WithdrawnCollateral(msg.sender, asset, amountWithdrawn);\n         return amountWithdrawn;\n     }\n\n\n\n\n\n    \n    function liquidationCall(\n        address collateralAsset,\n        address borrower,\n        uint debtToCover,\n        uint minCollateralOut\n    ) public whenNotPaused onlyTokenFactory(borrowableAsset) {\n        require(collateralAsset != address(0), "Invalid collateral asset");\n        require(borrower != address(0) && borrower != msg.sender, "Invalid borrower");\n        require(debtToCover > 0, "Invalid debt amount");\n\n\n        AssetConfig memory cConfig = assetConfigs[collateralAsset];\n        require(cConfig.liquidationBonus >= 10000, "Asset not eligible for liquidation");\n\n\n        _accrue();\n\n        uint totalOwed = getUserDebt(borrower);\n        require(totalOwed > 0, "Borrower has no debt");\n\n        uint health = getHealthFactor(borrower); \n        require(health < 1e18, "Position healthy");\n\n\n        uint maxRepay = (health < 95e16) ? totalOwed : (totalOwed / 2);\n        require(debtToCover <= maxRepay, "Repay amount exceeds allowed limit");\n\n\n        (uint priceDebt, uint timestampDebt) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset); \n        (uint priceColl, uint timestampColl) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(collateralAsset);\n        require(priceDebt > 0 && priceColl > 0, "Invalid oracle price");\n\n        uint collateralToSeize = (debtToCover * priceDebt * cConfig.liquidationBonus) / (priceColl * 10000);\n\n\n\n        uint borrowerCollateral = CollateralVault(_collateralVault()).userCollaterals(borrower, collateralAsset);\n        if (collateralToSeize > borrowerCollateral) {\n            collateralToSeize = borrowerCollateral; \n        }\n\n\n        require(collateralToSeize > 0, "There is no collateral to seize");\n        require(collateralToSeize >= minCollateralOut, "Remaining collateral is less than minimum requested by user");\n\n\n        LoanInfo storage loan = userLoan[borrower];\n        uint scaledDelta = (debtToCover * RAY) / borrowIndex;\n        require(scaledDelta > 0, "Insufficient repayment amount");\n\n\n        LiquidityPool(_liquidityPool()).repay(debtToCover, msg.sender);\n\n\n        if (scaledDelta > loan.scaledDebt) scaledDelta = loan.scaledDebt; \n        loan.scaledDebt -= scaledDelta;\n        totalScaledDebt -= scaledDelta;\n\n\n        uint owedAfterL = (loan.scaledDebt * borrowIndex) / RAY;\n        if (owedAfterL <= 1) {\n            if (loan.scaledDebt > 0) {\n                totalScaledDebt -= loan.scaledDebt;\n                loan.scaledDebt = 0;\n            }\n            delete userLoan[borrower].scaledDebt;\n            delete userLoan[borrower].lastUpdated;\n        } else {\n            loan.lastUpdated = block.timestamp;\n        }\n\n\n        CollateralVault(_collateralVault()).seizeCollateral(borrower, msg.sender, collateralAsset, collateralToSeize);\n\n\n        if (_getTotalCollateralValueForHealth(borrower) == 0) {\n            LoanInfo storage ln = userLoan[borrower];\n            uint scaled = ln.scaledDebt;\n            if (scaled > 0) {\n                uint baseBad = (scaled * borrowIndex) / RAY; \n\n\n                totalScaledDebt -= scaled;\n\n\n                ln.scaledDebt = 0;\n                delete userLoan[borrower].scaledDebt;\n                delete userLoan[borrower].lastUpdated;\n\n\n                badDebt += baseBad;\n\n                emit BadDebtRecognized(baseBad);\n            }\n        }\n\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n        emit Liquidated(borrower, borrowableAsset, debtToCover, collateralAsset, collateralToSeize);\n    }\n\n    \n    function liquidationCallAll(\n        address collateralAsset,\n        address borrower,\n        uint minCollateralOut\n    ) external whenNotPaused onlyTokenFactory(borrowableAsset) {\n        require(collateralAsset != address(0), "Invalid collateral asset");\n        require(borrower != address(0) && borrower != msg.sender, "Invalid borrower");\n\n\n        AssetConfig memory cConfig = assetConfigs[collateralAsset];\n        require(cConfig.liquidationBonus >= 10000, "Asset not eligible for liquidation");\n\n\n        _accrue();\n        uint totalOwed = getUserDebt(borrower);\n        require(totalOwed > 0, "Borrower has no debt");\n        uint health = getHealthFactor(borrower);\n        require(health < 1e18, "Position healthy");\n\n\n        uint maxRepay = (health < 95e16) ? totalOwed : (totalOwed / 2);\n\n\n        (uint priceDebt, uint timestampDebt) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset);\n        (uint priceColl, uint timestampColl) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(collateralAsset);\n        require(priceDebt > 0 && priceColl > 0, "Invalid oracle price");\n        uint borrowerCollateral = CollateralVault(_collateralVault()).userCollaterals(borrower, collateralAsset);\n        uint num = borrowerCollateral * priceColl * 10000;\n        uint den = priceDebt * cConfig.liquidationBonus;\n        uint coverage = (num + den - 1) / den; \n\n        uint debtToCover = totalOwed;\n        if (debtToCover > maxRepay) debtToCover = maxRepay;\n        if (debtToCover > coverage) debtToCover = coverage;\n        require(debtToCover > 0, "Nothing liquidatable");\n\n        liquidationCall(collateralAsset, borrower, debtToCover, minCollateralOut);\n    }\n\n\n\n\n\n    \n    function getUserLoan(address user) external view returns (LoanInfo memory loan) {\n        return userLoan[user];\n    }\n\n\n    function getUserDebt(address user) public view returns (uint debt) {\n        LoanInfo memory loan = userLoan[user];\n        if (loan.scaledDebt == 0) return 0;\n        return (loan.scaledDebt * borrowIndex) / RAY;\n    }\n\n\n\n\n\n    \n    function getHealthFactor(address user) public view returns (uint) {\n        uint totalCollateralValue = _getTotalCollateralValueForHealth(user);\n        uint totalBorrowValue = _getTotalBorrowValue(user);\n\n        if (totalBorrowValue == 0) return 2**256 - 1; \n        if (totalCollateralValue == 0) return 0; \n\n\n        return (totalCollateralValue * 1e18) / totalBorrowValue;\n    }\n\n\n\n\n\n    \n    function configureAsset(\n        address asset,\n        uint ltv,\n        uint liquidationThreshold,\n        uint liquidationBonus,\n        uint interestRate,\n        uint reserveFactor,\n        uint perSecondFactorRAY\n    ) external onlyPoolConfigurator {\n        require(asset != address(0) && tokenFactory.isTokenActive(asset), "Invalid or inactive asset");\n        require(ltv <= liquidationThreshold, "LTV must be <= liquidation threshold");\n        require(liquidationThreshold <= 9500, "Liquidation threshold too high"); \n        require(liquidationBonus >= 10000 && liquidationBonus <= 12500, "Invalid liquidation bonus"); \n        require(interestRate <= 10000, "Interest rate too high"); \n        require(reserveFactor <= 5000, "Reserve factor too high"); \n        require(perSecondFactorRAY >= RAY, "Invalid per-second factor");\n\n        bool isBorrowAsset = (asset == borrowableAsset);\n        bool canAccrue =\n            isBorrowAsset &&\n            assetConfigs[asset].perSecondFactorRAY > 0 &&\n            borrowIndex != 0 &&\n            lastAccrual != 0;\n\n        if (canAccrue) {\n            _accrue();\n        }\n\n\n        if (assetConfigs[asset].ltv == 0 && assetConfigs[asset].liquidationThreshold == 0) {\n            configuredAssets.push(asset);\n        }\n\n        assetConfigs[asset] = AssetConfig(\n            ltv,\n            liquidationThreshold,\n            liquidationBonus,\n            interestRate,\n            reserveFactor,\n            perSecondFactorRAY\n        );\n\n        emit AssetConfigured(asset, ltv, liquidationThreshold, liquidationBonus, interestRate, reserveFactor, perSecondFactorRAY);\n    }\n\n\n    \n    function getAssetConfig(address asset) external view returns (uint, uint, uint, uint, uint, uint) {\n        AssetConfig memory config = assetConfigs[asset];\n        return (config.ltv, config.liquidationThreshold, config.liquidationBonus, config.interestRate, config.reserveFactor, config.perSecondFactorRAY);\n    }\n\n\n\n\n\n    \n    function getExchangeRate() public view returns (uint) {\n        if (mToken == address(0)) return 1e18;\n\n        uint totalSupply_ = IERC20(mToken).totalSupply();\n        if (totalSupply_ == 0) {\n            return 1e18; \n        }\n\n        uint cash = IERC20(borrowableAsset).balanceOf(address(_liquidityPool()));\n        uint debt = _totalDebt(); \n\n\n        uint underlying = cash + debt + badDebt;  \n        if (reservesAccrued < underlying) {\n            underlying -= reservesAccrued;\n        } else {\n\n            underlying = cash;\n        }\n\n        if (underlying == 0) {\n            return 1e18; \n        }\n\n        return (underlying * 1e18) / totalSupply_;\n    }\n\n\n\n\n\n\n    function _totalDebt() internal view returns (uint) {\n        return (totalScaledDebt * borrowIndex) / RAY;\n    }\n\n\n    function _currentAprBps() internal view returns (uint) {\n        return assetConfigs[borrowableAsset].interestRate;\n    }\n\n\n    function _accrue() internal {\n        uint ts = uint(block.timestamp);\n        uint last = lastAccrual;\n        if (ts == last) return;\n\n        uint idx0 = borrowIndex;\n        uint dt = uint(ts - last);\n\n        uint perSec = assetConfigs[borrowableAsset].perSecondFactorRAY;\n        require(perSec > 0, "Compound factor not set");\n        uint idx1 = (idx0 * rpow(perSec, dt, RAY)) / RAY;\n        borrowIndex = idx1;\n        lastAccrual = ts;\n\n        uint rateBps = assetConfigs[borrowableAsset].interestRate;\n\n        if (totalScaledDebt > 0) {\n            uint interestDelta = (totalScaledDebt * (idx1 - idx0)) / RAY;\n            uint rf = assetConfigs[borrowableAsset].reserveFactor; \n            if (rf > 0 && interestDelta > 0) {\n                reservesAccrued += (interestDelta * rf) / 10000;\n            }\n            emit IndexAccrued(idx0, idx1, dt, rateBps, interestDelta, reservesAccrued);\n        }\n    }\n\n\n    function _checkDebtLimits(uint addAmount) internal view {\n        uint newDebt = _totalDebt() + addAmount;\n\n        if (debtCeilingAsset > 0) {\n            require(newDebt <= debtCeilingAsset, "Debt ceiling (asset) exceeded");\n        }\n        if (debtCeilingUSD > 0) {\n            (uint p, uint timestamp) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset); \n            require(p > 0, "No oracle price");\n            uint newUsd = (newDebt * p) / 1e18;\n            require(newUsd <= debtCeilingUSD, "Debt ceiling (USD) exceeded");\n        }\n    }\n\n\n\n\n\n    function setTokenFactory(address _tokenFactory) external onlyPoolConfigurator {\n        tokenFactory = TokenFactory(_tokenFactory);\n    }\n\n    function setFeeCollector(address _feeCollector) external onlyPoolConfigurator {\n        feeCollector = FeeCollector(_feeCollector);\n    }\n\n    function setSafetyModule(address _safetyModule) external onlyPoolConfigurator {\n        safetyModule = SafetyModule(_safetyModule);\n    }\n\n    \n    function setBorrowableAsset(address _asset) external onlyPoolConfigurator {\n        require(_asset != address(0) && tokenFactory.isTokenActive(_asset), "Invalid or inactive asset");\n        borrowableAsset = _asset;\n    }\n    \n    function setMToken(address _mToken) external onlyPoolConfigurator {\n        require(_mToken != address(0) && tokenFactory.isTokenActive(_mToken), "Invalid or inactive mToken");\n        mToken = _mToken;\n\n        LiquidityPool(_liquidityPool()).setMToken(_mToken);\n    }\n\n\n    function setRegistry(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry address");\n        registry = LendingRegistry(_registry);\n    }\n\n\n    function setDebtCeilings(uint assetUnits, uint usdValue) external onlyPoolConfigurator {\n        debtCeilingAsset = assetUnits;\n        debtCeilingUSD = usdValue;\n        emit DebtCeilingsUpdated(assetUnits, usdValue);\n    }\n\n\n     function setSafetyShareBps(uint bps) external onlyPoolConfigurator {\n        require(bps <= 10000, "LP:bad bps");\n        safetyShareBps = bps;\n    }\n\n\n    function sweepReserves(uint amount) external onlyPoolConfigurator {\n        if (amount == 0 || reservesAccrued == 0) return;\n        _accrue();\n\n        uint cash = IERC20(borrowableAsset).balanceOf(address(_liquidityPool()));\n        uint toSend = amount;\n        if (toSend > reservesAccrued) toSend = reservesAccrued;\n        if (toSend > cash) toSend = cash;\n        if (toSend == 0) return;\n\n        uint toSafety = (toSend * safetyShareBps) / 10000;\n        uint toTreas  = toSend - toSafety;\n\n\n        if (toSafety > 0 && address(safetyModule) != address(0)) {\n            uint256 smBalBefore = IERC20(borrowableAsset).balanceOf(address(safetyModule));\n\n            LiquidityPool(_liquidityPool()).transferReserve(toSafety, address(safetyModule));\n\n\n            safetyModule.recordTransfer(toSafety, smBalBefore);\n        }\n\n\n        if (toTreas > 0 && address(feeCollector) != address(0)) {\n            LiquidityPool(_liquidityPool()).transferReserve(toTreas, address(feeCollector));\n        }\n\n        reservesAccrued -= toSend;\n\n        emit ReservesSweptSafety(toSafety, address(safetyModule));\n        emit ReservesSweptTreasury(toTreas, address(feeCollector));\n    }\n\n\n\n\n\n\n    function _getTotalCollateralValueForHealth(address user) internal view returns (uint) {\n        uint totalValue = 0;\n        CollateralVault vault = _collateralVault();\n        PriceOracle oracle = _priceOracle();\n      for (uint i = 0; i < configuredAssets.length; i++) {\n            address asset = configuredAssets[i];\n            uint collateralAmount = vault.userCollaterals(user, asset);\n            if (collateralAmount == 0) continue;\n\n            (uint price, uint timestamp) = oracle.getAssetPriceWithTimestamp(asset);\n            uint liqThreshold = assetConfigs[asset].liquidationThreshold;\n            if (price == 0 || liqThreshold == 0) continue;\n\n            totalValue += (collateralAmount * price * liqThreshold) / (1e18 * 10000);\n        }\n        return totalValue;\n    }\n\n    \n    function _getTotalBorrowValue(address user) internal view returns (uint) {\n        uint debt = getUserDebt(user); \n        if (debt == 0) return 0;\n\n        (uint price, uint timestamp) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset); \n        if (price == 0) return 0;\n\n\n        return (debt * price) / 1e18;\n    }\n\n    \n    function calculateMaxBorrowingPower(address user, address excludeAsset, uint excludeAmount) public view returns (uint) {\n        uint totalCollateralValue = 0;\n\n\n        for (uint i = 0; i < configuredAssets.length; i++) {\n            address asset = configuredAssets[i];\n            uint ltv = assetConfigs[asset].ltv;\n\n\n            if (ltv > 0) {\n                uint collateralAmount = CollateralVault(_collateralVault()).userCollaterals(user, asset);\n\n\n                if (asset == excludeAsset) {\n                    if (collateralAmount >= excludeAmount) {\n                        collateralAmount = collateralAmount - excludeAmount;\n                    } else {\n                        collateralAmount = 0;\n                    }\n                }\n\n                if (collateralAmount > 0) {\n                    (uint price, uint timestamp) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(asset);\n\n                    if (price > 0) {\n\n                        uint assetBorrowableValue = (collateralAmount * price * ltv) / (1e18 * 10000);\n                        totalCollateralValue += assetBorrowableValue;\n                    }\n                }\n            }\n        }\n\n\n        (uint borrowableAssetPrice, uint timestamp) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset);\n        if (borrowableAssetPrice == 0) {\n            return 0;\n        }\n\n        return (totalCollateralValue * 1e18) / borrowableAssetPrice;\n    }\n\n\n\n\n\n    \n    function previewBorrowIndex() public view returns (uint projectedIndex) {\n        if (block.timestamp == lastAccrual) return borrowIndex;\n        uint dt = uint(block.timestamp - lastAccrual);\n        uint perSec = assetConfigs[borrowableAsset].perSecondFactorRAY;\n        require(perSec > 0, "Compound factor not set");\n        uint mul = rpow(perSec, dt, RAY);\n        return (borrowIndex * mul) / RAY;\n    }\n\n    \n    function getUserDebtPreview(address user) public view returns (uint debtPreview) {\n        uint idx = previewBorrowIndex();\n        return (userLoan[user].scaledDebt * idx) / RAY;\n    }\n\n    \n    function getTotalBorrowValuePreview(address user) public view returns (uint usdValuePreview) {\n        uint debt = getUserDebtPreview(user);\n        if (debt == 0) return 0;\n        (uint price, uint timestamp) = PriceOracle(_priceOracle()).getAssetPriceWithTimestamp(borrowableAsset); \n        if (price == 0) return 0;\n        return (debt * price) / 1e18;\n    }\n\n\n\n\n\n    \n    function recognizeBadDebt(address borrower) external onlyPoolConfigurator {\n        _accrue();\n        if (_getTotalCollateralValueForHealth(borrower) > 0) return;\n\n        LoanInfo storage ln = userLoan[borrower];\n        uint scaled = ln.scaledDebt;\n        if (scaled == 0) return;\n\n        uint baseBad = (scaled * borrowIndex) / RAY;\n\n\n        totalScaledDebt -= scaled;\n        ln.scaledDebt = 0;\n        delete userLoan[borrower].scaledDebt;\n        delete userLoan[borrower].lastUpdated;\n\n\n        badDebt += baseBad;\n\n\n        CollateralVault vault = _collateralVault();\n        require (address(feeCollector) != address(0), "LP: Fee collector not set");\n        uint n = configuredAssets.length;\n        for (uint i = 0; i < n; i++) {\n            address collateral = configuredAssets[i];\n            uint amt = vault.userCollaterals(borrower, collateral);\n            if (amt != 0) {\n                vault.seizeCollateral(borrower, address(feeCollector), collateral, amt); \n            }\n        }\n\n        emit BadDebtRecognized(baseBad);\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n    }\n\n    function coverShortfall(uint amount) external {\n        require(msg.sender == address(safetyModule), "LP:not SM");\n        require(amount > 0, "LP:zero");\n\n\n        uint cover = amount <= badDebt ? amount : badDebt;\n        if (cover > 0) {\n            badDebt -= cover;\n            emit BadDebtCovered(cover, badDebt);\n        }\n\n\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n    }\n\n    function writeOffBadDebtFromReserves(uint amount) external onlyPoolConfigurator {\n        if (amount == 0) return;\n        _accrue();\n\n\n        uint cap = reservesAccrued < badDebt ? reservesAccrued : badDebt;\n        if (cap == 0) return;\n\n\n        uint writeOff = amount <= cap ? amount : cap;\n\n        reservesAccrued -= writeOff;\n        badDebt        -= writeOff;\n\n        emit BadDebtWrittenOffFromReserves(writeOff, badDebt, reservesAccrued);\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n    }\n\n\n\n\n    function writeOffBadDebtWithHaircut(uint amount, string calldata reason) external onlyPoolConfigurator\n    {\n        require(amount > 0, "LP:zero");\n        _accrue();\n\n        uint writeOff = amount <= badDebt ? amount : badDebt;\n        if (writeOff == 0) return;\n\n        badDebt -= writeOff;\n\n        emit DepositorHaircutApplied(writeOff, badDebt, reason);\n        emit ExchangeRateUpdated(borrowableAsset, getExchangeRate());\n    }\n}\n\n\n\n\n contract record RateStrategy {\n    constructor()  {\n    }\n\n    function calculateInterest(uint principal, uint rate, uint lastUpdated) pure  returns (uint) {\n        if (block.timestamp <= lastUpdated) return 0;\n        uint durationSeconds = block.timestamp - lastUpdated;\n        uint hoursElapsed = durationSeconds / 3600; \n        if (hoursElapsed == 0) return 0;\n\n        return (principal * rate * hoursElapsed) / (8760 * 10000);\n    }\n}\n\n\n\n\n\n\n\n\n\n\ncontract record LendingRegistry is Ownable {\n\n    LendingPool public lendingPool;\n    LiquidityPool public liquidityPool;\n    CollateralVault public collateralVault;\n    RateStrategy public rateStrategy;\n    PriceOracle public priceOracle;\n\n    event ComponentsUpdated(\n        address indexed lendingPool,\n        address indexed liquidityPool,\n        address indexed collateralVault,\n        address rateStrategy,\n        address priceOracle\n    );\n\n    constructor(address initialOwner) Ownable(initialOwner) {}\n\n    \n    function setAllComponents(\n        address _lendingPool,\n        address _liquidityPool,\n        address _collateralVault,\n        address _rateStrategy,\n        address _priceOracle\n    ) external onlyOwner {\n\n        require(_lendingPool != address(0), "Invalid lendingPool address");\n        require(_liquidityPool != address(0), "Invalid liquidityPool address");\n        require(_collateralVault != address(0), "Invalid collateralVault address");\n        require(_rateStrategy != address(0), "Invalid rateStrategy address");\n        require(_priceOracle != address(0), "Invalid priceOracle address");\n\n        lendingPool = LendingPool(_lendingPool);\n        liquidityPool = LiquidityPool(_liquidityPool);\n        collateralVault = CollateralVault(_collateralVault);\n        rateStrategy = RateStrategy(_rateStrategy);\n        priceOracle = PriceOracle(_priceOracle);\n\n        emit ComponentsUpdated(_lendingPool, _liquidityPool, _collateralVault, _rateStrategy, _priceOracle);\n    }\n\n    \n    function setLendingPool(address _lendingPool) external onlyOwner {\n        require(_lendingPool != address(0), "Invalid address");\n        lendingPool = LendingPool(_lendingPool);\n        emit ComponentsUpdated(address(lendingPool), address(liquidityPool), address(collateralVault), address(rateStrategy), address(priceOracle));\n    }\n\n    function setLiquidityPool(address _liquidityPool) external onlyOwner {\n        require(_liquidityPool != address(0), "Invalid address");\n        liquidityPool = LiquidityPool(_liquidityPool);\n        emit ComponentsUpdated(address(lendingPool), address(liquidityPool), address(collateralVault), address(rateStrategy), address(priceOracle));\n    }\n\n    function setCollateralVault(address _collateralVault) external onlyOwner {\n        require(_collateralVault != address(0), "Invalid address");\n        collateralVault = CollateralVault(_collateralVault);\n        emit ComponentsUpdated(address(lendingPool), address(liquidityPool), address(collateralVault), address(rateStrategy), address(priceOracle));\n    }\n\n    function setRateStrategy(address _rateStrategy) external onlyOwner {\n        require(_rateStrategy != address(0), "Invalid address");\n        rateStrategy = RateStrategy(_rateStrategy);\n        emit ComponentsUpdated(address(lendingPool), address(liquidityPool), address(collateralVault), address(rateStrategy), address(priceOracle));\n    }\n\n    function setPriceOracle(address _priceOracle) external onlyOwner {\n        require(_priceOracle != address(0), "Invalid address");\n        priceOracle = PriceOracle(_priceOracle);\n        emit ComponentsUpdated(address(lendingPool), address(liquidityPool), address(collateralVault), address(rateStrategy), address(priceOracle));\n    }\n\n    \n    function getAllComponents() external view returns (\n        address,\n        address,\n        address,\n        address,\n        address\n    ) {\n        return (\n            address(lendingPool),\n            address(liquidityPool),\n            address(collateralVault),\n            address(rateStrategy),\n            address(priceOracle)\n        );\n    }\n\n\n    function getLendingPool() external view returns (address) {\n        return address(lendingPool);\n    }\n\n    function getLiquidityPool() external view returns (address) {\n        return address(liquidityPool);\n    }\n\n    function getCollateralVault() external view returns (address) {\n        return address(collateralVault);\n    }\n\n    function getRateStrategy() external view returns (address) {\n        return address(rateStrategy);\n    }\n\n    function getPriceOracle() external view returns (address) {\n        return address(priceOracle);\n    }\n}\n\n\n\n\n\n\n\ncontract record CollateralVault is Ownable {\n    event CollateralAdded(address indexed user, address indexed asset, uint amount);\n    event CollateralRemoved(address indexed user, address indexed asset, uint amount);\n\n    LendingRegistry public registry;\n\n\n    mapping(address => mapping(address => uint)) public record userCollaterals;\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry address");\n        registry = LendingRegistry(_registry);\n    }\n\n    modifier onlyLendingPool() {\n        require(msg.sender == address(registry.lendingPool()), "Caller is not LendingPool");\n        _;\n    }\n\n    \n    function addCollateral(address borrower, address asset, uint amount) public onlyLendingPool {\n        require(amount > 0, "Invalid amount");\n        require(IERC20(asset).transferFrom(borrower, address(this), amount), "Transfer failed");\n        userCollaterals[borrower][asset] += amount;\n        emit CollateralAdded(borrower, asset, amount);\n    }\n\n    \n    function removeCollateral(address borrower, address asset, uint amount) public onlyLendingPool {\n        require(userCollaterals[borrower][asset] >= amount, "Insufficient collateral");\n        userCollaterals[borrower][asset] -= amount;\n        require(IERC20(asset).transfer(borrower, amount), "Transfer failed");\n        emit CollateralRemoved(borrower, asset, amount);\n    }\n\n    \n    function seizeCollateral(address borrower, address to, address asset, uint amount) public onlyLendingPool {\n        require(amount > 0, "Invalid amount");\n        require(userCollaterals[borrower][asset] >= amount, "Insufficient collateral to seize");\n\n        userCollaterals[borrower][asset] -= amount;\n        require(IERC20(asset).transfer(to, amount), "Collateral transfer failed");\n\n        emit CollateralRemoved(borrower, asset, amount);\n    }\n\n    \n    function getCollateral(address user, address asset) public view returns (uint) {\n        return userCollaterals[user][asset];\n    }\n\n\n    function setRegistry(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry address");\n        registry = LendingRegistry(_registry);\n    }\n}\n\n\n\n\n\n\n\ncontract record PoolConfigurator is Ownable {\n\n    LendingRegistry public registry;\n\n    event AssetConfigured(address indexed asset, uint ltv, uint liquidationThreshold, uint liquidationBonus, uint interestRate, uint reserveFactor, uint perSecondFactorRAY);\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry");\n        registry = LendingRegistry(_registry);\n    }\n\n    \n\n    function initializeProtocol(\n        address lendingPool,\n        address liquidityPool,\n        address collateralVault,\n        address rateStrategy,\n        address priceOracle,\n        address tokenFactory,\n        address[] calldata assets,\n        uint[] calldata ltvs,\n        uint[] calldata liquidationThresholds,\n        uint[] calldata liquidationBonuses,\n        uint[] calldata interestRates,\n        uint[] calldata reserveFactors,\n        uint[] calldata perSecondFactorsRAY,\n        uint debtCeilingAssetUnits,\n        uint debtCeilingUSD,\n        uint safetyShareBps\n    ) external onlyOwner {\n\n        registry.setAllComponents(lendingPool, liquidityPool, collateralVault, rateStrategy, priceOracle);\n\n\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setTokenFactory(tokenFactory);\n\n\n        pool.setDebtCeilings(debtCeilingAssetUnits, debtCeilingUSD);\n        pool.setSafetyShareBps(safetyShareBps);\n\n\n        if (assets.length > 0) {\n\n            require(ltvs.length == assets.length, "LTVs length mismatch");\n            require(liquidationThresholds.length == assets.length, "Liquidation thresholds length mismatch");\n            require(liquidationBonuses.length == assets.length, "Liquidation bonuses length mismatch");\n            require(interestRates.length == assets.length, "Interest rates length mismatch");\n            require(reserveFactors.length == assets.length, "Reserve factors length mismatch");\n            require(perSecondFactorsRAY.length == assets.length, "per-second factors length mismatch");\n\n            for (uint i = 0; i < assets.length; i++) {\n                pool.configureAsset(\n                    assets[i],\n                    ltvs[i],\n                    liquidationThresholds[i],\n                    liquidationBonuses[i],\n                    interestRates[i],\n                    reserveFactors[i],\n                    perSecondFactorsRAY[i]\n                );\n                emit AssetConfigured(assets[i], ltvs[i], liquidationThresholds[i], liquidationBonuses[i], interestRates[i],reserveFactors[i],perSecondFactorsRAY[i]) ;\n            }\n        }\n    }\n\n    \n    function configureAssets(\n        address[] calldata assets,\n        uint[] calldata ltvs,\n        uint[] calldata liquidationThresholds,\n        uint[] calldata liquidationBonuses,\n        uint[] calldata interestRates,\n        uint[] calldata reserveFactors,\n        uint[] calldata perSecondFactorsRAY\n    ) external onlyOwner {\n\n        require(assets.length > 0, "No assets provided");\n        require(ltvs.length == assets.length, "LTVs length mismatch");\n        require(liquidationThresholds.length == assets.length, "Liquidation thresholds length mismatch");\n        require(liquidationBonuses.length == assets.length, "Liquidation bonuses length mismatch");\n        require(interestRates.length == assets.length, "Interest rates length mismatch");\n        require(reserveFactors.length == assets.length, "Reserve factors length mismatch");\n        require(perSecondFactorsRAY.length == assets.length, "per-second factors length mismatch");\n\n        for (uint i = 0; i < assets.length; i++) {\n            LendingPool pool = LendingPool(registry.getLendingPool());\n            pool.configureAsset(\n                assets[i],\n                ltvs[i],\n                liquidationThresholds[i],\n                liquidationBonuses[i],\n                interestRates[i],\n                reserveFactors[i],\n                perSecondFactorsRAY[i]\n            );\n            emit AssetConfigured(assets[i], ltvs[i], liquidationThresholds[i], liquidationBonuses[i], interestRates[i], reserveFactors[i], perSecondFactorsRAY[i]);\n        }\n    }\n\n    \n    function configureAsset(\n        address asset,\n        uint ltv,\n        uint liquidationThreshold,\n        uint liquidationBonus,\n        uint interestRate,\n        uint reserveFactor,\n        uint perSecondFactorRAY\n    ) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.configureAsset(asset, ltv, liquidationThreshold, liquidationBonus, interestRate, reserveFactor, perSecondFactorRAY);\n        emit AssetConfigured(asset, ltv, liquidationThreshold, liquidationBonus, interestRate, reserveFactor, perSecondFactorRAY);\n    }\n\n    \n    function getAssetConfig(address asset) external view returns (uint, uint, uint, uint, uint, uint) {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        return pool.getAssetConfig(asset);\n    }\n\n    \n    function setTokenFactory(address _tokenFactory) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setTokenFactory(_tokenFactory);\n    }\n\n    \n    function setFeeCollector(address _feeCollector) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setFeeCollector(_feeCollector);\n    }\n\n    \n    function setSafetyModule(address _safetyModule) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setSafetyModule(_safetyModule);\n    }\n\n\n    function setBorrowableAsset(address asset) external onlyOwner {\n        require(asset != address(0), "Invalid asset address");\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setBorrowableAsset(asset);\n    }\n\n\n    function setMToken(address mToken) external onlyOwner {\n        require(mToken != address(0), "Invalid mToken address");\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setMToken(mToken);\n    }\n\n\n    function setDebtCeilings(uint assetUnits, uint usdValue) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setDebtCeilings(assetUnits, usdValue);\n    }\n\n\n    function setSafetyShareBps(uint bps) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.setSafetyShareBps(bps);\n    }\n\n\n    function setLendingPool(address _lendingPool) external onlyOwner {\n        require(_lendingPool != address(0), "Invalid lendingPool address");\n        registry.setLendingPool(_lendingPool);\n    }\n    function setLiquidityPool(address _liquidityPool) external onlyOwner {\n        require(_liquidityPool != address(0), "Invalid liquidityPool address");\n        registry.setLiquidityPool(_liquidityPool);\n    }\n    function setCollateralVault(address _collateralVault) external onlyOwner {\n        require(_collateralVault != address(0), "Invalid collateralVault address");\n        registry.setCollateralVault(_collateralVault);\n    }\n    function setRateStrategy(address _rateStrategy) external onlyOwner {\n        require(_rateStrategy != address(0), "Invalid rateStrategy address");\n        registry.setRateStrategy(_rateStrategy);\n    }\n    function setPriceOracle(address _priceOracle) external onlyOwner {\n        require(_priceOracle != address(0), "Invalid priceOracle address");\n        registry.setPriceOracle(_priceOracle);\n    }\n\n    \n    function sweepReserves(uint amount) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.sweepReserves(amount);\n    }\n\n\n    function writeOffBadDebtWithHaircut(uint amount, string calldata reason) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.writeOffBadDebtWithHaircut(amount, reason);\n    }\n\n\n    function writeOffBadDebtFromReserves(uint amount) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.writeOffBadDebtFromReserves(amount);\n    }\n\n\n    function recognizeBadDebt(address borrower) external onlyOwner {\n        LendingPool pool = LendingPool(registry.getLendingPool());\n        pool.recognizeBadDebt(borrower);\n    }\n\n}\n\nlibrary BytesUtils {\n    function fromHex(uint x) internal pure returns (uint) {\n        if (x >= 0x30 && x <= 0x39) {\n            return x - 0x30;\n        } else if (x >= 0x61 && x <= 0x66) {\n            return x - 0x57;\n        } else {\n            require(x >= 0x41 && x <= 0x46, "not a valid hex digit: " + string(x, 16));\n            return x - 0x37;\n        }\n    }\n\n    function toHex(uint x) internal pure returns (uint) {\n        uint y = x & 0xf;\n        if (y >= 0xa) {\n            y += 0x27;\n        }\n        y += 0x30;\n        return y;\n    }\n\n    function b16encode(bytes b) internal pure returns (bytes) {\n        bytes dst = new bytes(2 * b.length);\n        for (uint i = 0; i < b.length; i++) {\n            dst[2*i] = toHex((b[i] >> 4) & 0xf);\n            dst[2*i + 1] = toHex(b[i] & 0xf);\n        }\n        return dst;\n    }\n\n    function b16decode(bytes b) internal pure returns (bytes) {\n        bool isEven = b.length % 2 == 0;\n        uint offset = isEven ? 0 : 1;\n        bytes dst = new bytes((b.length / 2) + offset);\n        if (!isEven) {\n            dst[0] = fromHex(b[0]);\n        }\n        for (uint i = offset; i < b.length; i += 2) {\n            dst[i/2 + offset] = (fromHex(b[i]) << 4) | fromHex(b[i+1]);\n        }\n        return dst;\n    }\n}\n\nlibrary StringUtils {\n    using BytesUtils for bytes;\n\n    function toLower(string s) internal pure returns (string) {\n        bytes b = bytes(s);\n        for (uint i = 0; i < b.length; i++) {\n            if (b[i] >= 0x41 && b[i] <= 0x5a) {\n                b[i] = b[i] + 0x20;\n            }\n        }\n        return string(b);\n    }\n\n    function toUpper(string s) internal pure returns (string) {\n        bytes b = bytes(s);\n        for (uint i = 0; i < b.length; i++) {\n            if (b[i] >= 0x61 && b[i] <= 0x7a) {\n                b[i] = b[i] - 0x20;\n            }\n        }\n        return string(b);\n    }\n\n    function intercalate(string s, string[] strs) internal pure returns (string) {\n        string r = "";\n        for (uint i = 0; i < strs.length; i++) {\n            if (i > 0) {\n                r += s;\n            }\n            r += strs[i];\n        }\n        return r;\n    }\n\n    function substring(string s, uint start) internal pure returns (string) {\n        return substring(s, start, s.length);\n    }\n\n    function substring(string s, uint start, uint end) internal pure returns (string) {\n        require(end > start, "substring: end index must be greater than starting index");\n        bytes b = bytes(s);\n        bytes ret = new bytes(end - start);\n        for (uint i = start; i < end; i++) {\n            ret[i - start] = b[i];\n        }\n        return string(ret);\n    }\n\n    function normalizeHex(string s) internal pure returns (string) {\n        string hexPart = substring(s,0,2) == "0x" ? substring(s,2) : s;\n        return "0x" + string(bytes(hexPart).b16decode().b16encode());\n    }\n}\n\nlibrary BridgeTypes {\n    enum BridgeStatus {\n        NONE,         \n        INITIATED,    \n\n        PENDING_REVIEW, \n\n        COMPLETED,    \n        ABORTED       \n    }\n\n    struct DepositInfo {\n        BridgeStatus bridgeStatus; \n        address externalSender;    \n        address externalToken;     \n        uint256 requestedAt;       \n        address stratoRecipient;   \n        address stratoToken;       \n        uint256 stratoTokenAmount; \n        uint256 timestamp;         \n    }\n\n    struct WithdrawalInfo {\n        BridgeStatus bridgeStatus;   \n        string custodyTxHash;        \n        uint256 externalChainId;     \n        address externalRecipient;   \n        address externalToken;       \n        uint256 externalTokenAmount; \n        uint256 requestedAt;         \n        address stratoSender;        \n        address stratoToken;         \n        uint256 stratoTokenAmount;   \n        uint256 timestamp;           \n    }\n\n    struct ChainInfo {\n        string  chainName;\n        address custody;            \n        address depositRouter;      \n        bool    enabled;            \n        uint256 lastProcessedBlock; \n    }\n\n    struct AssetInfo {\n        bool    enabled;          \n        uint256 externalChainId;  \n        uint256 externalDecimals; \n        string  externalName;     \n        string  externalSymbol;   \n        address externalToken;    \n        uint256 maxPerWithdrawal; \n        address stratoToken;      \n    }\n}\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record MercataBridge is Ownable {\n\n\n    using BridgeTypes for *;\n    using StringUtils for string;\n\n    \n    \n    \n\n\n\n    event PauseToggled(bool depositsPaused, bool withdrawalsPaused);\n\n\n    event TokenFactoryUpdated(address newFactory, address oldFactory);\n\n\n    event LendingRegistryUpdated(address newRegistry, address oldRegistry);\n\n\n    event USDSTAddressUpdated(address newAddress, address oldAddress);\n\n\n    event ChainToggled(bool enabled, uint256 externalChainId);\n\n\n    event AssetToggled(bool enabled, uint256 externalChainId, address externalToken);\n\n\n\n    event DepositAborted(uint256 srcChainId, string srcTxHash);\n\n\n    event DepositCompleted(uint256 srcChainId, string srcTxHash);\n\n\n\n\n\n\n\n\n    event DepositInitiated(uint256 externalChainId, address externalSender, string externalTxHash, address stratoRecipient, address stratoToken, uint256 stratoTokenAmount);\n\n\n    event DepositPendingReview(uint256 srcChainId, string srcTxHash);\n\n\n    event WithdrawalAborted(uint256 withdrawalId);\n\n\n    event WithdrawalCompleted(uint256 withdrawalId);\n\n\n    event WithdrawalPending(string custodyTxHash, uint256 withdrawalId);\n\n\n\n\n\n\n\n\n\n    event WithdrawalRequested(address dest, uint256 destChainId, uint256 externalTokenAmount, uint256 stratoTokenAmount, address token, address user, uint256 withdrawalId);\n\n\n\n    event ChainUpdated(string chainName, address custody, bool enabled, uint256 externalChainId, uint256 lastProcessedBlock, address router);\n\n\n    event LastProcessedBlockUpdated(uint256 externalChainId, uint256 lastProcessedBlock);\n\n\n    event EmergencyBlockRollback(uint256 externalChainId, uint256 lastProcessedBlock);\n\n\n\n\n\n\n\n\n\n\n    event AssetUpdated(bool enabled, uint256 externalChainId, uint256 externalDecimals, string externalName, string externalSymbol, address externalToken, uint256 maxPerWithdrawal, address stratoToken);\n\n\n\n\n\n    event AutoSaveRequested(address user, uint256 externalChainId, string externalTxHash);\n\n\n\n\n\n\n    event AutoSaved(uint256 externalChainId, string externalTxHash, uint256 mintedAmount, uint256 mTokenAmount);\n\n    \n    \n    \n\n\n\n\n    uint256 public DECIMAL_PLACES = 18;\n\n\n\n    bool public depositsPaused;\n\n\n\n    address public tokenFactory;\n\n\n    address public lendingRegistry;\n\n\n\n    address public USDST_ADDRESS = address(0x937efa7e3a77e20bbdbd7c0d32b6514f368c1010);\n\n\n\n    bool public withdrawalsPaused;\n\n\n\n    uint256 public WITHDRAWAL_ABORT_DELAY = 172800;\n\n\n\n\n\n\n\n    mapping(uint256 => mapping(string => DepositInfo)) public record deposits;\n\n\n\n\n\n\n\n    mapping(address => mapping (uint256 => mapping(string => bool))) public record autoSaveRequested;\n\n\n\n\n    mapping(uint256 => WithdrawalInfo) public record withdrawals;\n\n\n\n    uint256 public withdrawalCounter;\n\n\n\n\n\n    mapping(uint256 => ChainInfo) public record chains;\n\n\n\n\n\n\n    mapping(address => mapping(uint256 => AssetInfo)) public record assets;\n\n\n    \n    \n    \n\n\n    modifier whenDepositsOpen() {\n        require(!depositsPaused, "MB: deposits paused");\n        _;\n    }\n\n\n\n    modifier whenWithdrawalsOpen() {\n        require(!withdrawalsPaused, "MB: withdrawals paused");\n        _;\n    }\n\n    \n    \n    \n\n    \n    constructor(\n        address _owner\n    ) Ownable(_owner) { }\n\n    \n    function initialize(\n        address _tokenFactory,\n        address _lendingRegistry\n    ) external onlyOwner {\n        DECIMAL_PLACES = 18;\n        USDST_ADDRESS = address(0x937efa7e3a77e20bbdbd7c0d32b6514f368c1010);\n        WITHDRAWAL_ABORT_DELAY = 172800;\n\n        setTokenFactory(_tokenFactory);\n        setLendingRegistry(_lendingRegistry);\n    }\n\n\n    \n    function emergencySetLastProcessedBlock(\n        uint256 externalChainId, uint256 lastProcessedBlock\n    ) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        ChainInfo chainInfo = chains[externalChainId];\n        require(chainInfo.custody != address(0), "MB: chain missing");\n\n        chainInfo.lastProcessedBlock = lastProcessedBlock;\n        emit LastProcessedBlockUpdated(externalChainId, lastProcessedBlock);\n        emit EmergencyBlockRollback(externalChainId, lastProcessedBlock);\n    }\n\n    \n    function setAsset(\n        bool enabled, uint256 externalChainId, uint256 externalDecimals, string externalName, string externalSymbol, address externalToken, uint256 maxPerWithdrawal, address stratoToken\n    ) external onlyOwner {\n        require(chains[externalChainId].custody != address(0), "MB: chain missing");\n        require(externalName.length > 0, "MB: invalid external name");\n        require(externalSymbol.length > 0, "MB: invalid external symbol");\n        require(stratoToken != address(0), "MB: invalid strato token");\n        require(externalDecimals <= DECIMAL_PLACES, "MB: decimals exceed max");\n        assets[externalToken][externalChainId] = AssetInfo(enabled, externalChainId, externalDecimals, externalName, externalSymbol, externalToken, maxPerWithdrawal, stratoToken);\n        emit AssetUpdated(enabled, externalChainId, externalDecimals, externalName, externalSymbol, externalToken, maxPerWithdrawal, stratoToken);\n    }\n\n    \n    function setAssetMetadata(\n        uint256 externalChainId, string externalName, string externalSymbol, address externalToken\n    ) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid chain id");\n        require(externalName.length > 0, "MB: invalid external name");\n        require(externalSymbol.length > 0, "MB: invalid external symbol");\n        require(chains[externalChainId].custody != address(0), "MB: chain missing");\n        AssetInfo assetInfo = assets[externalToken][externalChainId];\n        require(assetInfo.externalToken == externalToken, "MB: asset not found");\n        assetInfo.externalName = externalName;\n        assetInfo.externalSymbol = externalSymbol;\n        emit AssetUpdated(assetInfo.enabled, externalChainId, assetInfo.externalDecimals, externalName, externalSymbol, externalToken, assetInfo.maxPerWithdrawal, assetInfo.stratoToken);\n    }\n\n    \n    function setWithdrawalLimits(\n        uint256 externalChainId, address externalToken, uint256 maxPerWithdrawal\n    ) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid chain id");\n        require(chains[externalChainId].custody != address(0), "MB: chain missing");\n        AssetInfo assetInfo = assets[externalToken][externalChainId];\n        require(assetInfo.externalToken == externalToken, "MB: asset not found");\n        assetInfo.maxPerWithdrawal = maxPerWithdrawal;\n        emit AssetUpdated(assetInfo.enabled, externalChainId, assetInfo.externalDecimals, assetInfo.externalName, assetInfo.externalSymbol, externalToken, maxPerWithdrawal, assetInfo.stratoToken);\n    }\n\n    \n    function setChain(\n        string chainName, address custody, bool enabled, uint256 externalChainId, uint256 lastProcessedBlock, address router\n    ) external onlyOwner {\n        require(chainName.length > 0, "MB: invalid chain name");\n        require(custody != address(0), "MB: zero custody address");\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(router != address(0), "MB: zero router address");\n        chains[externalChainId] = ChainInfo(chainName, custody, router, enabled, lastProcessedBlock);\n        emit ChainUpdated(chainName, custody, enabled, externalChainId, lastProcessedBlock, router);\n    }\n\n    \n    function setLastProcessedBlock(\n        uint256 externalChainId, uint256 lastProcessedBlock\n    ) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        ChainInfo chainInfo = chains[externalChainId];\n        require(chainInfo.custody != address(0), "MB: chain missing");\n\n        require(lastProcessedBlock >= chainInfo.lastProcessedBlock, "MB: cannot rollback block");\n\n        chainInfo.lastProcessedBlock = lastProcessedBlock;\n        emit LastProcessedBlockUpdated(externalChainId, lastProcessedBlock);\n    }\n\n    \n    function setPause(bool _deposits, bool _withdrawals) external onlyOwner {\n        depositsPaused    = _deposits;\n        withdrawalsPaused = _withdrawals;\n        emit PauseToggled(_deposits, _withdrawals);\n    }\n\n    \n    function setTokenFactory(address newFactory) public onlyOwner {\n        require(newFactory != address(0), "MB: zero");\n        emit TokenFactoryUpdated(newFactory, tokenFactory);\n        tokenFactory = newFactory;\n    }\n\n    \n    function setLendingRegistry(address newLendingRegistry) public onlyOwner {\n        require(newLendingRegistry != address(0), "MB: zero lending registry address");\n        emit LendingRegistryUpdated(newLendingRegistry, lendingRegistry);\n        lendingRegistry = newLendingRegistry;\n    }\n\n    \n    function setUSDSTAddress(address newUSDSTAddress) external onlyOwner {\n        require(newUSDSTAddress != address(0), "MB: zero USDST address");\n        emit USDSTAddressUpdated(newUSDSTAddress, USDST_ADDRESS);\n        USDST_ADDRESS = newUSDSTAddress;\n    }\n\n    \n    function toggleChain(uint256 externalChainId, bool enabled) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid chain id");\n        require(chains[externalChainId].custody != address(0), "MB: chain not found");\n\n        chains[externalChainId].enabled = enabled;\n        emit ChainToggled(enabled, externalChainId);\n    }\n\n    \n    function toggleAsset(address externalToken, uint256 externalChainId, bool enabled) external onlyOwner {\n        require(externalChainId > 0, "MB: invalid chain id");\n        require(assets[externalToken][externalChainId].externalChainId == externalChainId, "MB: asset not found");\n\n        assets[externalToken][externalChainId].enabled = enabled;\n        emit AssetToggled(enabled, externalChainId, externalToken);\n    }\n\n\n    \n    function _burnFunds(address token, uint256 amount) internal returns (uint256 actualAmount) {\n        uint256 balanceBefore = IERC20(token).balanceOf(address(this));\n        Token(token).burn(address(this), amount);\n        actualAmount = balanceBefore - IERC20(token).balanceOf(address(this));\n        require(actualAmount > 0, "MB: no tokens burned");\n    }\n\n    \n    function _escrowFunds(address token, address from, uint256 amount) internal returns (uint256 actualAmount) {\n        uint256 balanceBefore = IERC20(token).balanceOf(address(this));\n        require(IERC20(token).transferFrom(from, address(this), amount), "MB: transfer failed");\n        actualAmount = IERC20(token).balanceOf(address(this)) - balanceBefore;\n        require(actualAmount > 0, "MB: no tokens received");\n    }\n\n    \n    function _mintFunds(address token, address to, uint256 amount) internal returns (uint256 actualAmount) {\n        uint256 balanceBefore = IERC20(token).balanceOf(to);\n        Token(token).mint(to, amount);\n        actualAmount = IERC20(token).balanceOf(to) - balanceBefore;\n        require(actualAmount > 0, "MB: no tokens minted");\n    }\n\n    \n    function _refundFunds(address token, address to, uint256 amount) internal returns (uint256 actualAmount) {\n        uint256 balanceBefore = IERC20(token).balanceOf(address(this));\n        require(IERC20(token).transfer(to, amount), "MB: transfer failed");\n        actualAmount = balanceBefore - IERC20(token).balanceOf(address(this));\n        require(actualAmount > 0, "MB: no tokens sent");\n    }\n\n    function _autoSave(DepositInfo d, uint256 externalChainId, string normalizedTxHash) internal {\n\n        require(lendingRegistry != address(0), "MB: lending registry not set");\n\n        LendingRegistry registry = LendingRegistry(lendingRegistry);\n        LendingPool lendingPool = registry.lendingPool();\n        LiquidityPool liquidityPool = registry.liquidityPool();\n        IERC20 mToken = IERC20(lendingPool.mToken());\n\n\n        require(d.stratoToken == lendingPool.borrowableAsset(), "MB: cannot autosave token");\n\n\n        uint256 actualMintedAmount = _mintFunds(d.stratoToken, this, d.stratoTokenAmount);\n        require(actualMintedAmount > 0, "MB: no tokens minted");\n\n\n        IERC20(d.stratoToken).approve(address(liquidityPool), actualMintedAmount);\n        uint balanceBefore = mToken.balanceOf(d.stratoRecipient);\n        lendingPool.depositLiquidityOnBehalfOf(d.stratoRecipient, actualMintedAmount);\n        uint mTokenAmount = mToken.balanceOf(d.stratoRecipient) - balanceBefore;\n        require(mTokenAmount > 0, "MB: autosave failed");\n\n        emit AutoSaved(externalChainId, normalizedTxHash, actualMintedAmount, mTokenAmount);\n    }\n\n\n\n    \n    function deposit(\n        uint256 externalChainId, address externalSender, address externalToken, uint256 externalTokenAmount, string externalTxHash, address stratoRecipient\n    ) public onlyOwner whenDepositsOpen {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(externalSender != address(0), "MB: invalid external sender");\n        require(externalTokenAmount > 0, "MB: invalid external token amount");\n        require(externalTxHash.length > 0, "MB: invalid external tx hash");\n        require(stratoRecipient != address(0), "MB: invalid strato recipient");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n\n\n\n        string normalizedTxHash = externalTxHash.normalizeHex();\n        require(deposits[externalChainId][normalizedTxHash].bridgeStatus == BridgeStatus.NONE, "MB: duplicate deposit");\n\n        AssetInfo a = assets[externalToken][externalChainId];\n        require(a.enabled, "MB: asset not enabled");\n        require(TokenFactory(tokenFactory).isTokenActive(a.stratoToken), "MB: inactive token");\n\n\n        uint256 stratoTokenAmount = externalTokenAmount * (10 ** (DECIMAL_PLACES - a.externalDecimals));\n        require(stratoTokenAmount > 0, "MB: invalid strato token amount");\n\n        deposits[externalChainId][normalizedTxHash] = DepositInfo(\n            BridgeStatus.INITIATED, externalSender, externalToken, block.timestamp, stratoRecipient, a.stratoToken, stratoTokenAmount, block.timestamp\n        );\n\n        emit DepositInitiated(externalChainId, externalSender, normalizedTxHash, stratoRecipient, a.stratoToken, stratoTokenAmount);\n    }\n\n    \n    function depositBatch(\n        uint256[] externalChainIds, address[] externalSenders, address[] externalTokens, uint256[] externalTokenAmounts, string[] externalTxHashes, address[] stratoRecipients\n    ) external onlyOwner whenDepositsOpen {\n        uint256 n = externalChainIds.length;\n        require(n > 0 && n == externalSenders.length && n == externalTokens.length && n == externalTokenAmounts.length && n == externalTxHashes.length && n == stratoRecipients.length, "MB: len");\n        for (uint256 i = 0; i < n; i++) {\n            deposit(externalChainIds[i], externalSenders[i], externalTokens[i], externalTokenAmounts[i], externalTxHashes[i], stratoRecipients[i]);\n        }\n    }\n\n    function requestAutoSave(address user, uint externalChainId, string externalTxHash) external onlyOwner {\n        require(user != address(0), "MB: invalid user");\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n        require(externalTxHash.length > 0, "MB: invalid external tx hash");\n\n        string normalizedTxHash = externalTxHash.normalizeHex();\n\n        require(deposits[externalChainId][normalizedTxHash].bridgeStatus != BridgeStatus.COMPLETED, "MB: Already completed");\n        autoSaveRequested[user][externalChainId][normalizedTxHash] = true;\n\n        emit AutoSaveRequested(user, externalChainId, normalizedTxHash);\n    }\n\n    \n    function confirmDeposit(\n        uint256 externalChainId, string externalTxHash\n    ) public onlyOwner whenDepositsOpen {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n        require(externalTxHash.length > 0, "MB: invalid external tx hash");\n\n\n\n        string normalizedTxHash = externalTxHash.normalizeHex();\n        DepositInfo d = deposits[externalChainId][normalizedTxHash];\n        require(d.bridgeStatus == BridgeStatus.INITIATED || d.bridgeStatus == BridgeStatus.PENDING_REVIEW, "MB: bad state");\n\n        if (autoSaveRequested[d.stratoRecipient][externalChainId][normalizedTxHash]) {\n            try {\n                _autoSave(d, externalChainId, normalizedTxHash);\n            }\n            catch {\n\n                uint256 actualMintedAmount = _mintFunds(d.stratoToken, d.stratoRecipient, d.stratoTokenAmount);\n                require(actualMintedAmount > 0, "MB: no tokens minted");\n            }\n\n            delete autoSaveRequested[d.stratoRecipient][externalChainId][normalizedTxHash];\n        }\n        else {\n\n            uint256 actualMintedAmount = _mintFunds(d.stratoToken, d.stratoRecipient, d.stratoTokenAmount);\n            require(actualMintedAmount > 0, "MB: no tokens minted");\n        }\n\n        d.bridgeStatus = BridgeStatus.COMPLETED;\n        d.timestamp = block.timestamp;\n        emit DepositCompleted(externalChainId, normalizedTxHash);\n    }\n\n    \n    function confirmDepositBatch(\n        uint256[] externalChainIds, string[] externalTxHashes\n    ) external onlyOwner whenDepositsOpen {\n        uint256 n = externalChainIds.length;\n        require(n > 0 && n == externalTxHashes.length, "MB: len");\n        for (uint256 i = 0; i < n; i++) {\n            confirmDeposit(externalChainIds[i], externalTxHashes[i]);\n        }\n    }\n\n    \n    function reviewDeposit(\n        uint256 externalChainId, string externalTxHash\n    ) public onlyOwner whenDepositsOpen {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n        require(externalTxHash.length > 0, "MB: invalid external tx hash");\n\n\n\n        string normalizedTxHash = externalTxHash.normalizeHex();\n        DepositInfo d = deposits[externalChainId][normalizedTxHash];\n        require(d.bridgeStatus == BridgeStatus.INITIATED, "MB: bad state");\n\n        d.bridgeStatus = BridgeStatus.PENDING_REVIEW;\n        d.timestamp = block.timestamp;\n\n        emit DepositPendingReview(externalChainId, normalizedTxHash);\n    }\n\n    \n    function reviewDepositBatch(\n        uint256[] externalChainIds, string[] externalTxHashes\n    ) external onlyOwner whenDepositsOpen {\n        uint256 n = externalChainIds.length;\n        require(n > 0 && n == externalTxHashes.length, "MB: len");\n\n        for (uint256 i = 0; i < n; i++) {\n            reviewDeposit(externalChainIds[i], externalTxHashes[i]);\n        }\n    }\n\n    \n    function abortDeposit(\n        uint256 externalChainId, string externalTxHash\n    ) public onlyOwner {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n        require(externalTxHash.length > 0, "MB: invalid external tx hash");\n\n\n\n        string normalizedTxHash = externalTxHash.normalizeHex();\n        DepositInfo d = deposits[externalChainId][normalizedTxHash];\n        require(d.bridgeStatus == BridgeStatus.PENDING_REVIEW, "MB: bad state");\n\n        d.bridgeStatus = BridgeStatus.ABORTED;\n        d.timestamp = block.timestamp;\n\n        emit DepositAborted(externalChainId, normalizedTxHash);\n    }\n\n    \n    function abortDepositBatch(\n        uint256[] externalChainIds, string[] externalTxHashes\n    ) external onlyOwner {\n        uint256 n = externalChainIds.length;\n        require(n > 0 && n == externalTxHashes.length, "MB: len");\n\n        for (uint256 i = 0; i < n; i++) {\n            abortDeposit(externalChainIds[i], externalTxHashes[i]);\n        }\n    }\n\n\n    \n    function requestWithdrawal(\n        uint256 externalChainId, address externalRecipient, address externalToken, uint256 stratoTokenAmount\n    ) external whenWithdrawalsOpen returns (uint256 id) {\n        require(externalChainId > 0, "MB: invalid external chain id");\n        require(externalRecipient != address(0), "MB: invalid external recipient");\n        require(stratoTokenAmount > 0, "MB: invalid strato token amount");\n        require(chains[externalChainId].enabled, "MB: chain not enabled");\n\n        AssetInfo a = assets[externalToken][externalChainId];\n        require(a.enabled, "MB: asset not enabled");\n        require(TokenFactory(tokenFactory).isTokenActive(a.stratoToken), "MB: inactive token");\n\n\n\n        uint256 externalTokenAmount = stratoTokenAmount / (10 ** (DECIMAL_PLACES - a.externalDecimals));\n        require(externalTokenAmount > 0, "MB: not enough external tokens");\n\n        stratoTokenAmount = externalTokenAmount * (10 ** (DECIMAL_PLACES - a.externalDecimals));\n        require(a.maxPerWithdrawal == 0 || stratoTokenAmount <= a.maxPerWithdrawal, "MB: per-withdrawal cap");\n        stratoTokenAmount = _escrowFunds(a.stratoToken, msg.sender, stratoTokenAmount);\n        require(stratoTokenAmount > 0, "MB: no tokens escrowed");\n\n\n\n        externalTokenAmount = stratoTokenAmount / (10 ** (DECIMAL_PLACES - a.externalDecimals));\n        require(externalTokenAmount > 0, "MB: invalid external token amount");\n\n        id = ++withdrawalCounter;\n\n        withdrawals[id] = WithdrawalInfo(\n            BridgeStatus.INITIATED, "", externalChainId, externalRecipient, externalToken, externalTokenAmount, block.timestamp, msg.sender, a.stratoToken, stratoTokenAmount, block.timestamp\n        );\n\n        emit WithdrawalRequested(externalRecipient, externalChainId, externalTokenAmount, stratoTokenAmount, a.stratoToken, msg.sender, id);\n    }\n\n    \n    function confirmWithdrawal(\n        uint256 id, string custodyTxHash\n    ) public onlyOwner whenWithdrawalsOpen {\n        require(id > 0, "MB: invalid withdrawal id");\n        require(custodyTxHash.length > 0, "MB: invalid custody tx hash");\n\n        WithdrawalInfo w = withdrawals[id];\n        require(w.bridgeStatus == BridgeStatus.INITIATED, "MB: bad state");\n\n        w.bridgeStatus = BridgeStatus.PENDING_REVIEW;\n        w.timestamp = block.timestamp;\n\n\n\n        string normalizedCustodyTxHash = custodyTxHash.normalizeHex();\n        w.custodyTxHash = normalizedCustodyTxHash;\n\n        emit WithdrawalPending(normalizedCustodyTxHash, id);\n    }\n\n    \n    function confirmWithdrawalBatch(\n        uint256[] ids, string[] custodyTxHashes\n    ) external onlyOwner whenWithdrawalsOpen {\n        uint256 n = ids.length;\n        require(n > 0 && n == custodyTxHashes.length, "MB: len");\n\n        for (uint256 i = 0; i < n; i++) {\n            confirmWithdrawal(ids[i], custodyTxHashes[i]);\n        }\n    }\n\n    \n    function finaliseWithdrawal(\n        uint256 id\n    ) public onlyOwner whenWithdrawalsOpen {\n        require(id > 0, "MB: invalid withdrawal id");\n\n        WithdrawalInfo w = withdrawals[id];\n        require(w.bridgeStatus == BridgeStatus.PENDING_REVIEW, "MB: bad state");\n\n        uint256 actualBurnedAmount = _burnFunds(w.stratoToken, w.stratoTokenAmount);\n        require(actualBurnedAmount > 0, "MB: no tokens burned");\n\n        w.bridgeStatus = BridgeStatus.COMPLETED;\n        w.timestamp = block.timestamp;\n\n        emit WithdrawalCompleted(id);\n    }\n\n    \n    function finaliseWithdrawalBatch(\n        uint256[] ids\n    ) external onlyOwner whenWithdrawalsOpen {\n        uint256 n = ids.length;\n        require(n > 0, "MB: len");\n\n        for (uint256 i = 0; i < n; i++) {\n            finaliseWithdrawal(ids[i]);\n        }\n    }\n\n    \n    function abortWithdrawal(\n        uint256 id\n    ) public {\n        require(id > 0, "MB: invalid withdrawal id");\n\n        WithdrawalInfo w = withdrawals[id];\n        uint256 currentTimestamp = block.timestamp;\n\n        AdminRegistry admin = AdminRegistry(owner());\n        if (admin.whitelist(address(this), "abortWithdrawal", msg.sender)) {\n            require(w.bridgeStatus == BridgeStatus.INITIATED || w.bridgeStatus == BridgeStatus.PENDING_REVIEW, "MB: not abortable");\n        }\n        else {\n            require(msg.sender == w.stratoSender, "MB: not sender");\n            require(w.bridgeStatus == BridgeStatus.INITIATED, "MB: not abortable");\n            require(currentTimestamp >= w.requestedAt + WITHDRAWAL_ABORT_DELAY, "MB: wait 48h");\n        }\n\n        w.bridgeStatus = BridgeStatus.ABORTED;\n        w.timestamp = currentTimestamp;\n\n        uint256 actualRefundedAmount = _refundFunds(w.stratoToken, w.stratoSender, w.stratoTokenAmount);\n        require(actualRefundedAmount > 0, "MB: no tokens refunded");\n\n        emit WithdrawalAborted(id);\n    }\n\n    \n    function abortWithdrawalBatch(\n        uint256[] ids\n    ) external {\n        uint256 n = ids.length;\n        require(n > 0, "MB: len");\n\n        for (uint256 i = 0; i < n; i++) {\n            abortWithdrawal(ids[i]);\n        }\n    }\n}\n\n\n\n\n\n\n\ncontract record CDPVault is Ownable {\n    CDPRegistry public registry;\n\n\n    mapping(address => mapping(address => uint)) public userCollaterals;\n\n    event CollateralDeposited(address indexed user, address indexed asset, uint amount);\n    event CollateralWithdrawn(address indexed user, address indexed asset, uint amount);\n    event CollateralSeized(address indexed borrower, address indexed liquidator, address indexed asset, uint amount);\n    event RegistryUpdated(\n        address indexed oldRegistry,\n        address indexed newRegistry\n    );\n\n    modifier onlyEngine() {\n        require(msg.sender == address(registry.cdpEngine()), "CDPVault: Only engine");\n        _;\n    }\n\n    \n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _registry) external onlyOwner {\n        require(_registry != address(0), "CDPVault: Invalid registry");\n        registry = CDPRegistry(_registry);\n    }\n\n    \n    function deposit(\n        address borrower,\n        address asset,\n        uint amount\n    ) public onlyEngine {\n        require(borrower != address(0), "CDPVault: Invalid borrower");\n        require(asset != address(0), "CDPVault: Invalid asset");\n        require(amount > 0, "Invalid amount");\n\n        require(IERC20(asset).transferFrom(borrower, address(this), amount), "Transfer failed");\n        userCollaterals[borrower][asset] += amount;\n        emit CollateralDeposited(borrower, asset, amount);\n    }\n\n    \n    function withdraw(\n        address borrower,\n        address asset,\n        uint amount\n    ) public onlyEngine {\n        require(\n            userCollaterals[borrower][asset] >= amount,\n            "CDPVault: Insufficient balance"\n        );\n\n        userCollaterals[borrower][asset] -= amount;\n        require(IERC20(asset).transfer(borrower, amount), "Transfer failed");\n        emit CollateralWithdrawn(borrower, asset, amount);\n    }\n\n    \n    function seize(\n        address borrower,\n        address asset,\n        address liquidator,\n        uint amount\n    ) public onlyEngine {\n        require(amount > 0, "Invalid amount");\n        require(\n            userCollaterals[borrower][asset] >= amount,\n            "CDPVault: insufficient balance"\n        );\n\n        userCollaterals[borrower][asset] -= amount;\n        require(IERC20(asset).transfer(liquidator, amount), "Transfer failed");\n\n        emit CollateralSeized(borrower, liquidator, asset, amount);\n    }\n\n    \n    function getCollateral(address user, address asset) public view returns (uint) {\n        return userCollaterals[user][asset];\n    }\n\n    \n    function setRegistry(address _registry) external onlyOwner {\n        require(_registry != address(0), "Invalid registry address");\n        address oldRegistry = address(registry);\n        registry = CDPRegistry(_registry);\n        emit RegistryUpdated(oldRegistry, _registry);\n    }\n}\n\n\n\n\n\n\n\ncontract record CDPReserve is Ownable {\n  CDPRegistry public registry;\n\n  function _usdst() internal view returns (Token) { return Token(address(registry.usdst())); }\n\n  event Transferred(address indexed to, uint256 amount);\n\n  modifier onlyEngine() {\n    require(msg.sender == address(registry.cdpEngine()), "Reserve: not engine");\n    _;\n  }\n\n  constructor(address _owner) Ownable(_owner) { }\n\n  function initialize(address _registry) external onlyOwner {\n    require(_registry != address(0), "CDPReserve: Invalid registry");\n    registry = CDPRegistry(_registry);\n  }\n\n\n  function setRegistry(address _registry) external onlyOwner {\n    require(_registry != address(0), "CDPReserve: Invalid registry");\n    registry = CDPRegistry(_registry);\n  }\n\n\n  function transferTo(address to, uint256 amount) external onlyEngine {\n    require(to != address(0), "Reserve: to=0");\n    require(_usdst().transfer(to, amount), "Reserve: transfer failed");\n    emit Transferred(to, amount);\n  }\n\n}\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record CDPEngine is Ownable {\n\n    CDPRegistry public registry;\n\n\n\n    struct CollateralConfig {\n        uint liquidationRatio;          \n        uint minCR;                     \n        uint liquidationPenaltyBps;     \n        uint closeFactorBps;            \n        uint stabilityFeeRate;          \n        uint debtFloor;                 \n        uint debtCeiling;               \n        uint unitScale;                 \n        bool isPaused;                  \n    }\n\n\n    struct CollateralGlobalState {\n        uint rateAccumulator;   \n        uint lastAccrual;       \n        uint totalScaledDebt;   \n    }\n\n\n    struct Vault {\n        uint collateral;  \n        uint scaledDebt;  \n    }\n\n    mapping(address => CollateralConfig) public record collateralConfigs;\n    mapping(address => CollateralGlobalState) public record collateralGlobalStates;\n    mapping(address => mapping(address => Vault)) public record vaults; \n\n    bool public globalPaused;\n    uint public RAY = 1e27;\n    uint public WAD = 1e18;\n    mapping(address => bool) public record isSupportedAsset;\n\n    uint256 public feeToReserveBps; \n\n\n    event FeeToReserveBpsSet(uint256 oldBps, uint256 newBps);\n    event FeesRouted(address indexed asset, uint256 toReserve, uint256 toCollector);\n\n\n\n    event CollateralConfigured(\n        address indexed asset,\n        uint liquidationRatio,\n        uint minCR,\n        uint liquidationPenaltyBps,\n        uint closeFactorBps,\n        uint stabilityFeeRate,\n        uint debtFloor,\n        uint debtCeiling,\n        uint unitScale,\n        bool pause\n    );\n\n    event Accrued(\n        address indexed asset,\n        uint oldRate,\n        uint newRate,\n        uint deltaTime,\n        uint totalScaledDebt\n    );\n\n    event Deposited(address indexed owner, address indexed asset, uint amount);\n    event Withdrawn(address indexed owner, address indexed asset, uint amount);\n\n    event USDSTMinted(\n        address indexed owner,\n        address indexed asset,\n        uint amountUSD,\n        uint totalScaledDebt,\n        uint rateAccumulator\n    );\n\n    event USDSTBurned(\n        address indexed owner,\n        address indexed asset,\n        uint amountUSD,\n        uint totalScaledDebt,\n        uint rateAccumulator\n    );\n\n    event LiquidationExecuted(\n        address indexed borrower,\n        address indexed asset,\n        uint debtBurnedUSD,\n        uint penaltyUSD,\n        uint collateralOut,\n        address indexed liquidator,\n        uint remainingDebtUSD,\n        uint rateAccumulator\n    );\n    event Paused(address indexed asset, bool isPaused);\n    event PausedGlobal(bool isPaused);\n    event JuniorParamsSet(uint premiumBps, uint sliceBps);\n\n    event VaultUpdated(\n        address indexed user,\n        address indexed asset,\n        uint collateral,\n        uint scaledDebt\n    );\n\n    event RegistryUpdated(address indexed oldRegistry, address indexed newRegistry);\n\n\n    function _cdpVault() internal view returns (CDPVault) { return registry.cdpVault(); }\n    function _cdpPriceOracle() internal view returns (PriceOracle) { return registry.priceOracle(); }\n    function _usdst() internal view returns (Token) { return Token(address(registry.usdst())); }\n    function _tokenFactory() internal view returns (TokenFactory) { return TokenFactory(address(registry.tokenFactory())); }\n    function _feeCollector() internal view returns (FeeCollector) { return FeeCollector(address(registry.feeCollector())); }\n    function _cdpReserve() internal view returns (CDPReserve) { return registry.cdpReserve(); }\n\n\n    modifier whenNotPaused(address asset) {\n        require(!globalPaused, "CDPEngine: global pause");\n        require(!collateralConfigs[asset].isPaused, "CDPEngine: asset paused");\n        _;\n    }\n\n    modifier onlyKnownAsset(address asset) {\n        require(isSupportedAsset[asset], "unsupported"); _;\n    }\n\n    modifier onlyActiveAsset(address asset) {\n        require(isSupportedAsset[asset], "unsupported");\n        require(_tokenFactory().isTokenActive(asset), "inactive");\n        _;\n    }\n\n\n    constructor(address initialOwner) Ownable(initialOwner) { }\n\n    function initialize(address _registry) external onlyOwner {\n\n        RAY = 1e27;\n        WAD = 1e18;\n\n\n        require(_registry != address(0), "CDPEngine: invalid registry");\n        registry = CDPRegistry(_registry);\n    }\n\n    \n    function setRegistry(address _registry) external onlyOwner {\n        require(_registry != address(0), "CDPEngine: invalid registry");\n        address old = address(registry);\n        registry = CDPRegistry(_registry);\n        emit RegistryUpdated(old, _registry);\n    }\n\n    function setFeeToReserveBps(uint256 newBps) external onlyOwner {\n        require(newBps <= 10000, "fee bps > 10000");\n        uint256 old = feeToReserveBps;\n        feeToReserveBps = newBps;\n        emit FeeToReserveBpsSet(old, newBps);\n    }\n\n\n\n\n\n\n\n    \n    function _routeFees(address asset, uint256 feeUSD) internal {\n        if (feeUSD > 0) {\n\n            uint256 toReserve   = (feeUSD * feeToReserveBps) / 10000;\n            uint256 toCollector = feeUSD - toReserve;\n\n            if (toReserve > 0) Token(_usdst()).mint(address(_cdpReserve()), toReserve);\n            if (toCollector > 0) Token(_usdst()).mint(address(_feeCollector()), toCollector);\n\n            emit FeesRouted(asset, toReserve, toCollector);\n        }\n    }\n\n\n    \n    function deposit(address asset, uint amount) external onlyActiveAsset(asset) {\n        require(amount > 0, "CDPEngine: Invalid amount");\n\n        _cdpVault().deposit(msg.sender, asset, amount);\n        vaults[msg.sender][asset].collateral += amount;\n        emit Deposited(msg.sender, asset, amount);\n        emit VaultUpdated(msg.sender, asset, vaults[msg.sender][asset].collateral, vaults[msg.sender][asset].scaledDebt);\n    }\n\n    \n    function withdraw(address asset, uint amount) external onlyKnownAsset(asset) whenNotPaused(asset) {\n        require(amount > 0, "CDPEngine: Invalid amount");\n        Vault storage vault = vaults[msg.sender][asset];\n        require(vault.collateral >= amount, "CDPEngine: Insufficient collateral");\n\n        _accrue(asset);\n\n        vault.collateral -= amount;\n        if (vault.scaledDebt > 0) {\n            uint crAfter = collateralizationRatio(msg.sender, asset);\n            require(crAfter >= collateralConfigs[asset].minCR, "CDPEngine: below min CR");\n        }\n\n        _cdpVault().withdraw(msg.sender, asset, amount);\n        emit Withdrawn(msg.sender, asset, amount);\n        emit VaultUpdated(msg.sender, asset, vault.collateral, vault.scaledDebt);\n    }\n\n    \n    function withdrawMax(address asset) external onlyKnownAsset(asset) whenNotPaused(asset) returns (uint maxAmount) {\n\n        _accrue(asset);\n        Vault storage vault = vaults[msg.sender][asset];\n        uint debt = (vault.scaledDebt * collateralGlobalStates[asset].rateAccumulator) / RAY;\n        if (debt == 0) {\n\n            maxAmount = vault.collateral;\n        } else {\n\n            (uint price, uint timestamp) = _cdpPriceOracle().getAssetPriceWithTimestamp(asset);\n            require(price > 0, "invalid price");\n\n            CollateralConfig memory config = collateralConfigs[asset];\n            uint requiredCollateralValue = (debt * config.minCR) / WAD;\n            uint requiredCollateral = (requiredCollateralValue * config.unitScale) / price;\n\n            if (vault.collateral <= requiredCollateral + 1) {\n                maxAmount = 0; \n            } else {\n                maxAmount = vault.collateral - requiredCollateral - 1;\n            }\n        }\n        if (maxAmount > 0) {\n\n            vault.collateral -= maxAmount;\n            _cdpVault().withdraw(msg.sender, asset, maxAmount);\n            emit Withdrawn(msg.sender, asset, maxAmount);\n            emit VaultUpdated(msg.sender, asset, vault.collateral, vault.scaledDebt);\n        }\n    }\n\n    \n    function mint(address asset, uint amountUSD) external whenNotPaused(asset) onlyActiveAsset(asset) {\n\n        _accrue(asset);\n        require(amountUSD > 0, "CDPEngine: zero amount");\n\n        CollateralConfig memory assetConfig = collateralConfigs[asset];\n        CollateralGlobalState storage assetState = collateralGlobalStates[asset];\n        Vault storage userVault = vaults[msg.sender][asset];\n\n        uint currentDebt = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n\n        (uint price, uint timestamp) = _cdpPriceOracle().getAssetPriceWithTimestamp(asset);\n        require(price > 0, "invalid price");\n\n        uint collateralValueUSD_calc = (userVault.collateral * price) / assetConfig.unitScale;\n        uint maxBorrowableUSD = (collateralValueUSD_calc * WAD) / assetConfig.minCR;\n        require(currentDebt + amountUSD < maxBorrowableUSD, "CDPEngine: insufficient collateral");\n\n        if (assetConfig.debtCeiling > 0) {\n            uint assetDebtUSD = (assetState.totalScaledDebt * assetState.rateAccumulator) / RAY;\n            require(assetDebtUSD + amountUSD <= assetConfig.debtCeiling, "CDPEngine: debt ceiling exceeded");\n        }\n\n        uint scaledAdd = (amountUSD * RAY + assetState.rateAccumulator - 1) / assetState.rateAccumulator;\n        userVault.scaledDebt += scaledAdd;\n        assetState.totalScaledDebt += scaledAdd;\n\n        uint totalDebtAfter = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n        if (assetConfig.debtFloor > 0) {\n            require(totalDebtAfter >= assetConfig.debtFloor, "CDPEngine: below debt floor");\n        }\n\n        Token(_usdst()).mint(msg.sender, amountUSD);\n        emit USDSTMinted(msg.sender, asset, amountUSD, assetState.totalScaledDebt, assetState.rateAccumulator);\n        emit VaultUpdated(msg.sender, asset, userVault.collateral, userVault.scaledDebt);\n    }\n\n    \n    function mintMax(address asset) external whenNotPaused(asset) onlyActiveAsset(asset) returns (uint amountMinted) {\n\n        _accrue(asset);\n        CollateralConfig memory config = collateralConfigs[asset];\n        CollateralGlobalState storage assetState = collateralGlobalStates[asset];\n        Vault storage userVault = vaults[msg.sender][asset];\n\n        uint currentDebt = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n\n        (uint price, uint timestamp) = _cdpPriceOracle().getAssetPriceWithTimestamp(asset);\n        require(price > 0, "invalid price");\n\n        uint collateralValueUSD_calc = (userVault.collateral * price) / config.unitScale;\n        uint maxBorrowableUSD = (collateralValueUSD_calc * WAD) / config.minCR;\n        require(maxBorrowableUSD > currentDebt, "No borrowing power");\n        uint available = maxBorrowableUSD - currentDebt;\n\n        amountMinted = available > 1 ? (available - 1) : 0; \n        require(amountMinted > 0, "No borrowing power");\n\n        if (config.debtCeiling > 0) {\n            uint assetDebtUSD = (assetState.totalScaledDebt * assetState.rateAccumulator) / RAY;\n            require(assetDebtUSD + amountMinted <= config.debtCeiling, "CDPEngine: debt ceiling exceeded");\n        }\n\n        uint scaledAdd = (amountMinted * RAY + assetState.rateAccumulator - 1) / assetState.rateAccumulator;\n        userVault.scaledDebt += scaledAdd;\n        assetState.totalScaledDebt += scaledAdd;\n\n        uint totalDebtAfter = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n        if (config.debtFloor > 0) {\n            require(totalDebtAfter >= config.debtFloor, "CDPEngine: below debt floor");\n        }\n\n        Token(_usdst()).mint(msg.sender, amountMinted);\n        emit USDSTMinted(msg.sender, asset, amountMinted, assetState.totalScaledDebt, assetState.rateAccumulator);\n        emit VaultUpdated(msg.sender, asset, userVault.collateral, userVault.scaledDebt);\n    }\n\n    function repay(address asset, uint amountUSD) external onlyKnownAsset(asset) {\n        _accrue(asset);\n        require(amountUSD > 0, "CDPEngine: zero amount");\n\n        CollateralConfig memory config = collateralConfigs[asset];\n        CollateralGlobalState storage assetState = collateralGlobalStates[asset];\n        Vault storage userVault = vaults[msg.sender][asset];\n\n        uint owed = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n        require(owed > 0, "CDPEngine: no debt");\n\n\n        uint repayAmount = amountUSD > owed ? owed : amountUSD;\n        uint scaledDelta = (repayAmount * RAY) / assetState.rateAccumulator;\n        if (scaledDelta > userVault.scaledDebt) scaledDelta = userVault.scaledDebt;\n\n\n        uint newScaledDebt = userVault.scaledDebt - scaledDelta;\n        uint owedAfterPreview = (newScaledDebt * assetState.rateAccumulator) / RAY;\n        if (owedAfterPreview > 1 && config.debtFloor > 0 && owedAfterPreview < config.debtFloor) {\n            revert("CDPEngine: repay leaves debt below floor; use repayAll");\n        }\n\n\n        uint owedForDelta = (scaledDelta * assetState.rateAccumulator) / RAY;\n        uint baseUSD = scaledDelta;\n        uint feeUSD  = owedForDelta > baseUSD ? (owedForDelta - baseUSD) : 0;\n\n        Token(_usdst()).burn(msg.sender, owedForDelta);\n\n\n        _routeFees(asset, feeUSD);\n\n        userVault.scaledDebt = newScaledDebt;\n        assetState.totalScaledDebt -= scaledDelta;\n\n\n        if (owedAfterPreview <= 1) {\n            if (userVault.scaledDebt > 0) {\n                assetState.totalScaledDebt -= userVault.scaledDebt;\n                userVault.scaledDebt = 0;\n            }\n        }\n\n        emit USDSTBurned(msg.sender, asset, owedForDelta, assetState.totalScaledDebt, assetState.rateAccumulator);\n        emit VaultUpdated(msg.sender, asset, userVault.collateral, userVault.scaledDebt);\n    }\n\n    \n    function repayAll(address asset) external onlyKnownAsset(asset) {\n\n        _accrue(asset);\n        CollateralGlobalState storage assetState = collateralGlobalStates[asset];\n        Vault storage userVault = vaults[msg.sender][asset];\n        require(userVault.scaledDebt > 0, "CDPEngine: no debt");\n\n        uint owed = (userVault.scaledDebt * assetState.rateAccumulator) / RAY;\n        uint scaledDebtToRemove = userVault.scaledDebt;\n\n        Token(_usdst()).burn(msg.sender, owed);\n\n        uint baseUSD = scaledDebtToRemove; \n        uint feeUSD = owed > baseUSD ? (owed - baseUSD) : 0;\n\n\n        _routeFees(asset, feeUSD);\n\n        userVault.scaledDebt = 0;\n        assetState.totalScaledDebt -= scaledDebtToRemove;\n\n        emit USDSTBurned(msg.sender, asset, owed, assetState.totalScaledDebt, assetState.rateAccumulator);\n        emit VaultUpdated(msg.sender, asset, userVault.collateral, userVault.scaledDebt);\n    }\n\n    \n    function liquidate(\n        address collateralAsset,\n        address borrower,\n        uint debtToCover\n    ) external onlyKnownAsset(collateralAsset) whenNotPaused(collateralAsset) {\n        require(borrower != address(0) && borrower != msg.sender, "CDPEngine: invalid borrower");\n        require(debtToCover > 0, "CDPEngine: zero debt amount");\n\n        _accrue(collateralAsset);\n\n        CollateralConfig memory config = collateralConfigs[collateralAsset];\n        CollateralGlobalState storage assetState = collateralGlobalStates[collateralAsset];\n        Vault storage borrowerVault = vaults[borrower][collateralAsset];\n        require(borrowerVault.scaledDebt > 0, "CDPEngine: no debt to liquidate");\n\n        uint borrowerCR = collateralizationRatio(borrower, collateralAsset);\n        require(borrowerCR < config.liquidationRatio, "CDPEngine: position healthy");\n\n\n        (uint priceCollWei, uint timestamp) = _cdpPriceOracle().getAssetPriceWithTimestamp(collateralAsset);\n        require(priceCollWei > 0, "CDPEngine: invalid collateral price");\n\n\n        uint totalDebtWei   = (borrowerVault.scaledDebt * assetState.rateAccumulator) / RAY;\n        uint closeFactorCap = (totalDebtWei * config.closeFactorBps) / 10000;\n\n        uint collateralWei = (borrowerVault.collateral * priceCollWei) / config.unitScale;\n\n\n        uint coverageCap = (collateralWei * 10000) / (10000 + config.liquidationPenaltyBps);\n\n\n        bool capBinds = false;\n        uint repay = debtToCover;\n        if (repay > totalDebtWei)   repay = totalDebtWei;\n        if (repay > closeFactorCap) repay = closeFactorCap;\n        if (repay >= coverageCap) { repay = coverageCap; capBinds = true; }\n        require(repay > 0, "CDPEngine: nothing to liquidate");\n\n        uint collateralToSeize = 0;\n        uint penaltyWei = 0;\n\n\n        uint scaledDebtToLiquidate = (repay * RAY) / assetState.rateAccumulator;\n        if (scaledDebtToLiquidate > borrowerVault.scaledDebt) {\n            scaledDebtToLiquidate = borrowerVault.scaledDebt;\n        }\n        uint owedForDelta = (scaledDebtToLiquidate * assetState.rateAccumulator) / RAY;\n\n\n        Token(_usdst()).burn(msg.sender, owedForDelta);\n\n        uint feeWei = owedForDelta > scaledDebtToLiquidate ? (owedForDelta - scaledDebtToLiquidate) : 0;\n        if (feeWei > 0) _routeFees(collateralAsset, feeWei);\n\n        borrowerVault.scaledDebt   -= scaledDebtToLiquidate;\n        assetState.totalScaledDebt -= scaledDebtToLiquidate;\n\n        if (capBinds) {\n            collateralToSeize = borrowerVault.collateral;\n            uint collateralUSD = (collateralToSeize * priceCollWei) / config.unitScale;\n            penaltyWei = collateralUSD > owedForDelta ? (collateralUSD - owedForDelta) : 0;\n        } else {\n            penaltyWei = (owedForDelta * config.liquidationPenaltyBps) / 10000;\n            uint debtWithPenaltyWei = owedForDelta + penaltyWei;\n            collateralToSeize = (debtWithPenaltyWei * config.unitScale) / priceCollWei;\n            if (collateralToSeize > borrowerVault.collateral) {\n                collateralToSeize = borrowerVault.collateral;\n            }\n        }\n\n        borrowerVault.collateral -= collateralToSeize;\n        _cdpVault().seize(borrower, collateralAsset, msg.sender, collateralToSeize);\n\n        uint finalDebtWei = (borrowerVault.scaledDebt * assetState.rateAccumulator) / RAY;\n\n        if (borrowerVault.collateral == 0) {\n            uint rem = (borrowerVault.scaledDebt * assetState.rateAccumulator) / RAY;\n            if (rem > 1) {\n                assetState.totalScaledDebt -= borrowerVault.scaledDebt;\n                borrowerVault.scaledDebt = 0;\n                badDebtUSDST[collateralAsset] += rem;\n                emit BadDebtRealized(collateralAsset, borrower, rem);\n            }\n        }\n\n        emit LiquidationExecuted(\n            borrower,\n            collateralAsset,\n            owedForDelta,\n            penaltyWei,\n            collateralToSeize,\n            msg.sender,\n            finalDebtWei,\n            assetState.rateAccumulator\n        );\n\n        emit VaultUpdated(borrower, collateralAsset, borrowerVault.collateral, borrowerVault.scaledDebt);\n    }\n\n\n    \n    function _accrue(address asset) internal {\n\n        CollateralConfig memory assetConfig = collateralConfigs[asset];\n        CollateralGlobalState storage assetState = collateralGlobalStates[asset];\n        if (assetState.lastAccrual == 0) {\n            assetState.lastAccrual = block.timestamp;\n            assetState.rateAccumulator = RAY;\n            return;\n        }\n        uint dt = block.timestamp - assetState.lastAccrual; if (dt == 0) return;\n        uint oldRate = assetState.rateAccumulator;\n\n        uint factor = _rpow(assetConfig.stabilityFeeRate, dt, RAY);\n\n        uint newRate = (oldRate * factor) / RAY; if (newRate < RAY) { newRate = RAY; }\n\n        assetState.rateAccumulator = newRate; assetState.lastAccrual = block.timestamp;\n        emit Accrued(asset, oldRate, assetState.rateAccumulator, dt, assetState.totalScaledDebt);\n    }\n\n    \n    function setCollateralAssetParams(\n        address asset,\n        uint liquidationRatio,\n        uint minCR,\n        uint liquidationPenaltyBps,\n        uint closeFactorBps,\n        uint stabilityFeeRate,\n        uint debtFloor,\n        uint debtCeiling,\n        uint unitScale,\n        bool pause\n    ) public onlyOwner {\n        require(asset != address(0), "CDPEngine: invalid asset");\n        require(liquidationRatio >= WAD, "CDPEngine: LR too low");\n        require(minCR >= liquidationRatio, "CDPEngine: minCR < LR");\n        require(liquidationPenaltyBps >= 500 && liquidationPenaltyBps <= 3000, "penalty out of range");\n        require(closeFactorBps >= 5000 && closeFactorBps <= 10000, "CDPEngine: close factor out of range");\n        require(stabilityFeeRate >= RAY, "CDPEngine: stability fee too low");\n        require(unitScale > 0, "CDPEngine: invalid unit scale");\n        if (debtCeiling > 0) { require(debtFloor <= debtCeiling, "CDPEngine: debt floor above ceiling"); }\n\n        CollateralConfig storage config = collateralConfigs[asset];\n        config.liquidationRatio = liquidationRatio;\n        config.minCR = minCR;\n        config.liquidationPenaltyBps = liquidationPenaltyBps;\n        config.closeFactorBps = closeFactorBps;\n        config.stabilityFeeRate = stabilityFeeRate;\n        config.debtFloor = debtFloor;\n        config.debtCeiling = debtCeiling;\n        config.unitScale = unitScale;\n        config.isPaused = pause;\n\n        if (!isSupportedAsset[asset]) { isSupportedAsset[asset] = true; }\n\n        emit CollateralConfigured(\n            asset,\n            liquidationRatio,\n            minCR,\n            liquidationPenaltyBps,\n            closeFactorBps,\n            stabilityFeeRate,\n            debtFloor,\n            debtCeiling,\n            unitScale,\n            pause\n        );\n    }\n\n    \n    function setCollateralAssetParamsBatch(\n        address[] calldata assets,\n        uint[] calldata liquidationRatios,\n        uint[] calldata minCRs,\n        uint[] calldata liquidationPenaltyBpsArr,\n        uint[] calldata closeFactorBpsArr,\n        uint[] calldata stabilityFeeRates,\n        uint[] calldata debtFloors,\n        uint[] calldata debtCeilings,\n        uint[] calldata unitScales,\n        bool[] calldata pauses\n    ) external onlyOwner {\n        uint len = assets.length;\n        require(len > 0, "CDPEngine: empty batch");\n        require(\n            liquidationRatios.length == len &&\n            minCRs.length == len &&\n            liquidationPenaltyBpsArr.length == len &&\n            closeFactorBpsArr.length == len &&\n            stabilityFeeRates.length == len &&\n            debtFloors.length == len &&\n            debtCeilings.length == len &&\n            unitScales.length == len &&\n            pauses.length == len,\n            "CDPEngine: array length mismatch"\n        );\n        for (uint i = 0; i < len; i++) {\n            setCollateralAssetParams(\n                assets[i],\n                liquidationRatios[i],\n                minCRs[i],\n                liquidationPenaltyBpsArr[i],\n                closeFactorBpsArr[i],\n                stabilityFeeRates[i],\n                debtFloors[i],\n                debtCeilings[i],\n                unitScales[i],\n                pauses[i]\n            );\n        }\n    }\n\n    \n    function setPaused(address asset, bool isPaused) external onlyOwner {\n        require(isSupportedAsset[asset], "CDPEngine: unsupported asset");\n        collateralConfigs[asset].isPaused = isPaused;\n        emit Paused(asset, isPaused);\n    }\n\n    \n    function setPausedGlobal(bool isPaused) external onlyOwner {\n        globalPaused = isPaused;\n        emit PausedGlobal(isPaused);\n    }\n\n    \n\n\n\n    function setSupportedAsset(address asset, bool supported) external onlyOwner {\n        require(asset != address(0), "CDPEngine: invalid asset");\n        isSupportedAsset[asset] = supported;\n    }\n\n    \n    function _rpow(uint x, uint n, uint base) internal pure returns (uint z) {\n        if (x == 0) return n == 0 ? base : 0;\n        z = (n % 2 == 0) ? base : x;\n        uint half = base / 2;\n        for (n /= 2; n > 0; n /= 2) {\n            uint xx = x * x;\n            x = (xx + half) / base; \n            if (n % 2 == 1) {\n                uint zx = z * x;\n                z = (zx + half) / base; \n            }\n        }\n        return z;\n    }\n\n    \n\n\n\n    function collateralizationRatio(address user, address asset) public view returns (uint crWad) {\n        CollateralGlobalState storage s = collateralGlobalStates[asset];\n        Vault storage v = vaults[user][asset];\n        uint debtUSD = (v.scaledDebt * s.rateAccumulator) / RAY;\n        if (debtUSD == 0) return (2**256 - 1);\n        (uint price, uint timestamp) = _cdpPriceOracle().getAssetPriceWithTimestamp(asset);\n        require(price > 0, "invalid price");\n\n        uint unitScale = collateralConfigs[asset].unitScale;\n        uint collateralUSD = unitScale == 0 ? 0 : (v.collateral * price) / unitScale;\n        return (collateralUSD * WAD) / debtUSD;\n    }\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n    mapping(address => uint) public record badDebtUSDST; \n    uint256 public juniorPremiumBps;   \n\n\n\n    uint256 public juniorIndex;                   \n    uint256 public totalJuniorOutstandingUSDST;   \n    uint256 private prevReserveBalance;          \n\n    struct JuniorNote {\n        address owner;\n        uint256 capUSDST;     \n        uint256 entryIndex;   \n    }\n\n    mapping(address => JuniorNote) public record juniorNotes;\n\n\n\n\n    event BadDebtRealized(address indexed asset, address indexed borrower, uint amountUSDST);\n    event BadDebtRepaid(address indexed asset, uint amountUSDST, uint badDebtRemaining);\n    event JuniorNoteCreated(address indexed owner, uint256 capUSDST);\n    event JuniorNoteClosed(address indexed owner);\n    event JuniorNoteClaimed(address indexed owner, uint256 paidUSDST, uint256 remainingUSDST);\n\n\n\n    event JuniorIndexSynced(\n        uint256 deltaUSDST,         \n        uint256 outstandingUSDST,   \n        uint256 deltaIndexRay,      \n        uint256 progressWad,        \n        uint256 newJuniorIndexRay,  \n        uint256 timestamp           \n    );\n\n\n\n\n\n    function setJuniorPremium(uint256 newPremiumBps) external onlyOwner {\n        require(newPremiumBps <= 10000, "junior: premium > 100%");\n        juniorPremiumBps = newPremiumBps;\n        emit JuniorParamsSet(newPremiumBps, 0);\n    }\n\n\n\n\n\n\n    function _syncReserveToIndex() internal {\n        if (juniorIndex == 0) juniorIndex = 1e27;\n\n        address reserveAddr = address(registry.cdpReserve());\n        uint256 reserveBal = _usdst().balanceOf(reserveAddr);\n\n\n        if (reserveBal <= prevReserveBalance) return;\n\n        uint256 deltaUSDST = reserveBal - prevReserveBalance;\n        if (deltaUSDST == 0) {\n            prevReserveBalance = reserveBal; \n            return;\n        }\n\n        uint256 outstanding = totalJuniorOutstandingUSDST;\n\n\n        if (outstanding == 0) {\n            prevReserveBalance = reserveBal;\n            return;\n        }\n\n\n        uint256 deltaIndex = (deltaUSDST * RAY) / outstanding;  \n        uint256 newIndex = juniorIndex + deltaIndex;\n\n\n\n        uint256 progressWad = deltaIndex / (RAY / WAD); \n\n\n        juniorIndex = newIndex;\n        prevReserveBalance = reserveBal;\n\n        emit JuniorIndexSynced(\n            deltaUSDST,\n            outstanding,\n            deltaIndex,\n            progressWad,\n            newIndex,\n            block.timestamp\n        );\n    }\n\n    \n    function openJuniorNote(address asset, uint256 amountUSDST)\n        external\n        onlyKnownAsset(asset)\n        returns (uint256 burnedUSDST, uint256 capUSDST)\n    {\n        require(amountUSDST > 0, "junior: zero amount");\n\n        uint256 bad = badDebtUSDST[asset];\n        require(bad > 0, "junior: no bad debt for asset");\n\n\n        burnedUSDST = amountUSDST > bad ? bad : amountUSDST;\n        Token(_usdst()).burn(msg.sender, burnedUSDST);\n        badDebtUSDST[asset] = bad - burnedUSDST;\n        emit BadDebtRepaid(asset, burnedUSDST, badDebtUSDST[asset]);\n\n\n        capUSDST = (burnedUSDST * (10000 + juniorPremiumBps)) / 10000;\n\n\n        _syncReserveToIndex();\n        if (juniorIndex == 0) juniorIndex = 1e27;\n\n\n        JuniorNote storage note = juniorNotes[msg.sender];\n        if (note.owner == address(0)) {\n\n            juniorNotes[msg.sender] = JuniorNote(msg.sender, capUSDST, juniorIndex);\n            totalJuniorOutstandingUSDST += capUSDST;\n            emit JuniorNoteCreated(msg.sender, capUSDST);\n        } else {\n\n            uint256 oldCap = note.capUSDST;\n            uint256 oldEntry = note.entryIndex;\n            uint256 newCap = oldCap + capUSDST;\n\n\n            uint256 blendedEntry = juniorIndex;\n            if (juniorIndex > oldEntry) {\n                uint256 indexGrowth = juniorIndex - oldEntry;\n                uint256 adjustment = (oldCap * indexGrowth) / newCap;\n                blendedEntry = juniorIndex - adjustment;\n            }\n\n            note.capUSDST = newCap;\n            note.entryIndex = blendedEntry;\n            totalJuniorOutstandingUSDST += capUSDST;\n\n            emit JuniorNoteCreated(msg.sender, newCap);\n        }\n    }\n\n\n    function _entitlement(JuniorNote storage note, uint256 idx) internal view returns (uint256) {\n        if (note.owner == address(0)) return 0;\n        if (note.capUSDST == 0) return 0;\n        if (idx == 0) idx = 1e27;\n\n        uint256 last = note.entryIndex;\n        if (idx <= last) return 0;\n\n\n        uint256 ent = (note.capUSDST * (idx - last)) / 1e27;  \n        if (ent > note.capUSDST) ent = note.capUSDST;  \n        return ent;\n    }\n\n\n\n    function claimable(address owner) public view returns (uint256) {\n        JuniorNote storage note = juniorNotes[owner];\n\n\n        uint256 effectiveIndex = juniorIndex == 0 ? 1e27 : juniorIndex;\n        address reserveAddr = address(registry.cdpReserve());\n        uint256 reserveBalance = _usdst().balanceOf(reserveAddr);\n\n        if (reserveBalance > prevReserveBalance && totalJuniorOutstandingUSDST > 0) {\n            uint256 newInflows = reserveBalance - prevReserveBalance;\n            uint256 indexBump = (newInflows * 1e27) / totalJuniorOutstandingUSDST;\n            effectiveIndex += indexBump;\n        }\n\n        return _entitlement(note, effectiveIndex);\n    }\n\n    function claimJunior() external {\n        require(!globalPaused, "CDPEngine: global pause");\n        _syncReserveToIndex();\n        JuniorNote storage note = juniorNotes[msg.sender];\n        require(note.owner != address(0), "junior: no note");\n\n        uint256 currentIndex = juniorIndex;\n        uint256 currentCap = note.capUSDST;\n\n        uint256 entitlement = _entitlement(note, currentIndex);\n        require(entitlement > 0, "junior: nothing to claim");\n\n        address reserveAddr = address(registry.cdpReserve());\n        uint256 reserveBalance = _usdst().balanceOf(reserveAddr);\n        require(reserveBalance > 0, "junior: reserve empty");\n\n        uint256 payAmount = entitlement <= reserveBalance ? entitlement : reserveBalance;\n        uint256 unpaidAmount = entitlement - payAmount;\n        uint256 newCap = currentCap - payAmount;\n\n\n        if (newCap == 0) {\n            totalJuniorOutstandingUSDST -= payAmount;\n            prevReserveBalance -= payAmount;\n            delete juniorNotes[msg.sender].owner;\n            delete juniorNotes[msg.sender].capUSDST;\n            delete juniorNotes[msg.sender].entryIndex;\n            emit JuniorNoteClaimed(msg.sender, payAmount, 0);\n            emit JuniorNoteClosed(msg.sender);\n        } else {\n\n            uint256 indexAdjustment = (unpaidAmount == 0) ? 0 : (unpaidAmount * 1e27) / newCap;\n            uint256 newEntryIndex = currentIndex - indexAdjustment;\n\n            note.capUSDST = newCap;\n            note.entryIndex = newEntryIndex;\n\n            totalJuniorOutstandingUSDST -= payAmount;\n            prevReserveBalance -= payAmount;\n\n            emit JuniorNoteClaimed(msg.sender, payAmount, newCap);\n        }\n\n\n        CDPReserve(address(registry.cdpReserve())).transferTo(msg.sender, payAmount);\n    }\n\n}\n\n// SPDX-License-Identifier: MIT\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record CDPRegistry is Ownable {\n  CDPVault public cdpVault;\n  CDPEngine public cdpEngine;\n  PriceOracle public priceOracle;\n\n\n  Token public usdst;\n  TokenFactory public tokenFactory;\n  FeeCollector public feeCollector;\n  CDPReserve public cdpReserve;\n\n  event ComponentsUpdated(\n    address indexed cdpVault,\n    address indexed cdpEngine,\n    address indexed priceOracle,\n    address usdst,\n    address tokenFactory,\n    address feeCollector,\n    address cdpReserve\n  );\n\n  constructor(address initialOwner) Ownable(initialOwner) {}\n\n  function setAllComponents(\n    address _cdpVault,\n    address _cdpEngine,\n    address _priceOracle,\n    address _usdst,\n    address _tokenFactory,\n    address _feeCollector,\n    address _cdpReserve\n  ) external onlyOwner {\n    require(_cdpVault != address(0), "Invalid cdpVault");\n    require(_cdpEngine != address(0), "Invalid cdpEngine");\n    require(_priceOracle != address(0), "Invalid priceOracle");\n    require(_usdst != address(0), "Invalid USDST");\n    require(_tokenFactory != address(0), "Invalid tokenFactory");\n    require(_feeCollector != address(0), "Invalid feeCollector");\n    require(_cdpReserve != address(0), "Invalid cdpReserve");\n\n    cdpVault = CDPVault(_cdpVault);\n    cdpEngine = CDPEngine(_cdpEngine);\n    priceOracle = PriceOracle(_priceOracle);\n    usdst = Token(_usdst);\n    tokenFactory = TokenFactory(_tokenFactory);\n    feeCollector = FeeCollector(_feeCollector);\n    cdpReserve = CDPReserve(_cdpReserve);\n\n    emit ComponentsUpdated(\n      _cdpVault, _cdpEngine, _priceOracle, _usdst, _tokenFactory, _feeCollector, _cdpReserve\n    );\n  }\n\n\n\n  function setCDPVault(address _cdpVault) external onlyOwner {\n    require(_cdpVault != address(0), "Invalid address");\n    cdpVault = CDPVault(_cdpVault);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setCDPEngine(address _cdpEngine) external onlyOwner {\n    require(_cdpEngine != address(0), "Invalid address");\n    cdpEngine = CDPEngine(_cdpEngine);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setPriceOracle(address _priceOracle) external onlyOwner {\n    require(_priceOracle != address(0), "Invalid address");\n    priceOracle = PriceOracle(_priceOracle);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setUSDST(address _usdst) external onlyOwner {\n    require(_usdst != address(0), "Invalid address");\n    usdst = Token(_usdst);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setTokenFactory(address _tokenFactory) external onlyOwner {\n    require(_tokenFactory != address(0), "Invalid address");\n    tokenFactory = TokenFactory(_tokenFactory);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setFeeCollector(address _feeCollector) external onlyOwner {\n    require(_feeCollector != address(0), "Invalid address");\n    feeCollector = FeeCollector(_feeCollector);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function setCDPReserve(address _cdpReserve) external onlyOwner {\n    require(_cdpReserve != address(0), "Invalid address");\n    cdpReserve = CDPReserve(_cdpReserve);\n    emit ComponentsUpdated(address(cdpVault), address(cdpEngine), address(priceOracle),\n      address(usdst), address(tokenFactory), address(feeCollector), address(cdpReserve));\n  }\n\n  function getAllComponents() external view returns (\n    address, address, address, address, address, address, address\n  ) {\n    return (\n      address(cdpVault),\n      address(cdpEngine),\n      address(priceOracle),\n      address(usdst),\n      address(tokenFactory),\n      address(feeCollector),\n      address(cdpReserve)\n    );\n  }\n}\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\ncontract record Mercata is Authorizable {\n    RateStrategy public rateStrategy;\n    PriceOracle public priceOracle;\n    CollateralVault public collateralVault;\n    LiquidityPool public liquidityPool;\n    LendingPool public lendingPool;\n    PoolConfigurator public poolConfigurator;\n    LendingRegistry public lendingRegistry;\n    MercataBridge public mercataBridge;\n    PoolFactory public poolFactory;\n    TokenFactory public tokenFactory;\n    FeeCollector public feeCollector;\n    AdminRegistry public adminRegistry;\n    CDPEngine public cdpEngine;\n    CDPVault public cdpVault;\n    CDPRegistry public cdpRegistry;\n    CDPReserve public cdpReserve;\n    SafetyModule public safetyModule;\n    RewardsChef public rewardsChef;\n    Rewards public rewards;\n    Token public cataToken;\n\n    constructor() public {\n\n        address implOwnerIgnored = address("deadbeef");\n\n\n        address adminRegistryImpl = address(new AdminRegistry());\n        adminRegistry = AdminRegistry(address(new Proxy(adminRegistryImpl, this)));\n        adminRegistry.initialize([this]); \n        Ownable(address(adminRegistry)).transferOwnership(address(adminRegistry));\n\n\n        address feeCollectorImpl = address(new FeeCollector(implOwnerIgnored));\n        feeCollector = FeeCollector(address(new Proxy(feeCollectorImpl, this)));\n        Ownable(feeCollector).transferOwnership(address(adminRegistry));\n\n\n        address tokenFactoryImpl = address(new TokenFactory(implOwnerIgnored));\n        tokenFactory = TokenFactory(address(new Proxy(tokenFactoryImpl, this)));\n        Ownable(tokenFactory).transferOwnership(address(adminRegistry));\n\n        address poolFactoryImpl = address(new PoolFactory(implOwnerIgnored));\n        poolFactory = PoolFactory(address(new Proxy(poolFactoryImpl, this)));\n        poolFactory.initialize(address(tokenFactory), address(adminRegistry), address(feeCollector));\n        Ownable(poolFactory).transferOwnership(address(adminRegistry));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(tokenFactory), "createTokenWithInitialOwner", address(poolFactory));\n\n\n        address lendingRegistryImpl = address(new LendingRegistry(implOwnerIgnored));\n        lendingRegistry = LendingRegistry(address(new Proxy(lendingRegistryImpl, this)));\n        Ownable(lendingRegistry).transferOwnership(address(adminRegistry));\n\n        address collateralVaultImpl = address(new CollateralVault(implOwnerIgnored));\n        collateralVault = CollateralVault(address(new Proxy(collateralVaultImpl, this)));\n        collateralVault.initialize(address(lendingRegistry));\n        Ownable(collateralVault).transferOwnership(address(adminRegistry));\n\n        address liquidityPoolImpl = address(new LiquidityPool(implOwnerIgnored));\n        liquidityPool = LiquidityPool(address(new Proxy(liquidityPoolImpl, this)));\n        liquidityPool.initialize(address(lendingRegistry));\n        Ownable(liquidityPool).transferOwnership(address(adminRegistry));\n\n        address rateStrategyImpl = address(new RateStrategy());\n        rateStrategy = RateStrategy(address(new Proxy(rateStrategyImpl, this)));\n        Ownable(address(rateStrategy)).transferOwnership(address(adminRegistry));\n\n        address priceOracleImpl = address(new PriceOracle(implOwnerIgnored));\n        priceOracle = PriceOracle(address(new Proxy(priceOracleImpl, this)));\n        Ownable(priceOracle).transferOwnership(address(adminRegistry));\n\n        address poolConfiguratorImpl = address(new PoolConfigurator(implOwnerIgnored));\n        poolConfigurator = PoolConfigurator(address(new Proxy(poolConfiguratorImpl, this)));\n        poolConfigurator.initialize(address(lendingRegistry));\n        Ownable(poolConfigurator).transferOwnership(address(adminRegistry));\n\n        address safetyModuleImpl = address(new SafetyModule(implOwnerIgnored));\n        safetyModule = SafetyModule(address(new Proxy(safetyModuleImpl, this)));\n        safetyModule.initialize(address(lendingRegistry), address(tokenFactory));\n        Ownable(safetyModule).transferOwnership(address(adminRegistry));\n\n        address lendingPoolImpl = address(new LendingPool(implOwnerIgnored));\n        lendingPool = LendingPool(address(new Proxy(lendingPoolImpl, this)));\n        lendingPool.initialize(address(lendingRegistry), address(poolConfigurator), address(tokenFactory), address(feeCollector), address(safetyModule));\n        Ownable(lendingPool).transferOwnership(address(adminRegistry));\n\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setLendingPool", address(poolConfigurator));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setLiquidityPool", address(poolConfigurator));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setCollateralVault", address(poolConfigurator));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setRateStrategy", address(poolConfigurator));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setPriceOracle", address(poolConfigurator));\n        adminRegistry.castVoteOnIssue(address(adminRegistry), "addWhitelist", address(lendingRegistry), "setAllComponents", address(poolConfigurator));\n        authorizations[address(adminRegistry)][address(poolConfigurator)] = 1;\n        poolConfigurator.initializeProtocol(address(lendingPool),address(liquidityPool),address(collateralVault),address(rateStrategy),address(priceOracle),address(tokenFactory),[],[],[],[],[],[],[],0,0,1000);\n\n\n        address mercataBridgeImpl = address(new MercataBridge(implOwnerIgnored));\n        mercataBridge = MercataBridge(address(new Proxy(mercataBridgeImpl, this)));\n        mercataBridge.initialize(address(tokenFactory), address(lendingRegistry));\n        Ownable(mercataBridge).transferOwnership(address(adminRegistry));\n\n\n        address rewardsChefImpl = address(new RewardsChef(implOwnerIgnored));\n        rewardsChef = RewardsChef(address(new Proxy(rewardsChefImpl, this)));\n        Ownable(rewardsChef).transferOwnership(address(adminRegistry));\n\n\n        cataToken = Token(address(0x2680dc6693021cd3fefb84351570874fbef8332a));\n\n\n        address rewardsImpl = address(new Rewards(implOwnerIgnored));\n        rewards = Rewards(address(new Proxy(rewardsImpl, this)));\n        rewards.initialize(address(cataToken));\n        Ownable(rewards).transferOwnership(address(0x000000000000000000000000000000000000100c));\n\n\n        address cdpRegistryImpl = address(new CDPRegistry(implOwnerIgnored));\n        cdpRegistry = CDPRegistry(address(new Proxy(cdpRegistryImpl, this)));\n\n        address cdpVaultImpl = address(new CDPVault(implOwnerIgnored));\n        cdpVault = CDPVault(address(new Proxy(cdpVaultImpl, this)));\n        cdpVault.initialize(address(cdpRegistry));\n        Ownable(cdpVault).transferOwnership(address(adminRegistry));\n\n        address cdpEngineImpl = address(new CDPEngine(implOwnerIgnored));\n        cdpEngine = CDPEngine(address(new Proxy(cdpEngineImpl, this)));\n        cdpEngine.initialize(address(cdpRegistry));\n        Ownable(cdpEngine).transferOwnership(address(adminRegistry));\n\n        address cdpReserveImpl = address(new CDPReserve(implOwnerIgnored));\n        cdpReserve = CDPReserve(address(new Proxy(cdpReserveImpl, this)));\n        cdpReserve.initialize(address(cdpRegistry));\n        Ownable(cdpReserve).transferOwnership(address(adminRegistry));\n\n        cdpRegistry.setAllComponents(address(cdpVault), address(cdpEngine), address(priceOracle), address(0x937efa7e3a77e20bbdbd7c0d32b6514f368c1010), address(tokenFactory), address(feeCollector), address(cdpReserve));\n        Ownable(cdpRegistry).transferOwnership(address(adminRegistry));\n\n        adminRegistry.swapAdmin(this, msg.sender);\n    }\n}\n\n'

# Split the ORIGINAL content into chunks first
chunk_size = 250
chunks = []
for i in range(0, len(s), chunk_size):
    chunk = s[i:i+chunk_size]
    chunks.append(chunk)

# Now escape each chunk separately with json.dumps()
escaped_chunks = [json.dumps(chunk) for chunk in chunks]

# Join with " + " and format across multiple lines
# concatenated = ' +\n        '.join(escaped_chunks)
# concatenated = ' + '.join(escaped_chunks)
concatenated = '\n        + '.join(escaped_chunks)

